window.DECISIONMAKING_SETS = {"set1":[{"qn":1,"hi":{"prompt":["आप एक प्रशासनिक अधिकारी हैं। आपको कर्मचारियों की भर्ती में पक्षपात नज़र आता है। आपको क्या करना चाहिए?"],"options":["संघर्ष से बचने के लिए चुप रहें","साक्ष्य के साथ आपत्ति उठाएँ","चयनित उम्मीदवार को चुपचाप सूचित करें","शामिल होने की प्रक्रिया में देरी करें"],"solution":"Pakshapat (bias) dekh kar chup rehna galat hai; proper channel me saboot ke saath objection uthana hi सही, jimmedaar admin ka kaam."},"en":{"prompt":["You are an administrative officer. You notice bias in employee recruitment. What should you do?"],"options":["Stay silent to avoid conflict","Raise an objection with evidence","Quietly inform the selected candidate","Delay the joining process"],"solution":"Staying silent after noticing bias is wrong; raising an objection through the proper channel with evidence is the correct, responsible action for an administrator."},"answer":1},{"qn":2,"hi":{"prompt":["एक डॉक्टर गलती से मरीज़ का डेटा बता देता है। यह किस कानूनी सिद्धांत का उल्लंघन है?"],"options":["लापरवाही","गोपनीयता","मानहानि","गरिमा का अधिकार"],"solution":"Patient ka data leak karna Confidentiality (गोपनीयता) ka ulanghan hai — negligence/defamation nahi, seedha privacy principle."},"en":{"prompt":["A doctor accidentally discloses a patient's data. Which legal principle does this violate?"],"options":["Negligence","Confidentiality","Defamation","Right to dignity"],"solution":"Leaking a patient's data violates Confidentiality — not negligence or defamation, but directly the privacy principle."},"answer":1},{"qn":3,"hi":{"prompt":["एक न्यायाधीश के रूप में, आप देखते हैं कि एक वकील एक गवाह को प्रभावित कर रहा है। आपको क्या करना चाहिए?"],"options":["जब तक यह दोहराया न जाए, अनदेखा करें","वकील को अवमानना का दोषी ठहराएँ","मामले को स्थायी रूप से स्थगित करें","गवाह से चुप रहने का अनुरोध करें"],"solution":"Judge ko witness ko influence karne wale lawyer ko turant contempt of court ka dosi thehrana chahiye — nyay process ki suraksha priority hai."},"en":{"prompt":["As a judge, you notice a lawyer influencing a witness. What should you do?"],"options":["Ignore it unless it is repeated","Hold the lawyer in contempt of court","Adjourn the case permanently","Ask the witness to stay silent"],"solution":"A judge should immediately hold a lawyer who is influencing a witness in contempt of court — protecting the judicial process is the priority."},"answer":1},{"qn":4,"hi":{"prompt":["आप देखते हैं कि किसी का बटुआ सड़क पर गिर गया है। आपको क्या करना चाहिए?"],"options":["नज़रअंदाज़ करें","इसे रखें","इसे दान करें","वापस करें"],"solution":"Kisi ka gira wallet dekh kar sabse zimmedaar/ethical action hamesha 'wapas karna' hota hai, chahe le lena ya ignore karna aasan lage."},"en":{"prompt":["You see someone's wallet fall on the road. What should you do?"],"options":["Ignore it","Keep it","Donate it","Return it"],"solution":"On seeing a dropped wallet, the most responsible, ethical action is always to return it, even though keeping it or ignoring it may seem easier."},"answer":3},{"qn":5,"hi":{"prompt":["आप एक अस्पताल की रिसेप्शनिस्ट हैं। एक मरीज़ गंभीर हालत में आता है। आपको सबसे पहले क्या करना चाहिए?"],"options":["डॉक्टर को बुलाने से पहले कागजी कार्रवाई पूरी करें","डॉक्टर को बुलाएँ और फिर कागजी कार्रवाई शुरू करें","दस्तावेज़ प्राप्त करने के लिए मरीज़ को वापस भेजें","वरिष्ठ अनुमोदन की प्रतीक्षा करें"],"solution":"Emergency me pehle life-saving action (doctor bulana) phir paperwork — patient ki jaan documentation se upar hoti hai."},"en":{"prompt":["You are a hospital receptionist. A patient arrives in critical condition. What should you do first?"],"options":["Complete the paperwork before calling the doctor","Call the doctor and then start the paperwork","Send the patient back to get documents","Wait for senior approval"],"solution":"In an emergency, take the life-saving action first (call the doctor), then handle paperwork — the patient's life comes before documentation."},"answer":1},{"qn":6,"hi":{"prompt":["आप एक सरकारी इमारत में फ्रंट-डेस्क अधिकारी हैं और वहां आग का अलार्म बज रहा है। आप क्या करते हैं?"],"options":["सभी को बाहर निकालें और अधिकारियों को सतर्क करें","तब तक काम करते रहो जब तक कोई तुम्हें न कहे","लोगों पर चिल्लाना","अलार्म बंद करें"],"solution":"Fire alarm baje to sabse pehle evacuate + authorities alert — apna kaam continue karna ya alarm band karna dono galat."},"en":{"prompt":["You are a front-desk officer in a government building and the fire alarm goes off. What do you do?"],"options":["Evacuate everyone and alert the authorities","Keep working until someone tells you to stop","Shout at people","Turn off the alarm"],"solution":"When a fire alarm rings, evacuate and alert authorities first — continuing your work or turning off the alarm are both wrong."},"answer":0},{"qn":7,"hi":{"prompt":["आपकी टीम एक बड़ी समयसीमा से चूक जाती है। टीम लीडर के तौर पर आप क्या करते हैं?"],"options":["परियोजना छोड़ें","चुप रहें","कारणों का विश्लेषण करें और अगले कदमों के बारे में बताएं","किसी को दोष दें"],"solution":"Deadline miss hone par blame game ya chup rehna se kaam nahi chalta; cause analysis + next steps hi constructive leadership hai."},"en":{"prompt":["Your team misses a major deadline. As team leader, what do you do?"],"options":["Leave the project","Stay silent","Analyze the reasons and communicate next steps","Blame someone"],"solution":"Blaming or staying silent after missing a deadline doesn't help; analyzing the cause and communicating next steps is constructive leadership."},"answer":2},{"qn":8,"hi":{"prompt":["ऑफिस जाते समय आप एक सड़क दुर्घटना देखते हैं। आप क्या करेंगे?"],"options":["अनदेखा करें और आगे बढ़ें","आपातकालीन सेवाओं को कॉल करें और यातायात पुलिस को सूचित करें","किसी और की मदद तक प्रतीक्षा करें","इसे सोशल मीडिया पर पोस्ट करें"],"solution":"Accident dekh kar sabse zaroori step emergency services ko call karna hai — khud intervene karna risky, ignore karna irresponsible."},"en":{"prompt":["On your way to office, you witness a road accident. What will you do?"],"options":["Ignore it and move on","Call emergency services and inform traffic police","Wait for someone else to help","Post it on social media"],"solution":"On seeing an accident, the most essential step is calling emergency services — intervening yourself is risky, ignoring it is irresponsible."},"answer":1},{"qn":9,"hi":{"prompt":["आप एक आपातकालीन वार्ड में नर्स हैं। एक मरीज़ सीने में तेज़ दर्द के साथ आता है। आपको सबसे पहले क्या करना चाहिए?"],"options":["तुरंत डॉक्टर को बुलाएँ","मरीज़ का बीमा जाँचें","प्रवेश फ़ॉर्म भरें","परिवार से संपर्क करें"],"solution":"Chest pain = cardiac emergency ka sanket, ER nurse ka pehla kaam doctor ko turant bulana hai, formalities baad me."},"en":{"prompt":["You are a nurse in an emergency ward. A patient arrives with severe chest pain. What should you do first?"],"options":["Call the doctor immediately","Check the patient's insurance","Fill out the admission form","Contact the family"],"solution":"Chest pain signals a possible cardiac emergency; an ER nurse's first job is to call the doctor immediately — formalities come later."},"answer":0},{"qn":10,"hi":{"prompt":["आपको एक ऐसा काम सौंपा गया है जिसे आप नहीं जानते कि कैसे करना है। आपके लिए सबसे अच्छा उपाय क्या है?"],"options":["बहाने बनाएँ","गलत तरीके से करें","सहायता या मार्गदर्शन लें","इसमें देरी करें"],"solution":"Na aane wale kaam ko galat karne ya delay karne se better hai help/guidance lena — yehi professional maturity hai."},"en":{"prompt":["You are assigned a task you don't know how to do. What is the best course of action?"],"options":["Make excuses","Do it incorrectly","Seek help or guidance","Delay it"],"solution":"Rather than doing unfamiliar work incorrectly or delaying it, it's better to seek help or guidance — this is professional maturity."},"answer":2},{"qn":11,"hi":{"prompt":["पात्रता मानदंड: न्यूनतम 60% अंकों के साथ 12वीं पास होना चाहिए। 40 शब्द प्रति मिनट टाइपिंग स्पीड अनिवार्य है। टाइपिंग या डेटा एंट्री में सर्टिफिकेट कोर्स पूरा किया होना चाहिए। आयु केवल 18 से 28 वर्ष के बीच होनी चाहिए। मामला: राज ने 65% अंकों के साथ 12वीं पास की है, उसकी टाइपिंग स्पीड 38 शब्द प्रति मिनट है और वह एक प्रमाणित डेटा एंट्री पेशेवर है। उसकी आयु 24 वर्ष है।"],"options":["योग्य","आयु के कारण पात्र नहीं","टाइपिंग गति के कारण पात्र नहीं","प्रमाणन न होने के कारण पात्र नहीं"],"solution":"Eligibility check: 12th 65% (ok), age 24 (ok, 18-28), certificate hai (ok), lekin typing 38 WPM < 40 WPM mandatory — isi ek criterion fail hone se Raj typing speed ki wajah se ineligible hai."},"en":{"prompt":["Eligibility criteria: Must have passed 12th with a minimum of 60% marks. Typing speed of 40 words per minute is mandatory. Must have completed a certificate course in typing or data entry. Age must be strictly between 18 and 28 years. Case: Raj has passed 12th with 65% marks, his typing speed is 38 words per minute, and he is a certified data entry professional. His age is 24 years."],"options":["Eligible","Not eligible due to age","Not eligible due to typing speed","Not eligible due to lack of certification"],"solution":"Eligibility check: 12th 65% (ok), age 24 (ok, 18-28), certificate present (ok), but typing 38 WPM is below the mandatory 40 WPM — this single failed criterion makes Raj ineligible due to typing speed."},"answer":2},{"qn":12,"hi":{"prompt":["किसी संक्रामक रोग से पीड़ित मरीज़ को अस्पताल में भर्ती कराया जाता है। आपका पहला कदम क्या होगा?"],"options":["रोगी को अलग रखें और डॉक्टर को सूचित करें","उनसे प्रतीक्षा करने के लिए कहें","मीडिया को सूचित करें","उन्हें तुरंत छुट्टी दे दी जाए"],"solution":"Infectious disease patient ko pehle isolate karke doctor ko inform karna spread rokne ka standard protocol hai."},"en":{"prompt":["A patient suffering from an infectious disease is admitted to the hospital. What would be your first step?"],"options":["Isolate the patient and inform the doctor","Ask them to wait","Inform the media","Discharge them immediately"],"solution":"Isolating an infectious disease patient first and informing the doctor is the standard protocol to prevent spread."},"answer":0},{"qn":13,"hi":{"prompt":["आप एक सरकारी क्लर्क हैं और आपको एक गरीब ग्रामीण से अधूरा आवेदन मिलता है, जो प्रक्रिया को नहीं समझता। आपको क्या करना चाहिए?"],"options":["आवेदन को तुरंत अस्वीकार करें","बिना स्पष्टीकरण के इसे वापस कर दें","उसे उचित मार्गदर्शन दें और फॉर्म भरने में उसकी मदद करें","इसे अपनी जिम्मेदारी न मानकर नज़रअंदाज़ करें"],"solution":"Ek gareeb villager jo process nahi samajhta usse guidance dena aur form bharne me madad karna hi ek responsible clerk ka kaam hai, reject/ignore karna nahi."},"en":{"prompt":["You are a government clerk and receive an incomplete application from a poor villager who doesn't understand the process. What should you do?"],"options":["Reject the application immediately","Return it without explanation","Give him proper guidance and help him fill out the form","Ignore it, considering it not your responsibility"],"solution":"Giving guidance and helping a poor villager who doesn't understand the process fill out the form is a responsible clerk's job, not rejecting or ignoring it."},"answer":2},{"qn":14,"hi":{"prompt":["आप एक कानूनी सहायता क्लिनिक में काम करते हैं और कोई व्यक्ति घरेलू हिंसा की रिपोर्ट करता है। आपको क्या करना चाहिए?"],"options":["उन्हें रिपोर्ट दर्ज करने और सहायता प्रदान करने में सहायता करें","इसे व्यक्तिगत समझकर अनदेखा करें","उन्हें प्रतीक्षा करने के लिए कहें","उन्हें अदालत भेजो"],"solution":"Legal aid clinic me domestic violence report par turant help + report filing me support dena hi sahi responsibility hai, ignore ya delay nahi."},"en":{"prompt":["You work at a legal aid clinic and someone reports domestic violence. What should you do?"],"options":["Help them file a report and provide support","Ignore it as a personal matter","Ask them to wait","Send them to court"],"solution":"At a legal aid clinic, immediately helping with support and filing a report on a domestic violence complaint is the right response — not ignoring or delaying it."},"answer":0},{"qn":15,"hi":{"prompt":["आप एक न्यायाधीश हैं और आपकी अदालत में एक जाने-माने व्यक्ति का मुकदमा चल रहा है। मीडिया का दबाव बहुत ज़्यादा है। आपको किस आधार पर फैसला लेना चाहिए?"],"options":["मीडिया की धारणा और जनता की राय","कानूनी मिसालें और व्यक्तिगत पूर्वाग्रह","साक्ष्य और कानून के आधार पर न्याय सुनिश्चित करें","निर्णय लेने से पहले मित्रों से परामर्श करें"],"solution":"Judge ko media pressure ya bias nahi, sirf evidence aur law ke aadhar par nyay dena chahiye — judicial independence ka core principle."},"en":{"prompt":["You are a judge and a well-known person's case is being heard in your court. There is heavy media pressure. On what basis should you decide?"],"options":["Media perception and public opinion","Legal precedents and personal bias","Ensure justice based on evidence and law","Consult friends before deciding"],"solution":"A judge should deliver justice based only on evidence and law, not media pressure or bias — the core principle of judicial independence."},"answer":2}],"set2":[{"qn":16,"hi":{"prompt":["एक डॉक्टर एक ऐसे मरीज़ का इलाज कर रहा है जो अपनी निजी मान्यताओं के कारण जीवन रक्षक दवा लेने से इनकार कर रहा है। डॉक्टर को क्या करना चाहिए?"],"options":["बिना किसी हस्तक्षेप के रोगी की पसंद का सम्मान करें","रोगी को परामर्श देने और इनकार को दस्तावेज में दर्ज करने का प्रयास करें","रोगी की सुरक्षा के लिए दवा देना अनिवार्य करें","मरीज़ की उपेक्षा करें और किसी अन्य मामले पर आगे बढ़ें"],"solution":"Patient ka autonomy respect karte hue counsel karna aur refusal document karna sahi balance hai — na to force karna, na ignore karna."},"en":{"prompt":["A doctor is treating a patient who refuses life-saving medication due to personal beliefs. What should the doctor do?"],"options":["Respect the patient's choice without any intervention","Try to counsel the patient and document the refusal","Make administering the medication mandatory for the patient's safety","Neglect the patient and move to another case"],"solution":"Respecting patient autonomy while counseling them and documenting the refusal is the right balance — neither forcing nor ignoring."},"answer":1},{"qn":17,"hi":{"prompt":["आप एक नगरपालिका अधिकारी हैं और एक फैक्ट्री रात में नदी में कचरा डालती है। आपको किस काम को प्राथमिकता देनी चाहिए?"],"options":["उच्च अधिकारियों द्वारा कार्रवाई किये जाने की प्रतीक्षा करें","एक महीने के बाद फैक्ट्री पर जुर्माना लगाओ","गुप्त रूप से इस कृत्य को रिकॉर्ड करें और इसे लीक करें","कानूनी कार्रवाई करें और पर्यावरण विभाग को सूचित करें"],"solution":"Illegal river pollution dekh kar municipal officer ko legal action + environment dept ko turant inform karna chahiye, delay ya secret recording nahi."},"en":{"prompt":["You are a municipal officer and a factory dumps waste into the river at night. What action should you prioritize?"],"options":["Wait for higher authorities to act","Fine the factory after a month","Secretly record the act and leak it","Take legal action and inform the environment department"],"solution":"On seeing illegal river pollution, a municipal officer should immediately take legal action and inform the environment department, not delay or secretly record it."},"answer":3},{"qn":18,"hi":{"prompt":["श्रुति एक सफल ऑनलाइन व्यवसाय चलाती है। उसे एक बड़ी कंपनी द्वारा साझेदारी की पेशकश की गई है जो उसके ब्रांड का 60% अधिग्रहण करना चाहती है। जबकि आर्थिक लाभ अधिक हैं, वह निर्णय लेने में प्रमुख नियंत्रण खो देगी। उसका ब्रांड व्यक्तिगत जुड़ाव और ग्राहक विश्वास पर आधारित है। सर्वोत्तम कार्यवाही क्या है?"],"options":["वित्तीय लाभ के लिए तुरंत स्वीकार करना","छोटे हिस्से और आंशिक नियंत्रण के लिए बातचीत करना","अपना व्यवसाय बंद करना और नया अवसर तलाशना","स्वतंत्रता बनाए रखने के लिए स्पष्ट रूप से अस्वीकार करना"],"solution":"Business partial control lose kiye bina bhi fund/growth chahiye to bada stake dene ke bajaye smaller share aur partial control ke liye negotiate karna balanced strategic move hai."},"en":{"prompt":["Shruti runs a successful online business. She has been offered a partnership by a large company that wants to acquire 60% of her brand. While the financial benefits are high, she would lose major control over decision-making. Her brand is built on personal connection and customer trust. What is the best course of action?"],"options":["Accept immediately for financial gain","Negotiate for a smaller stake and partial control","Shut down her business and look for a new opportunity","Clearly refuse in order to maintain independence"],"solution":"If funding or growth is needed without losing full control, negotiating for a smaller stake and partial control instead of giving up a large stake is the balanced strategic move."},"answer":1},{"qn":19,"hi":{"prompt":["आपके स्वयंसेवी समूह में साथी आखिरी समय में हुए बदलावों को व्यक्तिगत तौर पर लेकर पीछे हट जाते हैं। उन्हें वापस कैसे लाएँ?"],"options":["उन पर ज़्यादा प्रतिक्रिया करने का आरोप लगाएं","उनकी भावनाओं को स्वीकार करें, कारण बताएं और भविष्य के निर्णयों में उनकी राय लें","उन्हें नजरअंदाज करें और उनके बिना जारी रखें","चुपचाप उन्हें बदल दें"],"solution":"Volunteers agar last-minute changes se hurt feel karein to unki feelings acknowledge karo, reason batao, aur future decisions me unhe involve karo — yehi team ko wapas engage karta hai."},"en":{"prompt":["Peers in your volunteer group withdraw personally after last-minute changes. How do you bring them back?"],"options":["Accuse them of overreacting","Acknowledge their feelings, explain the reasons, and involve them in future decisions","Ignore them and continue without them","Quietly replace them"],"solution":"If volunteers feel hurt by last-minute changes, acknowledging their feelings, explaining the reason, and involving them in future decisions is what re-engages the team."},"answer":1},{"qn":20,"hi":{"prompt":["एक भर्ती प्रबंधक को एक तकनीकी भूमिका भरनी है। सभी आवेदक तकनीकी मानदंडों को पूरा करते हैं, लेकिन एक आवेदक टीमवर्क और नेतृत्व में भी मजबूत दिखता है। किसे चुना जाना चाहिए?"],"options":["मजबूत टीमवर्क और नेतृत्व वाला आवेदक","सबसे अधिक डिग्रियों वाला आवेदक","सर्वोच्च टेस्ट स्कोर वाला आवेदक","सबसे लंबा रिज्यूमे वाला आवेदक"],"solution":"Sab technical criteria pura karte hain, isliye tie-breaker teamwork+leadership hai — jo candidate in soft skills me bhi strong ho wahi best overall fit."},"en":{"prompt":["A hiring manager needs to fill a technical role. All applicants meet the technical criteria, but one applicant also shows strong teamwork and leadership. Who should be selected?"],"options":["The applicant with strong teamwork and leadership","The applicant with the most degrees","The applicant with the highest test score","The applicant with the longest resume"],"solution":"Since everyone meets the technical criteria, the tie-breaker is teamwork and leadership — the candidate strong in these soft skills is the best overall fit."},"answer":0},{"qn":21,"hi":{"prompt":["एक सांस्कृतिक उत्सव के दौरान, दो समुदाय समूह अपने प्रदर्शनों के लिए एक ही स्थान का दावा करते हैं। आयोजक को कैसे निर्णय लेना चाहिए?"],"options":["इसे बड़े समूह को दें","एक समूह से रद्द करने के लिए कहें","वेन्यू का समय विभाजित करें और शेड्यूल को समन्वित करें","सिक्का उछालें"],"solution":"Venue conflict me sabse fair solution time-split karke schedule coordinate karna hai, na ki ek group ko poora de dena ya coin toss jaisa random tarika."},"en":{"prompt":["During a cultural festival, two community groups claim the same venue for their performances. How should the organizer decide?"],"options":["Give it to the larger group","Ask one group to cancel","Split the venue time and coordinate the schedule","Flip a coin"],"solution":"The fairest solution to a venue conflict is splitting the time and coordinating the schedule, not giving it entirely to one group or leaving it to chance like a coin toss."},"answer":2},{"qn":22,"hi":{"prompt":["स्कूल बस का मार्ग अव्यवस्थित है जिससे देरी होती है। तर्कसंगत सुधार क्या होगा?"],"options":["लागत की परवाह किए बिना अधिक बसें जोड़ें","छात्रों से अतिरिक्त शुल्क लें","छात्रों के स्थानों का उपयोग कर मार्ग को पुनः डिजाइन करें और इष्टतम पथ चुनें","परिवर्तन से बचने के लिए समान मार्ग रखें"],"solution":"Bus route disorganized hai to logical fix hai student locations use karke route redesign karna aur optimal path choose karna — sirf buses add karna cost-inefficient hai."},"en":{"prompt":["A school bus route is disorganized, causing delays. What would be the logical fix?"],"options":["Add more buses regardless of cost","Charge students an extra fee","Redesign the route using student locations and choose the optimal path","Keep the same route to avoid change"],"solution":"Since the route is disorganized, the logical fix is redesigning it using student locations and choosing the optimal path — simply adding buses is cost-inefficient."},"answer":2},{"qn":23,"hi":{"prompt":["कविता अपने भाई-बहन की पढाई में मदद करने या अपनी परीक्षा की तैयारी करने में समय लगा सकती है। उसका भाई-बहन संघर्ष कर रहा है और उसकी कल परीक्षा है। संतुलित निर्णय क्या होगा?"],"options":["दोनों के लिए सीमित समय निर्धारित करना","किसी और से भाई-बहन की मदद करने को कहना","भाई-बहन को अनदेखा कर पढ़ाई करना","पूरे दिन भाई-बहन की मदद करना"],"solution":"Sibling ki exam kal hai aur khud ki bhi taiyari zaroori — dono ke liye time divide karna balanced decision hai, na poora din ek ko dena na dusre ko ignore karna."},"en":{"prompt":["Kavita can spend her time helping her sibling study or preparing for her own exam. Her sibling is struggling and has an exam tomorrow. What is the balanced decision?"],"options":["Set limited time for both","Ask someone else to help the sibling","Ignore the sibling and study","Help the sibling the whole day"],"solution":"The sibling's exam is tomorrow and her own preparation matters too — dividing time between both is the balanced decision, not devoting the whole day to one or ignoring the other."},"answer":0},{"qn":24,"hi":{"prompt":["एक समूह असाइनमेंट के दौरान, एक सदस्य कम योगदान देता है लेकिन व्यस्त होने का दावा करता है। आप स्थिति को सामाजिक रूप से बुद्धिमानी से कैसे संभालेंगे?"],"options":["सारा काम खुद करें","कार्यों को स्पष्ट रूप से विभाजित करें और निजी तौर पर उनकी सीमाएँ समझने के लिए चेक-इन करें और मदद की पेशकश करें","समूह के सामने कड़ी फटकार लगाएं","बिना चर्चा के उन्हें बाहर कर दें"],"solution":"Kam contribute karne wale member ko sidha bahar nikalne ya khud sab kaam karne ke bajaye tasks clearly divide karo aur privately unki situation samajh kar help offer karo."},"en":{"prompt":["During a group assignment, one member contributes little but claims to be busy. How would you handle the situation with social wisdom?"],"options":["Do all the work yourself","Clearly divide tasks, check in privately to understand their limits, and offer help","Scold them harshly in front of the group","Exclude them without discussion"],"solution":"Instead of doing all the work yourself or removing the low-contributing member outright, clearly divide tasks and check in privately to understand their situation and offer help."},"answer":1},{"qn":25,"hi":{"prompt":["एक स्कूल के प्रिंसिपल को अभिभावकों की ओर से एक शिक्षक की सख्त अनुशासनात्मक विधियों के बारे में कई शिकायतें मिलती हैं, हालाँकि उस शिक्षक के अंतर्गत छात्रों के ग्रेड स्कूल में सर्वोत्तम हैं। सही विकल्प चुनें।"],"options":["चूंकि छात्र अच्छा कर रहे हैं, शिकायतों को अनदेखा करें","वैकल्पिक अनुशासन रणनीतियों पर चर्चा करने और कक्षा की गतिशीलता की निगरानी के लिए शिक्षक से मिलें","छात्रों से अनुरोध करें कि वे तरीकों को सहन करें क्योंकि इससे ग्रेड सुधरते हैं","माता-पिता को खुश करने के लिए शिक्षक को तुरंत निलंबित करें"],"solution":"Strict discipline ki complaints aane par teacher se milkar alternative strategies discuss karna aur classroom dynamics monitor karna balanced approach hai, na ignore karna na turant suspend karna."},"en":{"prompt":["A school principal receives several complaints from parents about a teacher's strict disciplinary methods, though that teacher's students have the best grades in the school. Choose the correct option."],"options":["Since students are doing well, ignore the complaints","Meet the teacher to discuss alternative discipline strategies and monitor classroom dynamics","Ask students to tolerate the methods since grades improve","Suspend the teacher immediately to appease the parents"],"solution":"Meeting the teacher to discuss alternative strategies and monitoring classroom dynamics is the balanced approach when strict-discipline complaints arise, rather than ignoring them or suspending immediately."},"answer":1},{"qn":26,"hi":{"prompt":["एक स्कूल में केवल एक कंप्यूटर लैब है और दो कक्षाओं को एक ही समय में महत्वपूर्ण प्रोजेक्ट्स के लिए इसकी आवश्यकता है। प्रधानाचार्य को इस संघर्ष को सबसे निष्पक्ष तरीके से हल करने के लिए क्या करना चाहिए?"],"options":["अधिक अनुभवी शिक्षक को निर्णय लेने दें","प्रत्येक कक्षा को आधा समय आवंटित करें और दोनों की निगरानी के लिए शिक्षक प्रदान करें","यह उच्च औसत अंक वाली कक्षा को दें","एक कक्षा की परियोजना की समय सीमा आगे बढ़ाएं"],"solution":"Ek hi lab, do classes — fairest solution time split karna aur dono ki supervision ensure karna hai."},"en":{"prompt":["A school has only one computer lab, and two classes need it at the same time for important projects. What should the principal do to resolve this most fairly?"],"options":["Let the more experienced teacher decide","Allocate half the time to each class and provide supervision for both","Give it to the class with the higher average marks","Extend one class's project deadline"],"solution":"With one lab and two classes needing it, the fairest solution is splitting the time and ensuring supervision for both."},"answer":1},{"qn":27,"hi":{"prompt":["एक छात्रा की परीक्षा में केवल 3 दिन शेष हैं। उसने आधा पाठ्यक्रम भी पूरा नहीं किया है। सबसे अच्छी रणनीति क्या होनी चाहिए?"],"options":["हार मानकर परीक्षा छोड़ देना","अधिक अंकभार वाले और परिचित विषयों पर ध्यान केंद्रित करना","घबराहट शांत करने के लिए प्रेरणादायक वीडियो देखना","कम सोकर सभी विषयों को कवर करना"],"solution":"3 din bache hain, aadha syllabus baki — high-weightage aur familiar topics par focus karna smartest exam strategy hai, sab kuch cover karne ki koshish counterproductive hai."},"en":{"prompt":["A student has only 3 days left for her exam and hasn't even finished half the syllabus. What should be the best strategy?"],"options":["Give up and skip the exam","Focus on high-weightage and familiar topics","Watch motivational videos to calm nerves","Sleep less to cover all subjects"],"solution":"With 3 days left and half the syllabus remaining, focusing on high-weightage and familiar topics is the smartest exam strategy — trying to cover everything is counterproductive."},"answer":1},{"qn":28,"hi":{"prompt":["आपका सहकर्मी व्यक्तिगत समस्याएँ साझा करता है जो उनके काम को प्रभावित कर रही हैं। आप उनके प्रबंधक नहीं हैं। सबसे अच्छी सामाजिक बुद्धिमत्ता वाली प्रतिक्रिया क्या है?"],"options":["उन्हें कार्यों को प्राथमिकता देने में मदद करें और एचआर या सुपरवाइज़र से बात करने का सुझाव दें","उनके मुद्दों को कार्यालय गपशप के रूप में फैलाएं ताकि सहानुभूति मिले","चूंकि यह आपकी चिंता नहीं है, नजरअंदाज करें","उन्हें काम को घर पर छोड़ने के लिए कहें"],"solution":"Aap manager nahi ho to sahi EQ response hai colleague ki task prioritization me help karna aur HR/supervisor se baat karne ka suggest dena — gossip ya ignore dono galat."},"en":{"prompt":["Your colleague shares personal problems that are affecting their work. You are not their manager. What is the best socially intelligent response?"],"options":["Help them prioritize tasks and suggest talking to HR or a supervisor","Spread their issues as office gossip to gain sympathy","Ignore it since it's not your concern","Ask them to leave their work at home"],"solution":"Since you aren't their manager, the right emotionally-intelligent response is to help them prioritize tasks and suggest talking to HR or a supervisor — gossiping or ignoring are both wrong."},"answer":0},{"qn":29,"hi":{"prompt":["एक नगर परिषद को बुनियादी ढांचे के लिए सीमित बजट आवंटित करना होता है। परिषद के पास एक पुराने पुल की मरम्मत, एक नया पार्क बनाने, जल आपूर्ति में सुधार, या स्थानीय परिवहन को बेहतर बनाने का विकल्प है। यदि शहर को हाल ही में पानी की कमी का सामना करना पड़ा है, तो सबसे उचित कदम क्या होगा?"],"options":["एक नया पार्क बनाएं","जल आपूर्ति में सुधार करें","पुराने पुल की मरम्मत करें","स्थानीय परिवहन को बेहतर बनाएँ"],"solution":"City me recent water shortage hua hai isliye given options me sabse relevant/urgent priority water supply improve karna hai — context-specific decision."},"en":{"prompt":["A city council has to allocate a limited budget for infrastructure. The council can choose to repair an old bridge, build a new park, improve the water supply, or improve local transport. If the city recently faced a water shortage, what would be the most appropriate step?"],"options":["Build a new park","Improve the water supply","Repair the old bridge","Improve local transport"],"solution":"Since the city recently faced a water shortage, the most relevant and urgent priority among the given options is improving the water supply — a context-specific decision."},"answer":1},{"qn":30,"hi":{"prompt":["एक कर्मचारी का दावा है कि एक सहकर्मी ने उसके विचार का श्रेय ले लिया। एचआर को हल करना होगा। सबसे अच्छा कदम क्या है?"],"options":["सहकर्मी को तुरंत बर्खास्त करें","दोनों पक्षों से सबूत एकत्र करके जांच करें","टकराव से बचने के लिए नजरअंदाज करें","दावेदार को खुश करने के लिए पदोन्नति दें"],"solution":"Credit-stealing complaint par HR ka sahi kaam dono paksho se evidence collect karke investigate karna hai — turant fire karna ya ignore karna bias dikhata hai."},"en":{"prompt":["An employee claims a colleague took credit for their idea. HR must resolve this. What is the best step?"],"options":["Immediately fire the colleague","Investigate by collecting evidence from both sides","Ignore it to avoid confrontation","Promote the complainant to appease them"],"solution":"On a credit-stealing complaint, HR's correct action is to investigate by collecting evidence from both sides — firing immediately or ignoring both show bias."},"answer":1}],"set3":[{"qn":31,"hi":{"prompt":["अमन का स्टार्टअप वित्तीय संकट का सामना कर रहा है। एक निवेशक फंड देने को तैयार है लेकिन इसके बदले अमन को बहुमत स्वामित्व छोड़ना होगा। अमन भावनात्मक रूप से स्टार्टअप से जुड़ा है। सबसे रणनीतिक निर्णय क्या होगा?"],"options":["कंपनी को बचाने के लिए प्रस्ताव स्वीकार करना","नौकरी की तलाश में इस्तीफा देना","कुछ रणनीतिक नियंत्रण बनाए रखने के लिए बातचीत करना","प्रस्ताव को अस्वीकार करना और दिवालियापन का जोखिम उठाना"],"solution":"Startup bachana hai lekin emotional attachment bhi hai to full control chodne ya offer thukrane ke bajaye kuch strategic control retain karte hue negotiate karna best middle path hai."},"en":{"prompt":["Aman's startup is facing a financial crisis. An investor is willing to provide funds but in return Aman must give up majority ownership. Aman is emotionally attached to the startup. What would be the most strategic decision?"],"options":["Accept the offer to save the company","Resign and look for a job","Negotiate to retain some strategic control","Reject the offer and risk bankruptcy"],"solution":"Since the startup needs saving but there's also emotional attachment, negotiating to retain some strategic control instead of giving up full control or rejecting the offer entirely is the best middle path."},"answer":2},{"qn":32,"hi":{"prompt":["एक मित्र बार-बार पैसे उधार लेता है और चुकौती में देरी करता है, जिससे आप असहज महसूस करते हैं। क्या उचित है?"],"options":["टकराव से बचने के लिए और उधार दें","उनसे बात करना बंद कर दें","भविष्य के उधार के लिए स्पष्ट शर्तें निर्धारित करें और मौजूदा ऋण की वापसी विनम्रता से मांगें","सार्वजनिक रूप से उन्हें शर्मिंदा करें"],"solution":"Baar baar udhaar leke der se lautane wale dost ke saath clear terms set karna aur existing debt politely maangna healthy boundary-setting hai."},"en":{"prompt":["A friend repeatedly borrows money and delays repayment, making you uncomfortable. What is appropriate?"],"options":["Lend more to avoid confrontation","Stop talking to them","Set clear terms for future loans and politely ask for repayment of the existing debt","Publicly embarrass them"],"solution":"Setting clear terms with a friend who repeatedly borrows and delays repayment, and politely asking for the existing debt back, is healthy boundary-setting."},"answer":2},{"qn":33,"hi":{"prompt":["एक शहर के प्रदूषण स्तर में वृद्धि हो रही है। इसे संबोधित करने के लिए, मेयर को जनहित में शीघ्र निर्णय लेना होगा। सबसे उचित पहला कदम क्या है?"],"options":["इमारतों को पेंट करें","अधिक बाज़ार खोलें","एक मैराथन आयोजित करें","सख्त उत्सर्जन नियम लागू करें"],"solution":"Rising pollution ek urgent public issue hai — mayor ka pehla practical kadam strict emission regulations enforce karna hai, cosmetic steps nahi."},"en":{"prompt":["A city's pollution levels are rising. To address this, the mayor must make a quick decision in public interest. What is the most appropriate first step?"],"options":["Paint the buildings","Open more markets","Organize a marathon","Enforce strict emission regulations"],"solution":"Rising pollution is an urgent public issue — the mayor's first practical step should be enforcing strict emission regulations, not cosmetic measures."},"answer":3},{"qn":34,"hi":{"prompt":["एक राजनेता सीमित विकास बजट आवंटित करना चाहता है। नागरिक सभी क्षेत्रों की मांग करते हैं। तार्किक पहला कदम क्या है?"],"options":["ज़रूरत की परवाह किए बिना समान रूप से बांटें","निर्णय को अनिश्चित काल के लिए स्थगित करें","सब कुछ अपने ही निर्वाचन क्षेत्र को दे दें","एक आवश्यकता मूल्यांकन करें और प्रभाव के आधार पर प्राथमिकता तय करें"],"solution":"Limited budget, sab area demand kar rahe — logical first step needs assessment karke impact ke hisaab se priority tay karna hai."},"en":{"prompt":["A politician wants to allocate a limited development budget. Citizens demand attention for all areas. What is the logical first step?"],"options":["Distribute equally regardless of need","Postpone the decision indefinitely","Give everything to their own constituency","Conduct a needs assessment and prioritize based on impact"],"solution":"With a limited budget and demands from every area, the logical first step is conducting a needs assessment and prioritizing based on impact."},"answer":3},{"qn":35,"hi":{"prompt":["एक सरकारी हेल्पलाइन को कई डुप्लीकेट सवाल आ रहे हैं। सबसे कारगर समाधान?"],"options":["हेल्पलाइन बंद करें","FAQ और स्वचालित प्रतिक्रिया प्रणाली शुरू करें","डुप्लिकेट्स को नज़रअंदाज़ करें","कॉल करने वालों को दंडित करें"],"solution":"Baar baar duplicate queries aane par FAQ + automated response system sabse efficient scalable solution hai."},"en":{"prompt":["A government helpline is receiving many duplicate queries. What is the most effective solution?"],"options":["Shut down the helpline","Start an FAQ and automated response system","Ignore the duplicates","Penalize the callers"],"solution":"When duplicate queries keep coming in, an FAQ plus automated response system is the most efficient, scalable solution."},"answer":1},{"qn":36,"hi":{"prompt":["एक खिलाड़ी चोट से उबर रहा है। डॉक्टर का कहना है कि वह हल्की ट्रेनिंग फिर से शुरू कर सकता है, लेकिन वह जल्दी से पूर्ण रूप में लौटना चाहता है। सुरक्षित विकल्प क्या होगा?"],"options":["फिर भी कड़ी मेहनत से प्रशिक्षण लेना","धीमी रिकवरी योजना का पालन करना","खेल को पूरी तरह छोड़ देना","दर्दनाशक लेना और प्रयास करते रहना"],"solution":"Injury recovery me doctor ne slow return bola hai, jaldi full form me aane ki koshish risk badhati hai — safe option slow recovery plan follow karna hai."},"en":{"prompt":["An athlete is recovering from an injury. The doctor says he can resume light training, but he wants to quickly return to full form. What would be the safe option?"],"options":["Train hard anyway","Follow a slow recovery plan","Quit the sport entirely","Take painkillers and keep pushing"],"solution":"The doctor has advised a slow return during injury recovery; trying to return to full form quickly increases risk — the safe option is following a slow recovery plan."},"answer":1},{"qn":37,"hi":{"prompt":["आपके कार्यालय में जूनियर अच्छे विचार होने के बावजूद बोलने से डरता है। आप उन्हें कैसे प्रोत्साहित कर सकते हैं?"],"options":["अनदेखा करें और उन्हें चुप रहने दें","निजी तौर पर उनकी अंतर्दृष्टि की प्रशंसा करें और सहयोग की पेशकश करते हुए उन्हें साझा करने के लिए आमंत्रित करें","बिना पूर्वसूचना के मीटिंग में उन्हें जोर से बोलने के लिए कहें","आत्मविश्वास बढ़ाने के लिए उनके विचारों का श्रेय लें"],"solution":"Junior hesitant hai bolne me to private praise + collaborative invitation dena unhe confidence deta hai, credit lena ya ignore karna demotivating hoga."},"en":{"prompt":["A junior in your office is afraid to speak up despite having good ideas. How can you encourage them?"],"options":["Ignore it and let them stay quiet","Privately praise their insight and invite them to share while offering collaboration","Ask them to speak up loudly in a meeting without warning","Take credit for their ideas to boost their confidence"],"solution":"If a junior is hesitant to speak up, private praise plus a collaborative invitation gives them confidence — taking credit or ignoring them would be demotivating."},"answer":1},{"qn":38,"hi":{"prompt":["एक टेक स्टार्टअप एक शक्तिशाली AI विकसित करता है जो मानव आवाज़ों की नकल कर सकता है। यह क्रांतिकारी है लेकिन धोखाधड़ी के लिए दुरुपयोग का जोखिम भी है। सबसे जिम्मेदार निर्णय क्या होगा?"],"options":["इसे सबसे ऊँची बोली लगाने वाले को बेच दें","AI को कंपनी का गुप्त रखें","AI को बिना प्रतिबंधों के लॉन्च करें","सख्त नैतिक दिशानिर्देशों और पहचान उपकरणों के साथ AI जारी करें"],"solution":"Powerful voice-cloning AI misuse-prone hai — sabse responsible move strict ethical guidelines + detection tools ke saath release karna hai, na ki secret rakhna ya bina restriction launch karna."},"en":{"prompt":["A tech startup develops a powerful AI that can mimic human voices. It is revolutionary but also carries a risk of misuse for fraud. What would be the most responsible decision?"],"options":["Sell it to the highest bidder","Keep the AI a company secret","Launch the AI without restrictions","Release the AI with strict ethical guidelines and detection tools"],"solution":"A powerful voice-cloning AI is prone to misuse — the most responsible move is releasing it with strict ethical guidelines and detection tools, not keeping it secret or launching without restrictions."},"answer":3},{"qn":39,"hi":{"prompt":["एक शहर में पानी की आपूर्ति कम है। अधिकारियों को राशनिंग और अल्पकालिक टैंकर वितरण में निवेश के बीच निर्णय लेना है। तात्कालिक दृष्टिकोण क्या है?"],"options":["स्थायी रूप से राशनिंग शुरू करें","मुख्य पाइपलाइन को ठीक करते समय अस्थायी रूप से टैंकर तैनात करें","पानी के लिए अधिक शुल्क लें","अनदेखा करें और उम्मीद करें कि बारिश आएगी"],"solution":"Water shortage me turant/short-term fix (tanker deployment) karte hue main pipeline repair karna immediate practical approach hai, permanent rationing ek radical step hai."},"en":{"prompt":["A city has a low water supply. Authorities must decide between rationing and investing in short-term tanker distribution. What is the immediate approach?"],"options":["Start permanent rationing","Temporarily deploy tankers while fixing the main pipeline","Charge more for water","Ignore it and hope it rains"],"solution":"During a water shortage, deploying tankers as an immediate short-term fix while repairing the main pipeline is the practical approach — permanent rationing is a more radical step."},"answer":1},{"qn":40,"hi":{"prompt":["एक आदमी को पार्क में एक खोया हुआ बटुआ मिलता है। उसमें नकद और एक पहचान पत्र है। सबसे नैतिक कार्य क्या होगा?"],"options":["पैसे लेना और वॉलेट छोड़ देना","अनदेखा करना और आगे बढ़ जाना","इसे अपने पास रखें, ताकि बाद में कोई इसका दावा न कर सके","ID का उपयोग करके मालिक से संपर्क करना या अधिकारियों को रिपोर्ट करना"],"solution":"Lost wallet with ID milne par ID se owner contact karna ya authorities ko report karna sabse ethical action hai."},"en":{"prompt":["A man finds a lost wallet in a park. It has cash and an ID card. What would be the most ethical action?"],"options":["Take the money and leave the wallet","Ignore it and move on","Keep it so no one can claim it later","Use the ID to contact the owner or report it to authorities"],"solution":"On finding a lost wallet with an ID, using the ID to contact the owner or reporting it to authorities is the most ethical action."},"answer":3},{"qn":41,"hi":{"prompt":["एक सहपाठी को एक अफवाह के कारण समूह अध्ययन से बाहर रखा जा रहा है। सामाजिक रूप से जिम्मेदार कार्रवाई क्या है?"],"options":["प्रतिकूल अफवाह फैलाएं","स्थिति को पूरी तरह नजरअंदाज करें","क्लासमेट से प्राइवेटली बात करें और अफवाह फैलाने से हतोत्साहित करते हुए उन्हें शामिल करें","फिट होने के लिए उन्हें बाहर करने में शामिल हो जाएँ"],"solution":"Rumour ki wajah se kisi ko exclude kiya ja raha ho to classmate se privately baat karo aur unhe include karo, rumour ko discourage karte hue — sabse socially responsible step."},"en":{"prompt":["A classmate is being excluded from group study because of a rumor. What is the socially responsible action?"],"options":["Spread the harmful rumor further","Ignore the situation entirely","Talk to the classmates privately, discourage the rumor, and include them","Join in excluding them to fit in"],"solution":"When someone is excluded because of a rumor, privately talking to classmates, including the person, and discouraging the rumor is the most socially responsible step."},"answer":2},{"qn":42,"hi":{"prompt":["एक स्थानीय सरकार एक घनी आबादी वाले शहरी क्षेत्र में एक सार्वजनिक पार्क विकसित करने की योजना बना रही है। प्रस्तावित भूमि वर्तमान में सड़क विक्रेताओं और फेरीवालों द्वारा अपनी आजीविका के लिए उपयोग की जाती है।"],"options":["विक्रेताओं को तुरंत हटाकर निर्माण शुरू करें","विक्रेताओं को वैकल्पिक स्थान पर स्थानांतरित करें और पार्क विकास के साथ आगे बढ़ें","पार्क को विक्रेताओं से अलग करने के लिए क्षेत्र के चारों ओर एक दीवार बनाएँ","पार्क प्रोजेक्ट को पूरी तरह रद्द करें"],"solution":"Vendors ki livelihood affect ho rahi hai to unhe alternate location par relocate karke park development continue karna balanced solution hai, seedha hataana ya project cancel karna extreme steps hain."},"en":{"prompt":["A local government is planning to develop a public park in a densely populated urban area. The proposed land is currently used by street vendors and hawkers for their livelihood."],"options":["Remove the vendors immediately and start construction","Relocate the vendors to an alternative location and proceed with the park development","Build a wall around the area to separate the park from the vendors","Cancel the park project entirely"],"solution":"Since the vendors' livelihood is affected, relocating them to an alternative location while continuing park development is the balanced solution — outright removal or cancelling the project are extreme steps."},"answer":1},{"qn":43,"hi":{"prompt":["एक NGO के स्वयंसेवकों की भूमिकाएं ओवरलैप हो रही हैं, जिससे भ्रम पैदा हो रहा है। सबसे अच्छा समाधान क्या है?"],"options":["स्वयंसेवकों को लगातार बदलते रहें","कुछ न करें और अक्षमता स्वीकार करें","स्वयंसेवकों को आपस में निर्णय लेने दें","एक सरल मैट्रिक्स के साथ स्पष्ट जिम्मेदारियाँ निर्धारित करें"],"solution":"Roles overlap se confusion ho rahi hai to simple responsibility matrix banakar clear roles define karna structural fix hai."},"en":{"prompt":["An NGO's volunteers have overlapping roles, causing confusion. What is the best solution?"],"options":["Keep constantly changing volunteers","Do nothing and accept the inefficiency","Let the volunteers decide amongst themselves","Define clear responsibilities with a simple matrix"],"solution":"Since overlapping roles are causing confusion, creating a simple responsibility matrix with clearly defined roles is the structural fix."},"answer":3},{"qn":44,"hi":{"prompt":["विद्या के पास इंटर्नशिप के दो विकल्प हैं: एक किसी बड़ी बहुराष्ट्रीय कंपनी में जहाँ डेटा एंट्री का काम होता है, और दूसरा किसी स्टार्टअप में जहाँ वह कोडिंग और प्रोजेक्ट मैनेजमेंट सीखेगी। उसका लक्ष्य तकनीकी करियर बनाना है। उसे कौन सा विकल्प चुनना चाहिए?"],"options":["ब्रांड नाम के लिए बहुराष्ट्रीय","इंटर्नशिप छोड़ना और स्वयं अध्ययन करना","दोनों एक साथ करना","व्यावहारिक अनुभव के लिए स्टार्टअप"],"solution":"Career goal tech hai to brand name wali MNC me data entry se better hai startup me coding/project management ka practical hands-on experience lena."},"en":{"prompt":["Vidya has two internship options: one at a large multinational company doing data entry work, and another at a startup where she would learn coding and project management. Her goal is to build a tech career. Which option should she choose?"],"options":["The MNC for the brand name","Quit internships and self-study instead","Do both simultaneously","The startup for practical experience"],"solution":"Since her goal is a tech career, getting practical hands-on experience in coding and project management at the startup is better than data entry at a well-known MNC."},"answer":3},{"qn":45,"hi":{"prompt":["एक बहु-सांस्कृतिक प्रोजेक्ट के दौरान, एक सदस्य एक मुहावरेदार वाक्यांश को गलत समझ लेता है और अपमानित महसूस करता है। सबसे अच्छा क्या है?"],"options":["उन्हें प्रोजेक्ट से हटा दें","उनकी भावनाओं को नजरअंदाज करें","संदर्भ के अनुसार वाक्यांश समझाएं और गलतफहमी के लिए माफी मांगें","उन्हें बताएं कि वे बहुत संवेदनशील हैं"],"solution":"Idiomatic phrase misunderstand hone par context explain karke apologize karna respectful aur clarity-focused response hai."},"en":{"prompt":["During a multicultural project, a member misunderstands an idiomatic phrase and feels insulted. What is best?"],"options":["Remove them from the project","Ignore their feelings","Explain the phrase in context and apologize for the misunderstanding","Tell them they are too sensitive"],"solution":"When an idiomatic phrase is misunderstood, explaining it in context and apologizing for the misunderstanding is a respectful, clarity-focused response."},"answer":2}],"set4":[{"qn":46,"hi":{"prompt":["एक कर्मचारी को गोपनीय दस्तावेज एक सार्वजनिक स्थान पर पड़े मिलते हैं। सबसे अच्छा कोर्स ऑफ एक्शन क्या है?"],"options":["कागजातों को नजरअंदाज करें","दूसरों को चीजें इधर-उधर न छोड़ने की चेतावनी दें","दस्तावेज़ सुरक्षा पर्यवेक्षक को सौंपें","फोटो लेकर सोशल मीडिया पर शेयर करें"],"solution":"Confidential documents public jagah milne par ise security supervisor ko handover karna sahi protocol hai, ignore ya share karna security breach badhata hai."},"en":{"prompt":["An employee finds confidential documents lying in a public place. What is the best course of action?"],"options":["Ignore the papers","Warn others not to leave things lying around","Hand the documents over to the security supervisor","Take photos and share them on social media"],"solution":"Finding confidential documents in a public place, handing them to the security supervisor is the correct protocol — ignoring or sharing them increases the security breach."},"answer":2},{"qn":47,"hi":{"prompt":["एक कर्मचारी लंबी यात्रा के कारण लगातार देरी से आता है लेकिन अच्छा प्रदर्शन कर रहा है। प्रबंधक अनुशासन बनाए रखना चाहता है। संतुलित दृष्टिकोण क्या है?"],"options":["बिना बदलाव के बार-बार चेतावनी दें","एक निर्धारित स्वीकार्य विंडो सेट करते हुए लचीले प्रारंभिक घंटे प्रदान करें","कर्मचारी को देरी के लिए निकाल दें","अच्छे प्रदर्शन के कारण देरी को नजरअंदाज करें"],"solution":"Achha performer hai lekin travel ke karan late aata hai to flexible start hours with a fixed acceptable window dena discipline aur flexibility dono balance karta hai."},"en":{"prompt":["An employee is consistently late due to a long commute but performs well. The manager wants to maintain discipline. What is the balanced approach?"],"options":["Give repeated warnings without any change","Offer flexible start hours with a fixed acceptable window","Fire the employee for lateness","Ignore the lateness because of good performance"],"solution":"Since the employee performs well but is late due to travel, offering flexible start hours within a fixed acceptable window balances both discipline and flexibility."},"answer":1},{"qn":48,"hi":{"prompt":["अस्पताल में संसाधनों का दुरुपयोग हो रहा है। प्रशासक को निष्पक्ष तरीके से इसे कैसे ठीक करना चाहिए?"],"options":["बिना समझाए दंड बढ़ाएं","दुरुपयोग को अनदेखा करें, उम्मीद करें कि यह बंद हो जाएगा","सार्वजनिक रूप से एक उपसमूह को दोष दें","पारदर्शी ट्रैकिंग और फीडबैक लागू करें"],"solution":"Resource misuse fix karne ke liye transparent tracking + feedback system implement karna fair aur sustainable solution hai."},"en":{"prompt":["Resources are being misused in a hospital. How should the administrator fix this fairly?"],"options":["Increase penalties without explanation","Ignore the misuse and hope it stops","Publicly blame one subgroup","Implement transparent tracking and feedback"],"solution":"To fix resource misuse, implementing transparent tracking and a feedback system is the fair, sustainable solution."},"answer":3},{"qn":49,"hi":{"prompt":["दो छात्रों पर नकल का आरोप है। एक छात्र का पिछला रिकॉर्ड है; दूसरे छात्र का नहीं है। अभी तक कोई सबूत नहीं है। सबसे अच्छा निर्णय कौन-सा होगा?"],"options":["दोनों को तुरंत निलंबित कर देना चाहिए","केवल बार-बार अपराध करने वालों को ही दंडित करना चाहिए","कार्रवाई से पहले सबूत का इंतज़ार करना चाहिए","बिना रिकॉर्ड वाले छात्र पर भरोसा करना चाहिए"],"solution":"Sabooto ke bina 2 students par cheating allegation hai to fair decision hai evidence aane tak wait karna, kisi ek par bina proof bharosa ya suspend karna galat."},"en":{"prompt":["Two students are accused of cheating. One student has a prior record; the other doesn't. There is no evidence yet. What would be the best decision?"],"options":["Both should be suspended immediately","Only repeat offenders should be punished","Wait for evidence before taking action","Trust the student with no prior record"],"solution":"With no evidence yet against either student, the fair decision is to wait until evidence emerges — trusting one student without proof or suspending either is wrong."},"answer":2},{"qn":50,"hi":{"prompt":["एक परियोजना प्रबंधक की टीम विस्तारित समयसीमा चाहती है, लेकिन ग्राहक मूल तिथि पर ही अड़ा हुआ है। सबसे अच्छा निर्णय क्या होगा?"],"options":["टीम को अनदेखा करना और उन्हें अधिक दबाव में काम कराना","दोनों को संतुष्ट करने के लिए आंशिक वितरण योजना का अनुरोध करें","परियोजना रद्द करना","टीम को बदल देना"],"solution":"Team extended timeline chahti hai, client fix date par ada hai — partial delivery plan dono ko satisfy karne wala balanced middle-ground solution hai."},"en":{"prompt":["A project manager's team wants an extended timeline, but the client insists on the original date. What would be the best decision?"],"options":["Ignore the team and push them to work under more pressure","Request a partial delivery plan to satisfy both","Cancel the project","Replace the team"],"solution":"With the team wanting an extended timeline and the client fixed on the original date, a partial delivery plan that satisfies both is the balanced middle-ground solution."},"answer":1},{"qn":51,"hi":{"prompt":["एक सहकर्मी लंबे ब्रेक लेता है, और टीम का काम आप पर आ जाता है। सबसे रचनात्मक प्रतिक्रिया क्या है?"],"options":["उनका काम चुपके से कर दें","उनसे निजी तौर पर बात करके कारण समझें और साथ मिलकर कार्य वितरण समायोजित करें","तुरंत प्रबंधन से शिकायत करें","उनकी आलस्य के बारे में अफवाहें फैलाएँ"],"solution":"Colleague lambe break lete hain to unse privately reason samjho aur mil kar work distribution adjust karo — chupke se kaam karna ya complain karna reactive hai."},"en":{"prompt":["A colleague takes long breaks, and their team workload falls on you. What is the most constructive response?"],"options":["Quietly do their work for them","Talk to them privately to understand the reason and jointly adjust the workload","Immediately complain to management","Spread rumors about their laziness"],"solution":"If a colleague takes long breaks, talking to them privately to understand the reason and jointly adjusting the workload is the right response — doing their work secretly or complaining immediately is reactive."},"answer":1},{"qn":52,"hi":{"prompt":["आपका दोस्त किसी सार्वजनिक परीक्षा में नकल करता है और आपको चुप रहने के लिए कहता है। सही निर्णय क्या होगा?"],"options":["वफादार बने रहना और चुप रहना","गुमनाम तरीके से उसकी रिपोर्ट करना","केवल एक चेतावनी देना","उससे बात करना लेकिन कोई कार्रवाई न करना"],"solution":"Dost cheating kar raha hai public exam me — anonymously report karna sahi hota hai, integrity maintain karte hue bina public shaming ke."},"en":{"prompt":["Your friend cheats in a public exam and asks you to stay silent. What would be the right decision?"],"options":["Stay loyal and remain silent","Report it anonymously","Give only a warning","Talk to them but take no action"],"solution":"When a friend cheats in a public exam, reporting it anonymously is the right response — it maintains integrity without public shaming."},"answer":1},{"qn":53,"hi":{"prompt":["आपके सहकर्मी आपके द्वारा किए गए काम का श्रेय लेते हैं। आपको कैसे प्रतिक्रिया देनी चाहिए?"],"options":["सहकर्मी का सार्वजनिक रूप से सामना करें","संघर्ष से बचने के लिए चुप रहें","स्थिति के बारे में सहकर्मी और प्रबंधक से शांतिपूर्वक बात करें","सहकर्मी से बचना शुरू करें"],"solution":"Credit-stealing colleague ke against sabse professional step hai colleague aur manager dono se calmly baat karna, public confrontation ya avoidance nahi."},"en":{"prompt":["Your colleague takes credit for work you did. How should you respond?"],"options":["Publicly confront the colleague","Stay silent to avoid conflict","Calmly talk to the colleague and the manager about the situation","Start avoiding the colleague"],"solution":"Against a credit-stealing colleague, the most professional step is calmly talking to both the colleague and the manager, not public confrontation or avoidance."},"answer":2},{"qn":54,"hi":{"prompt":["आप एक समूह असाइनमेंट में भाग ले रहे हैं, और एक सदस्य लगातार अपना काम देर से जमा करता है, जिससे टीम की प्रगति प्रभावित होती है। आप उनसे एक बार बात भी कर चुके हैं। अब आपका अगला सबसे अच्छा कदम क्या होगा?"],"options":["आगे की देरी से बचने के लिए अपना काम स्वयं पूरा करें","बिना कुछ कहे तुरंत शिक्षक को इसकी सूचना दें","उनके साथ स्पष्ट, छोटे समय-सीमाएं तय करें और सहायता प्रदान करें, तथा यदि समस्या बनी रहे तो ही शिक्षक से बात करें","उन्हें फाइनल प्रेजेंटेशन से बाहर निकाल दें"],"solution":"Ek baar baat ho chuki hai, ab agla step clear chhoti deadlines set karna + support dena hai, aur agar problem persist kare tabhi teacher tak jaana."},"en":{"prompt":["You're in a group assignment, and one member consistently submits their work late, affecting the team's progress. You've already spoken to them once. What is your next best step?"],"options":["Complete their work yourself to avoid further delay","Immediately report it to the teacher without saying anything to them","Set clear, short deadlines with them and offer support, going to the teacher only if the problem persists","Remove them from the final presentation"],"solution":"Since you've already spoken to them once, the next step is setting clear short deadlines with support, and going to the teacher only if the problem persists."},"answer":2},{"qn":55,"hi":{"prompt":["आपका सहकर्मी देर से आता है क्योंकि वे एक बीमार परिवार के सदस्य की देखभाल कर रहे हैं। दूसरे उससे नाराज़ हैं। सामाजिक रूप से बुद्धिमान कार्रवाई क्या है?"],"options":["तनाव बढ़ने दें और नजरअंदाज करें","उनका समर्थन करें और टीम को स्थिति समझाते हुए अस्थायी बदलाव का सुझाव दें","टीम को शिकायत करने के लिए प्रोत्साहित करें","उनसे इस्तीफा देने की मांग करें"],"solution":"Family emergency ki wajah se late aa raha colleague — usko support karo aur team ko situation samjhate hue temporary adjustment suggest karo."},"en":{"prompt":["Your colleague arrives late because they are caring for a sick family member. Others are annoyed with them. What is the socially intelligent action?"],"options":["Let the tension build and ignore it","Support them and suggest a temporary adjustment while explaining the situation to the team","Encourage the team to complain","Demand their resignation"],"solution":"A colleague arriving late due to a family emergency should be supported, and the team should be told about the situation with a suggested temporary adjustment."},"answer":1},{"qn":56,"hi":{"prompt":["आपको पता चलता है कि आपका कोई सहकर्मी आपके काम का श्रेय ले रहा है। निम्न में से सबसे पेशेवर फैसला कौनसा होगा?"],"options":["उसे सार्वजनिक रूप से शर्मिंदा करना","अपनी नौकरी छोड़ देना","सबूत के साथ अपने प्रबंधक से बात करना","इसे अनदेखा करना और कड़ी मेहनत करना"],"solution":"Credit-stealing colleague ke against evidence ke saath manager se baat karna most professional step hai — public shaming ya silent hard work nahi."},"en":{"prompt":["You discover that a colleague is taking credit for your work. Which of the following would be the most professional decision?"],"options":["Publicly embarrass them","Quit your job","Talk to your manager with evidence","Ignore it and work harder"],"solution":"Against a credit-stealing colleague, talking to your manager with evidence is the most professional step — not public shaming or silently working harder."},"answer":2},{"qn":57,"hi":{"prompt":["एक करीबी दोस्त एक करियर विकल्प ले रहा है जिसे आप अनुचित मानते हैं। दोस्ती को नुकसान पहुँचाए बिना प्रभावित करने का सबसे अच्छा तरीका क्या है?"],"options":["उन्हें नज़रअंदाज़ करें और असफल होने दें","उदाहरणों के साथ अपनी चिंताएँ साझा करें और पूछें कि क्या उन्होंने विकल्पों पर विचार किया है","सीधे उन्हें बताएँ कि वे गलती कर रहे हैं","म्युचुअल दोस्तों के बीच संदेह फैलाएँ"],"solution":"Career choice galat lag rahi ho dost ki to friendship na todte hue apni concerns examples ke saath share karo aur pucho ki unhone alternatives consider kiye hain ya nahi."},"en":{"prompt":["A close friend is making a career choice you consider unwise. What is the best way to influence them without damaging the friendship?"],"options":["Ignore them and let them fail","Share your concerns with examples and ask if they've considered alternatives","Directly tell them they are making a mistake","Spread doubt among mutual friends"],"solution":"If a friend's career choice seems wrong, sharing your concerns with examples and asking whether they've considered alternatives preserves the friendship."},"answer":1},{"qn":58,"hi":{"prompt":["आपके शीर्ष प्रदर्शनकर्ता ने सहायक कर्मचारियों के साथ अशिष्ट व्यवहार किया है। निम्न में से सही दृष्टिकोण क्या है?"],"options":["उन्हें तुरंत नौकरी से निकाल देना चाहिए","उत्पादकता के लिए अनदेखा कर देना चाहिए","चेतावनी जारी करनी चाहिए और व्यवहार की निगरानी की जानी चाहिए","किसी भी तरह से उन्हें बढ़ावा देना चाहिए"],"solution":"Top performer bhi agar rude behave kare to warning + behavior monitoring balanced disciplinary approach hai, na fire karna na ignore karna."},"en":{"prompt":["Your top performer has behaved rudely toward support staff. Which of the following is the correct approach?"],"options":["Fire them immediately","Ignore it for the sake of productivity","Issue a warning and monitor their behavior","Promote them regardless"],"solution":"Even a top performer behaving rudely calls for a warning plus behavior monitoring — a balanced disciplinary approach, neither firing nor ignoring."},"answer":2},{"qn":59,"hi":{"prompt":["परीक्षा के दौरान एक छात्र फुसफुसाते हुए पकड़ा जाता है, लेकिन कहता है कि वह पेन मांग रहा था। आपने नकल करते नहीं देखा। क्या किया जाना चाहिए?"],"options":["उनका पेपर कैंसिल कर देना चाहिए","चेतावनी देनी चाहिए और परीक्षा जारी रखने की अनुमति देनी चाहिए","अन्य निरीक्षकों से उन पर नजर रखने के लिए कहना चाहिए","तुरंत शिकायत दर्ज करनी चाहिए"],"solution":"Cheating dekhi nahi, sirf whisper suna hai to benefit of doubt dete hue warning dena aur exam continue karne dena fair approach hai."},"en":{"prompt":["During an exam, a student is caught whispering but claims they were asking for a pen. You did not see them cheating. What should be done?"],"options":["Cancel their paper","Give a warning and allow the exam to continue","Ask other invigilators to watch them","File a complaint immediately"],"solution":"Since cheating wasn't actually witnessed, only whispering was heard, giving the benefit of the doubt with a warning and letting the exam continue is fair."},"answer":1},{"qn":60,"hi":{"prompt":["एक शहर में खराब समय पर सेट किए गए ट्रैफिक सिग्नलों के कारण जाम हो रहा है। तत्काल व्यावहारिक कदम क्या है?"],"options":["भीड़भाड़ वाले क्षेत्रों में प्रवेश के लिए टोल चार्ज करें","दिन के समय सभी वाहनों पर प्रतिबंध लगाएँ","तुरंत नई सड़कें बनाएं","चरम पैटर्न के आधार पर सिग्नलों को सिंक्रोनाइज़ करें"],"solution":"Poor traffic signal timing se jam ho raha hai to turant practical fix hai peak patterns ke hisaab se signals ko synchronize karna, naye roads banana slow/costly hai."},"en":{"prompt":["A city is facing jams due to poorly timed traffic signals. What is the immediate practical step?"],"options":["Charge tolls for entering congested areas","Ban all vehicles during the day","Build new roads immediately","Synchronize signals based on peak patterns"],"solution":"Since poor signal timing is causing jams, the immediate practical fix is synchronizing signals based on peak patterns — building new roads is slow and costly."},"answer":3}],"set5":[{"qn":61,"hi":{"prompt":["आप एक प्रेजेंटेशन दे रहे हैं, और पीछे बैठे कुछ छात्र जम्हाई ले रहे हैं, छत की ओर देख रहे हैं, और कभी-कभी अपने फोन देख रहे हैं। वे कौन से अशाब्दिक संकेत दे रहे हैं, और आपको किस निर्णय पर विचार करना चाहिए?"],"options":["वे गहन ध्यान लगा रहे हैं; ऐसे ही चलते रहें","वे ऊब गए हैं या उनसे कोई बातचीत नहीं हो रही है; उन्हें प्रश्न पूछकर या बातचीत के माध्यम से पुनः बातचीत में शामिल करने का प्रयास करें","वे बस थके हुए हैं; उनके व्यवहार को अनदेखा करें","वे अनादर कर रहे हैं; प्रेजेंटेशन रोक दीजिए और उन्हें फटकार लगाइए"],"solution":"Peeche baithe students yawn/phone dekh rahe hain — ye boredom/disengagement ka non-verbal sign hai, isliye unhe questions/interaction se dobara engage karna sahi decision hai."},"en":{"prompt":["You are giving a presentation, and some students at the back are yawning, looking at the ceiling, and occasionally checking their phones. What non-verbal cues are they showing, and what decision should you consider?"],"options":["They are deeply focused; continue as is","They are bored or disengaged; try to re-engage them through questions or interaction","They are just tired; ignore their behavior","They are being disrespectful; stop the presentation and reprimand them"],"solution":"Yawning and checking phones at the back are non-verbal signs of boredom or disengagement, so re-engaging them through questions or interaction is the right decision."},"answer":1},{"qn":62,"hi":{"prompt":["आप एक न्यायाधीश हैं और अभियुक्त दोषी साबित हो चुका है, लेकिन वह मानसिक रूप से अस्थिर भी है। निम्न में से उचित फैसला क्या होगा?"],"options":["अधिकतम सजा","तत्काल रिहाई","सजा सुनाए जाने से पहले मनोवैज्ञानिक मूल्यांकन का संदर्भ लेना","मानसिक स्थिति को नजरअंदाज करना"],"solution":"Accused guilty saabit ho chuka hai but mentally unstable bhi hai — sentencing se pehle psychological evaluation refer karna fair judicial process hai."},"en":{"prompt":["You are a judge and the accused has been proven guilty, but is also mentally unstable. Which of the following would be the appropriate decision?"],"options":["Maximum punishment","Immediate release","Refer for a psychological evaluation before sentencing","Ignore the mental condition"],"solution":"Since the accused is guilty but also mentally unstable, referring for a psychological evaluation before sentencing is the fair judicial process."},"answer":2},{"qn":63,"hi":{"prompt":["एक दुकानदार के आपूर्तिकर्ता ने डिलीवरी में देरी की है, जिससे कमी हो गई है। ग्राहकों का विश्वास बनाए रखने के लिए उसे क्या करना चाहिए?"],"options":["प्रभावित वस्तुओं की बिक्री बंद करें","सप्लायर को सार्वजनिक रूप से दोष दें","कीमतें बढ़ाएँ और कमी को छिपाएँ","ग्राहकों को पारदर्शिता से सूचित करें और विकल्प प्रदान करें"],"solution":"Supplier delay se shortage hui to customers ko transparently inform karna aur alternatives dena trust maintain karta hai, price badhana ya chhupana nahi."},"en":{"prompt":["A shopkeeper's supplier has delayed delivery, causing a shortage. What should he do to maintain customer trust?"],"options":["Stop selling the affected items","Publicly blame the supplier","Raise prices and hide the shortage","Transparently inform customers and offer alternatives"],"solution":"When a supplier delay causes a shortage, transparently informing customers and offering alternatives maintains trust, rather than raising prices or hiding it."},"answer":3},{"qn":64,"hi":{"prompt":["एक टीम उत्सव के दौरान, कोई गलती से एक जूनियर पर पेय गिरा देता है। सबसे अच्छी प्रतिक्रिया क्या है?"],"options":["सफाई में मदद करें और उन्हें आश्वस्त करें कि यह अनजाने में हुआ था","नजरअंदाज करके चले जाएं","जूनियर पर हँसें","व्यंग्यात्मक टिप्पणी करें"],"solution":"Junior par accidentally drink gira to cleanup me help karo aur reassure karo ki ye anjaane me hua — supportive kind response."},"en":{"prompt":["During a team celebration, someone accidentally spills a drink on a junior. What is the best response?"],"options":["Help clean up and reassure them it was unintentional","Ignore it and walk away","Laugh at the junior","Make a sarcastic comment"],"solution":"When a drink is accidentally spilled on a junior, helping clean up and reassuring them it was unintentional is the supportive, kind response."},"answer":0},{"qn":65,"hi":{"prompt":["आप दो दोस्तों के बीच बहस में परस्पर विरोधी कहानियाँ सुनते हैं। निष्पक्ष निर्णय लेने का सबसे तर्कसंगत तरीका कौनसा है?"],"options":["उस व्यक्ति का समर्थन करना जिसे आप लंबे समय से जानते हैं","अपनी अंतर्दृष्टि के अनुसार चलना","दोनों पक्षों की तुलना करना और तथ्यों की पुष्टि करना","किसी भी प्रकार का निर्णय देने से बचना"],"solution":"Do dosto ki conflicting stories sunte hue fair decision ka sabse rational tarika dono sides compare karke facts verify karna hai."},"en":{"prompt":["You hear conflicting stories in an argument between two friends. What is the most rational way to reach a fair decision?"],"options":["Support the person you've known longer","Go with your own intuition","Compare both sides and verify the facts","Avoid giving any judgment at all"],"solution":"When hearing conflicting stories between two friends, the most rational way to reach a fair decision is comparing both sides and verifying the facts."},"answer":2},{"qn":66,"hi":{"prompt":["एक बाढ़ राहत वाहन केवल 10 लोगों को ले जा सकता है। 15 लोग इंतजार कर रहे हैं, जिनमें बुजुर्ग, बच्चे और स्वस्थ वयस्क शामिल हैं। इनमें से किसे प्राथमिकता दी जानी चाहिए?"],"options":["जो पहले आएगा उसे पहले ले जाया जाएगा","बाद में दूसरों की मदद करने हेतु वयस्कों को","बुजुर्गों और बच्चों को","यादृच्छिक चयन को"],"solution":"Flood relief vehicle limited hai (10 seats, 15 log) — sabse vulnerable groups (elderly aur children) ko priority deni chahiye, first-come-first-serve ya random selection nahi."},"en":{"prompt":["A flood relief vehicle can carry only 10 people. 15 people are waiting, including elderly people, children, and healthy adults. Who should be given priority?"],"options":["First come, first served","Adults, so they can help others later","The elderly and children","Random selection"],"solution":"With a limited flood relief vehicle (10 seats, 15 people), priority should go to the most vulnerable groups — the elderly and children — not first-come-first-served or random selection."},"answer":2},{"qn":67,"hi":{"prompt":["आप देखते हैं कि एक नए छात्र को लोकप्रिय छात्रों के एक छोटे समूह द्वारा अलग-थलग कर दिया जाता है और उसका मजाक उड़ाया जाता है। आपका नैतिक निर्णय क्या है?"],"options":["स्वयं निशाना बनने से बचने के लिए इसे अनदेखा करें","लोकप्रिय समूह में शामिल हो जाएँ","नए छात्र से सावधानीपूर्वक संपर्क करें और उसे सहायता प्रदान करें, या किसी विश्वसनीय वयस्क को बदमाशी की सूचना दें","सार्वजनिक रूप से लोकप्रिय समूह का सामना करें, इससे विवाद बढ़ने का खतरा है"],"solution":"New student ko isolate/mock kiya ja raha hai to unse carefully reach out karo ya trusted adult ko bullying report karo — sabse ethical response."},"en":{"prompt":["You notice a new student being isolated and mocked by a small group of popular students. What is your ethical decision?"],"options":["Ignore it to avoid becoming a target yourself","Join the popular group","Carefully reach out to the new student and offer support, or report the bullying to a trusted adult","Publicly confront the popular group, risking escalation"],"solution":"When a new student is being isolated or mocked, carefully reaching out to offer support or reporting the bullying to a trusted adult is the most ethical response."},"answer":2},{"qn":68,"hi":{"prompt":["आपके व्यवसाय साथी नाराज़ हैं क्योंकि आपने उनसे सलाह लिए बिना एक निर्णय लिया। विश्वास कैसे बहाल करें?"],"options":["उनकी भावनाओं को नजरअंदाज करें और आगे बढ़ें","बाहरी दबाव का दोष दें","माफी मांगें, तर्क समझाएँ और भविष्य के निर्णयों में उन्हें शामिल करें","उन्हें निकाल दें"],"solution":"Business partner ka trust todne par apologize karna, reasoning explain karna aur future decisions me unhe involve karna trust rebuild karta hai."},"en":{"prompt":["Your business partner is upset because you made a decision without consulting them. How do you restore trust?"],"options":["Ignore their feelings and move on","Blame outside pressure","Apologize, explain your reasoning, and involve them in future decisions","Fire them"],"solution":"After breaking a business partner's trust, apologizing, explaining your reasoning, and involving them in future decisions rebuilds trust."},"answer":2},{"qn":69,"hi":{"prompt":["आपने एक गलती की जिसके कारण आपकी टीम को एक क्लाइंट खोना पड़ा। भावनात्मक रूप से समझदार प्रतिक्रिया क्या होगी?"],"options":["अपनी नौकरी बचाने के लिए दूसरों पर दोष डालें","अपनी गलती मानें और सुधार के बारे में चर्चा करें","मुद्दे को नजरअंदाज करके आगे बढ़ें","सभी शामिल लोगों से बहुत अधिक माफी मांगें"],"solution":"Apni galti se client loss hua ho to blame shift karne ke bajaye mistake accept karke improvement discuss karna emotionally mature response hai."},"en":{"prompt":["You made a mistake that caused your team to lose a client. What would be the emotionally intelligent response?"],"options":["Shift the blame to others to save your job","Accept your mistake and discuss improvements","Ignore the issue and move on","Over-apologize to everyone involved"],"solution":"When your mistake causes a client loss, accepting the mistake and discussing improvements — instead of shifting blame — is the emotionally mature response."},"answer":1},{"qn":70,"hi":{"prompt":["आपका बिजनेस पार्टनर मीटिंग में लगातार आपको बीच में काटता है, जिससे आपको कम महत्व दिया हुआ लगता है। सबसे अच्छा सामाजिक बुद्धिमत्ता वाला जवाब क्या होगा?"],"options":["प्रभुत्व जताने के लिए आक्रामक तरीके से जवाबी हमला करें","चुपके से अपना अलग व्यवसाय शुरू करें","मीटिंग के बाद शांति से चर्चा करें कि बीच में टोकना सहयोग को कैसे प्रभावित करता है और बारी-बारी से बोलने का सुझाव दें","आइडिया शेयर करना बंद कर दें"],"solution":"Meeting me baar baar interrupt karne wale partner se baad me shanti se baat karo ki interruption collaboration ko kaise affect karta hai, aur turn-taking suggest karo."},"en":{"prompt":["Your business partner keeps interrupting you in meetings, making you feel undervalued. What would be the best socially intelligent response?"],"options":["Counter-interrupt aggressively to assert dominance","Quietly start a separate business","Calmly discuss after the meeting how interrupting affects collaboration and suggest taking turns","Stop sharing ideas altogether"],"solution":"When a partner keeps interrupting in meetings, calmly discussing afterward how it affects collaboration and suggesting turn-taking is the best response."},"answer":2},{"qn":71,"hi":{"prompt":["एक व्यक्ति नकदी से भरा खोया हुआ बटुआ वापस लौटा देता है, लेकिन ₹100 का नोट ले लेता है। निम्न में से सबसे तार्किक निर्णय कौन-सा होगा?"],"options":["वह एक चोर है","वह ईमानदार है","उसने आंशिक तौर पर ईमानदारी दिखाई","वह इनाम का हकदार है"],"solution":"Wallet return kiya lekin ₹100 rakh liya — pura honest nahi lekin pura dishonest bhi nahi, isliye 'partial honesty' sabse logical description hai."},"en":{"prompt":["A person returns a lost wallet full of cash, but keeps a ₹100 note. Which of the following would be the most logical judgment?"],"options":["He is a thief","He is honest","He showed partial honesty","He deserves a reward"],"solution":"He returned the wallet but kept ₹100 — not fully honest, but not fully dishonest either, so 'partial honesty' is the most logical description."},"answer":2},{"qn":72,"hi":{"prompt":["एक CEO को पता चलता है कि कंपनी में उनके एक करीबी दोस्त ने डेटा लीक किया है। इसके ठोस सबूत हैं। निम्न में से सबसे सैद्धांतिक फैसला क्या होगा?"],"options":["दोस्ती की खातिर अनदेखा करना","दोस्त को निजी तौर पर नौकरी से निकाल देना","पारदर्शी अनुशासनात्मक कार्रवाई करना","दोस्त को दूसरे विभाग में स्थानांतरित करना"],"solution":"Close friend ke against solid evidence ho to CEO ka sahi principled decision transparent disciplinary action lena hai, friendship ki wajah se ignore ya secretly transfer karna nahi."},"en":{"prompt":["A CEO discovers that a close friend at the company leaked data, with solid evidence. Which of the following would be the most principled decision?"],"options":["Ignore it for the sake of friendship","Fire the friend privately","Take transparent disciplinary action","Transfer the friend to another department"],"solution":"With solid evidence against a close friend, the CEO's principled decision is transparent disciplinary action — not ignoring it or secretly transferring the friend."},"answer":2},{"qn":73,"hi":{"prompt":["एक सॉफ़्टवेयर कंपनी जल्दी एक बग से भरा उत्पाद लॉन्च कर सकती है या गुणवत्ता के लिए उसे विलंबित कर सकती है। समझदारी भरा निर्णय क्या होगा?"],"options":["अभी लॉन्च करना और बाद में सुधार करना","लॉन्च को विलंबित करना और स्थिरता सुनिश्चित करना","उत्पाद रद्द करना","पहले सीमित दर्शकों के लिए जारी करना"],"solution":"Bug-filled product jaldi launch karne se better hai limited audience ke liye pehle release karna (beta approach) — balanced smart decision."},"en":{"prompt":["A software company can launch a bug-filled product early or delay it for quality. What would be the wise decision?"],"options":["Launch now and fix later","Delay the launch to ensure stability","Cancel the product","Release first to a limited audience"],"solution":"Rather than launching a bug-filled product immediately, releasing it first to a limited audience (a beta approach) is the balanced, smart decision."},"answer":3},{"qn":74,"hi":{"prompt":["आप एक धन जुटाने वाला कार्यक्रम आयोजित कर रहे हैं। आप एक छोटे, विशिष्ट कार्यक्रम के लिए ज्यादा टिकट शुल्क या एक बड़े, समावेशी कार्यक्रम के लिए कम टिकट शुल्क चुन सकते हैं। आपका मुख्य लक्ष्य कुल एकत्रित धनराशि को अधिकतम करना है। इनमें से कौन सा निर्णय सबसे प्रभावी है?"],"options":["टिकट की अधिक कीमत, छोटा आयोजन","कम टिकट कीमत, बड़ा आयोजन","सही संतुलन बनाए रखने के लिए संभावित उपस्थिति बनाम टिकट मूल्य की सावधानीपूर्वक गणना करें","कोई शुल्क न लें, केवल दान मांगें"],"solution":"Fund maximize karna goal hai to sirf high price/small event ya low price/big event chunne ke bajaye attendance vs ticket price ka careful calculation karke optimal balance nikalna hai."},"en":{"prompt":["You are organizing a fundraiser. You can choose a small, exclusive event with a high ticket price or a large, inclusive event with a lower ticket price. Your main goal is to maximize the total funds raised. Which decision is most effective?"],"options":["High ticket price, small event","Low ticket price, large event","Carefully calculate expected attendance versus ticket price to find the right balance","Charge no fee, only ask for donations"],"solution":"Since the goal is maximizing funds, carefully calculating expected attendance versus ticket price to find the optimal balance beats simply picking high-price/small or low-price/large."},"answer":2},{"qn":75,"hi":{"prompt":["आपको अपने प्रेजेंटेशन में एक तथ्यात्मक त्रुटि मिली है, लेकिन उसे ठीक करने के लिए आपको एक महत्वपूर्ण भाग दोबारा लिखना होगा और संभवतः आपके कार्यक्रम में देरी भी हो सकती है। सबसे पेशेवर निर्णय क्या है?"],"options":["प्रेजेंटेशन में गलतियों को शामिल करें, आशा करें कि यह ध्यान में न आए","प्रेजेंटेशन कैंसल कर दें","गलतियों को संक्षेप में समझाएं और सही जानकारी प्रस्तुत करें, भले ही इससे थोड़ी देरी हो","सूचना के स्रोत को दोष दें"],"solution":"Presentation me factual error mile to delay ho jaye phir bhi briefly explain karke correct info present karna professional integrity dikhata hai."},"en":{"prompt":["You find a factual error in your presentation, but fixing it means rewriting a significant part and possibly delaying your event. What is the most professional decision?"],"options":["Include the mistakes in the presentation, hoping no one notices","Cancel the presentation","Briefly explain the mistakes and present the correct information, even if it causes some delay","Blame the source of the information"],"solution":"On finding a factual error, briefly explaining the mistake and presenting correct information — even at the cost of some delay — shows professional integrity."},"answer":2}],"set6":[{"qn":76,"hi":{"prompt":["यदि प्रस्तुति के दौरान टीम का कोई सदस्य घबरा जाए, तो भावनात्मक रूप से समझदारी भरा जवाब क्या होगा?"],"options":["उनसे बात करने से बचें","जबरदस्ती सलाह थोपें","उनकी भावनाओं को नजरअंदाज करें","बिना दबाव डाले सुनने की पेशकश करें"],"solution":"Team member panic ho jaye presentation me to bina force kiye sirf listen karne ki offer dena emotionally supportive response hai."},"en":{"prompt":["If a team member panics during a presentation, what would be the emotionally intelligent response?"],"options":["Avoid talking to them","Force advice on them","Ignore their feelings","Offer to listen without pressure"],"solution":"If a team member panics during a presentation, offering to listen without forcing anything is the emotionally supportive response."},"answer":3},{"qn":77,"hi":{"prompt":["एक मुखबिर आपके संगठन में भ्रष्टाचार का पर्दाफाश करता है, लेकिन आंतरिक गोपनीयता के नियमों का उल्लंघन करता है। आपको क्या करना चाहिए?"],"options":["नियमों का उल्लंघन करने पर उसे दंडित करना चाहिए","एक नायक के रूप में उसकी प्रशंसा करनी चाहिए","उनकी पहचान सुरक्षित रखनी चाहिए और दावे की जाँच करनी चाहिए","उसे चुपचाप निकाल देना चाहिए"],"solution":"Whistleblower ne confidentiality break ki lekin corruption expose ki — identity protect karo aur claim ki jaanch karo, na turant punish karo na blindly praise."},"en":{"prompt":["A whistleblower exposes corruption in your organization but violates internal confidentiality rules. What should you do?"],"options":["Punish them for breaking the rules","Praise them as a hero","Protect their identity and investigate the claim","Quietly fire them"],"solution":"The whistleblower broke confidentiality but exposed corruption — protect their identity and investigate the claim, neither punishing immediately nor blindly praising."},"answer":2},{"qn":78,"hi":{"prompt":["यदि आपको एक ही समय में अलग-अलग प्रबंधकों से दो जरूरी कार्य मिलते हैं, तो सबसे अच्छा तरीका क्या होगा?"],"options":["पूछें कि किसे प्राथमिकता देनी है","आसान काम पहले करें","जो आपको पसंद हो उसे चुनें","एक कार्य छोड़ें"],"solution":"Do urgent tasks alag managers se aaye to sabse practical step hai pooch lena ki kise priority di jaaye, guess karna ya khud choose karna risky hai."},"en":{"prompt":["If you receive two urgent tasks from different managers at the same time, what would be the best approach?"],"options":["Ask which one should be prioritized","Do the easier task first","Choose whichever you prefer","Drop one task"],"solution":"With two urgent tasks from different managers, the most practical step is asking which should be prioritized — guessing or choosing yourself is risky."},"answer":0},{"qn":79,"hi":{"prompt":["आपकी आखिरी ट्रेन छूट गई है और फिर भी आपको सुरक्षित घर पहुँचना है। सबसे अच्छा फैसला क्या होगा?"],"options":["असुरक्षित क्षेत्र से अकेले चलें","मदद के लिए किसी अजनबी को बुलाएँ","स्टेशन पर सो जाओ","सुरक्षित उपलब्ध टैक्सी/सवारी लें"],"solution":"Last train miss ho gayi, ghar safely pahunchna hai to safe available taxi/ride lena best decision hai — akele unsafe area walk karna risky."},"en":{"prompt":["You've missed your last train and still need to get home safely. What would be the best decision?"],"options":["Walk alone through an unsafe area","Call a stranger for help","Sleep at the station","Take a safe available taxi/ride"],"solution":"Having missed the last train and needing to get home safely, taking a safe available taxi or ride is the best decision — walking alone through an unsafe area is risky."},"answer":3},{"qn":80,"hi":{"prompt":["आपको पहले से सबमिट की गई ग्राहक रिपोर्ट में एक जोखिम भरी त्रुटि मिलती है। सबसे अच्छा कदम क्या होगा?"],"options":["आशा है ग्राहक को पता नहीं चलेगा","दूसरे विभाग को दोष दो","त्रुटि पर ध्यान न दें","ग्राहक को त्रुटि के बारे में सूचित करें और सुधार भेजें"],"solution":"Submitted report me risky error mile to client ko turant inform karke correction bhejna hi honest professional step hai, hide karna risk badhata hai."},"en":{"prompt":["You find a risky error in a client report that has already been submitted. What would be the best step?"],"options":["Hope the client doesn't notice","Blame another department","Ignore the error","Inform the client about the error and send a correction"],"solution":"On finding a risky error in a submitted report, immediately informing the client and sending a correction is the honest, professional step — hiding it increases risk."},"answer":3},{"qn":81,"hi":{"prompt":["आप एक वन अधिकारी हैं और एक स्थानीय त्योहार संवेदनशील क्षेत्र में प्रदूषण का कारण बनता है। आपका सबसे अच्छा कदम क्या है?"],"options":["पर्यावरण अनुकूल समारोहों के लिए स्थानीय नेताओं के साथ समन्वय करें","त्योहार पर स्थायी रूप से प्रतिबंध लगाएं","चुप रहें","क्षेत्र छोड़ें"],"solution":"Festival se pollution ho raha ho to local leaders ke saath coordinate karke eco-friendly celebrations plan karna practical balanced solution hai, ban lagana extreme hai."},"en":{"prompt":["You are a forest officer, and a local festival is causing pollution in a sensitive area. What is your best step?"],"options":["Coordinate with local leaders for eco-friendly celebrations","Permanently ban the festival","Stay silent","Leave the area"],"solution":"When a festival is causing pollution, coordinating with local leaders to plan eco-friendly celebrations is the practical, balanced solution — an outright ban is extreme."},"answer":0},{"qn":82,"hi":{"prompt":["एक गरमागरम समूह चर्चा में, एक भावनात्मक रूप से बुद्धिमान व्यक्ति को क्या करना चाहिए?"],"options":["तुरंत पक्ष लें","अपनी बात रखने के लिए चिल्लाओ","गुस्से में चले जाओ","दोनों पक्षों को शांतिपूर्वक सुनें"],"solution":"Heated discussion me emotionally intelligent person dono sides ko shanti se sunta hai, side lena ya chillana nahi."},"en":{"prompt":["In a heated group discussion, what should an emotionally intelligent person do?"],"options":["Immediately take a side","Shout to make your point","Angrily walk away","Calmly listen to both sides"],"solution":"In a heated discussion, an emotionally intelligent person calmly listens to both sides, rather than taking sides or shouting."},"answer":3},{"qn":83,"hi":{"prompt":["आप देखते हैं कि हाल ही में हुई एक व्यक्तिगत हानि के बाद एक महत्वपूर्ण बैठक में आपका मैनेजर असामान्य रूप से चुप है। टीम को फैसलों की उम्मीद होती है। सर्वोत्तम क्रिया क्या है?"],"options":["महत्वपूर्ण चर्चाओं के लिए पहल करें और बाद में समर्थन प्रदान करें","प्रबंधक के बोलने तक चुप रहें","उनके नुकसान के बारे में दखल देने वाले प्रश्न पूछें","नेतृत्व की कमी की आलोचना करें"],"solution":"Manager personal loss ke baad quiet hai but team ko decisions chahiye — khud initiative lo important discussions ke liye aur baad me support offer karo."},"en":{"prompt":["You notice your manager is unusually quiet in an important meeting following a recent personal loss. The team expects decisions. What is the best action?"],"options":["Take initiative for important discussions and offer support afterward","Stay silent until the manager speaks","Ask intrusive questions about their loss","Criticize their lack of leadership"],"solution":"With the manager quiet after a personal loss but the team needing decisions, taking the initiative on important discussions and offering support afterward is best."},"answer":0},{"qn":84,"hi":{"prompt":["एक मित्र परीक्षा में असफल हो जाता है। भावनात्मक बुद्धिमत्ता क्या दर्शाती है?"],"options":["अपनी सफलता का जश्न मनाएं","अगली बार तैयारी करने में मदद की पेशकश करें","कहें \"यह तुम्हारी गलती है\"","जल्दी से विषय बदलो"],"solution":"Dost exam me fail ho gaya to sabse emotionally intelligent response hai agli baar prepare karne me help offer karna, blame ya deflect karna nahi."},"en":{"prompt":["A friend fails an exam. What does emotional intelligence look like?"],"options":["Celebrate your own success","Offer to help them prepare next time","Say \"it's your own fault\"","Quickly change the subject"],"solution":"When a friend fails an exam, the most emotionally intelligent response is offering to help them prepare next time, not blaming or deflecting."},"answer":1},{"qn":85,"hi":{"prompt":["आप किसी सहकर्मी को सुरक्षा नियम का उल्लंघन करते हुए देखते हैं। आपको क्या करना चाहिए?"],"options":["अगर अभी कोई नुकसान न हो तो अनदेखा करें","पर्यवेक्षक को तुरंत रिपोर्ट करें","उन्हें मौके पर ही विनम्रता से सुधारें","फोटो लें और ऑनलाइन साझा करें"],"solution":"Colleague safety rule todte dekha to unhe politely on-the-spot correct karna sahi hai — turant supervisor ko escalate karna ya photo lena zyada extreme hai jab tak koi immediate harm na ho."},"en":{"prompt":["You see a colleague violating a safety rule. What should you do?"],"options":["Ignore it if there's no immediate harm","Report it immediately to the supervisor","Politely correct them on the spot","Take a photo and share it online"],"solution":"On seeing a colleague break a safety rule, politely correcting them on the spot is right — escalating to a supervisor immediately or taking photos is excessive unless there's immediate harm."},"answer":2},{"qn":86,"hi":{"prompt":["आपको अपनी विशेषज्ञता से बाहर एक चुनौतीपूर्ण कार्य सौंपा गया है। सबसे भावनात्मक रूप से बुद्धिमान रवैया क्या है?"],"options":["असुविधा के कारण मना करना","सहायता या प्रशिक्षण स्वीकार करें और अनुरोध करें","प्रबंधक के निर्णय के बारे में शिकायत करें","स्वीकार करो लेकिन कठिनाइयों को छिपाओ"],"solution":"Apni expertise se bahar ka task mile to help/training request karna emotionally intelligent aur mature response hai, refuse karna ya chhupana nahi."},"en":{"prompt":["You've been assigned a challenging task outside your expertise. What is the most emotionally intelligent attitude?"],"options":["Refuse due to discomfort","Accept help or training and ask for it","Complain about the manager's decision","Accept it but hide your struggles"],"solution":"When assigned a task outside your expertise, requesting help or training is the emotionally intelligent, mature response, not refusing or hiding struggles."},"answer":1},{"qn":87,"hi":{"prompt":["प्रस्तुति के दौरान आपके पास एक महत्वपूर्ण वस्तु कम पड़ गई है। आपको क्या करना चाहिए?"],"options":["प्रस्तुति रोकें","दर्शकों से जोर से उधार लें","रद्द करें और पुनर्निर्धारित करें","उपलब्ध संसाधनों के साथ सुधार करें"],"solution":"Presentation me item kam pad gaya to available resources se improvise karna sabse practical solution hai, cancel karna extreme step hai."},"en":{"prompt":["You run short of an essential item during a presentation. What should you do?"],"options":["Stop the presentation","Loudly borrow from the audience","Cancel and reschedule","Improvise with available resources"],"solution":"Running short of an item during a presentation, improvising with available resources is the most practical solution — cancelling is extreme."},"answer":3},{"qn":88,"hi":{"prompt":["आप समय सीमा के अनुसार काम कर रहे हैं, लेकिन आपको परिवार से एक जरूरी फोन आता है। सबसे अच्छा फैसला क्या होगा?"],"options":["तात्कालिकता का आकलन करने के लिए उत्तर दें","कॉल को अनदेखा करें","बिना बताए काम छोड़ना","फोन बंद कर दें"],"solution":"Deadline ke beech important family call aaye to turant answer karke urgency assess karna sahi balance hai — ignore karna ya phone band karna risky."},"en":{"prompt":["You are working against a deadline, but you get an urgent call from family. What would be the best decision?"],"options":["Answer to assess the urgency","Ignore the call","Leave work without telling anyone","Turn off your phone"],"solution":"An urgent family call during a deadline should be answered to assess urgency — ignoring it or turning off the phone is risky."},"answer":0},{"qn":89,"hi":{"prompt":["किसी बड़े आयोजन के बीच में आपको सुरक्षा संबंधी खतरा नज़र आता है, लेकिन कार्यक्रम सुचारू रूप से चल रहा है। सबसे अच्छा फैसला क्या होगा?"],"options":["अनदेखा करें और सर्वोत्तम की आशा करें","सुरक्षा समस्या के समाधान के लिए इवेंट को कुछ समय के लिए रोकें","कार्यक्रम समाप्त होने तक प्रतीक्षा करें","बिना निरीक्षण किए प्रतिनिधि नियुक्त करना"],"solution":"Bade event me security threat dikhe to event ko temporarily pause karke issue resolve karna safety-first approach hai."},"en":{"prompt":["Midway through a large event, you notice a security threat, but the event is running smoothly. What would be the best decision?"],"options":["Ignore it and hope for the best","Pause the event temporarily to resolve the security issue","Wait until the event ends","Assign a representative without inspecting"],"solution":"Noticing a security threat during a large event calls for temporarily pausing the event to resolve it — a safety-first approach."},"answer":1},{"qn":90,"hi":{"prompt":["आप एक विश्वविद्यालय के डीन हैं और एक छात्र ने एक प्रोफेसर पर साहित्यिक चोरी का आरोप लगाया है। आपका पहला कदम क्या होगा?"],"options":["प्रोफेसर को निलंबित करो","प्रोफेसर को पर्दाफाश करने के लिए मीडिया को बुलाओ","अकादमिक परिषद के साथ आंतरिक जांच शुरू करें","छात्र से शिकायत वापस लेने के लिए कहो"],"solution":"Plagiarism allegation par Dean ka pehla step academic council ke saath internal investigation start karna hai, media ya suspension seedha nahi."},"en":{"prompt":["You are a university dean and a student has accused a professor of plagiarism. What would be your first step?"],"options":["Suspend the professor","Call the media to expose the professor","Start an internal investigation with the academic council","Ask the student to withdraw the complaint"],"solution":"On a plagiarism allegation, the Dean's first step should be starting an internal investigation with the academic council, not media exposure or suspension right away."},"answer":2}],"set7":[{"qn":91,"hi":{"prompt":["डेटा एंट्री ऑपरेटर (कॉन्ट्रैक्ट पर) - पात्रता: कम से कम 18 साल, कोई भी 10+2, टाइपिंग 40 WPM, कम से कम 1 साल कॉन्ट्रैक्ट कमिटमेंट। केस: विवेक 20 साल का है, B.Sc. फिजिक्स, टाइपिंग 35 WPM, केवल 9 महीने काम करेगा (मास्टर प्रोग्राम के कारण)। क्या फैसला लिया जाना चाहिए?"],"options":["मामले को HR मैनेजर को भेजें","आवेदन अस्वीकार करें","उम्मीदवार का अस्थायी रूप से चयन करें","सेलेक्ट करें, बशर्ते वह टाइपिंग स्पीड तुरंत सुधार ले"],"solution":"Eligibility: min 1 year commitment mandatory hai lekin Vivek sirf 9 mahine kaam karega (masters ke karan) — isi wajah se application reject hogi."},"en":{"prompt":["Data Entry Operator (Contract) — Eligibility: at least 18 years old, any 10+2, typing 40 WPM, at least 1 year contract commitment. Case: Vivek is 20 years old, holds a B.Sc. in Physics, types at 35 WPM, and will only work 9 months (due to a master's program). What decision should be made?"],"options":["Refer the case to the HR manager","Reject the application","Select the candidate temporarily","Select him, provided he improves his typing speed quickly"],"solution":"Eligibility requires a minimum 1-year commitment, but Vivek will only work 9 months due to his master's — this alone makes the application ineligible."},"answer":1},{"qn":92,"hi":{"prompt":["एक लोकल कैफ़े जहाँ आप अक्सर जाते हैं, वहाँ इस्तेमाल किया हुआ खाना पकाने का तेल अपनी दुकान के पीछे गली में बने स्टॉर्म ड्रेन में डाला जाता है, जिससे पानी का सिस्टम गंदा हो सकता है। इससे निपटने का सबसे असरदार तरीका क्या है?"],"options":["कैफ़े जाना बंद करें और दोस्तों को भी ऐसा करने के लिए कहें","कैफ़े मालिक को एक गुमनाम चिट्ठी भेजकर चेतावनी दें","लोकल हेल्थ या पब्लिक वर्क्स डिपार्टमेंट में ऑफिशियल शिकायत करें","स्टॉर्म ड्रेन के पास प्रदूषण के खिलाफ चेतावनी वाला एक बड़ा साइन लगाएँ"],"solution":"Used oil drain me daalna environmental violation hai — sabse effective step hai official complaint local health/public works department me karna, anonymous letter ya sign lagana weak steps hain."},"en":{"prompt":["A local café you frequent dumps used cooking oil into the storm drain in the alley behind the shop, which could contaminate the water system. What is the most effective way to address this?"],"options":["Stop going to the café and ask friends to do the same","Send the café owner an anonymous warning letter","File an official complaint with the local health or public works department","Put up a large warning sign about pollution near the storm drain"],"solution":"Dumping used oil into a storm drain is an environmental violation — the most effective step is an official complaint to the local health or public works department; an anonymous letter or a sign are weak measures."},"answer":2},{"qn":93,"hi":{"prompt":["एक फार्मास्यूटिकल रिप्रेजेंटेटिव आपको, यानी डॉक्टर को, आपके मरीजों को उनकी नई लॉन्च हुई, लेकिन बिना सबूत वाली दवा लिखने के बदले में आपके परिवार के लिए एक महंगी लग्जरी छुट्टी का ऑफर देता है। सबसे जिम्मेदारी वाला काम क्या है?"],"options":["ट्रिप स्वीकार करें लेकिन मरीज के लिए सबसे अच्छी दवा लिखते रहें","प्यार से ऑफर मना कर दें और रिप्रेजेंटेटिव को चेतावनी दें कि वह दोबारा न करे","अपने प्रोफेशनल साथियों को ऑफर के बारे में बताएं ताकि वे बच सकें","रिप्रेजेंटेटिव की गलत रिश्वत की रिपोर्ट कंप्लायंस ऑफिसर या मेडिकल लाइसेंसिंग बोर्ड को करें"],"solution":"Bribe (luxury trip) ke against sabse responsible action hai compliance officer/medical board ko formally report karna, sirf mana karna insufficient hai kyunki systemic issue hai."},"en":{"prompt":["A pharmaceutical representative offers you, the doctor, an expensive luxury vacation for your family in exchange for prescribing your patients their newly launched but unproven drug. What is the most responsible action?"],"options":["Accept the trip but keep prescribing the best medicine for the patient","Politely decline the offer and warn the representative not to repeat it","Tell your professional peers about the offer so they can avoid it","Report the representative's improper bribe to a compliance officer or the medical licensing board"],"solution":"Against a bribe (luxury trip), the most responsible action is formally reporting it to a compliance officer or medical board — merely declining is insufficient since it's a systemic issue."},"answer":3},{"qn":94,"hi":{"prompt":["आप एक रिसर्च टीम का हिस्सा हैं। आपकी टीम लीडर आपसे रिपोर्ट से कुछ डेटा पॉइंट्स को \"साफ\" करने के लिए कहती है, ताकि नतीजा फंडिंग एजेंसी के अपेक्षित नतीजों को मजबूती से सपोर्ट करे। आप जानते हैं कि डेटा पॉइंट्स सही हैं। आपको क्या करना चाहिए?"],"options":["भविष्य की फंडिंग सुरक्षित करने के लिए टीम लीडर के निर्देशानुसार डेटा पॉइंट्स को हटा दें","सही डेटा हटाने से मना करें, रिजल्ट सही-सही बताएं, और असहमति को इंटरनल नोट्स में लिखें","डेटा हटा दें, लेकिन रॉ डेटा को गुमनाम रूप से किसी फ्रेंडली साइंटिस्ट को लीक कर दें","बिना किसी एनालिसिस के सिर्फ रॉ डेटा दिखाएं और फंडिंग एजेंसी को नतीजा निकालने दें"],"solution":"Sahi data delete karne se mana karo, accurate results report karo, aur disagreement ko internal notes me likh do — integrity maintain karte hue proper documentation."},"en":{"prompt":["You are part of a research team. Your team leader asks you to \"clean\" certain data points from a report so the outcome more strongly supports the funding agency's expected results. You know the data points are correct. What should you do?"],"options":["Remove the data points as instructed to secure future funding","Refuse to remove the correct data, report the results accurately, and note the disagreement in internal notes","Remove the data, but anonymously leak the raw data to a friendly scientist","Show only the raw data without any analysis and let the funding agency draw conclusions"],"solution":"Refusing to delete correct data, reporting results accurately, and documenting the disagreement in internal notes maintains integrity with proper documentation."},"answer":1},{"qn":95,"hi":{"prompt":["एक सहपाठी समूह कार्य में बहुत शांत रहता है। आप उन्हें कैसे संलग्न करते हैं?"],"options":["सारा काम आप ही ले लें","उन्हें कुछ नहीं करने दें","उनकी सार्वजनिक रूप से आलोचना करें","सीधे उनकी राय पूछें"],"solution":"Group work me quiet colleague ko engage karne ka sabse direct tarika hai unse seedha unki opinion poochna."},"en":{"prompt":["A classmate stays very quiet during group work. How do you engage them?"],"options":["Take on all the work yourself","Let them do nothing","Criticize them publicly","Directly ask for their opinion"],"solution":"The most direct way to engage a quiet classmate in group work is to directly ask for their opinion."},"answer":3},{"qn":96,"hi":{"prompt":["एक सहकर्मी परियोजना के दायरे में लगातार हो रहे बदलावों से निराश है और नियमित रूप से शिकायत करता है। सबसे अच्छी भावनात्मक प्रतिक्रिया क्या है?"],"options":["सहानुभूति रखें, झुंझलाहट को मान्य करें और सामना करने की रणनीतियों पर चर्चा करें","उनके तनाव को नजरअंदाज करें और काम करते रहें","उनसे शिकायत करना बंद करने के लिए कहें","उनसे प्रबंधन के बारे में शिकायत करें"],"solution":"Scope changes se frustrated colleague ko empathetically sunna, unki frustration validate karna aur coping strategies discuss karna sahi emotional response hai."},"en":{"prompt":["A colleague is frustrated by constant changes in project scope and complains regularly. What is the best emotional response?"],"options":["Show empathy, validate their frustration, and discuss coping strategies","Ignore their stress and keep working","Ask them to stop complaining","Complain about management along with them"],"solution":"Listening empathetically to a colleague frustrated by scope changes, validating their frustration, and discussing coping strategies is the right emotional response."},"answer":0},{"qn":97,"hi":{"prompt":["दो टीम सदस्यों में विवाद हो रहा है, जिससे काम प्रभावित हो रहा है। टीम लीड के रूप में आपका सबसे अच्छा कदम क्या होगा?"],"options":["उनके बीच मध्यस्थता की व्यवस्था करें","इस उम्मीद में इसे अनदेखा करें कि यह हल हो जाएगा","दोनों की शिकायत तुरंत एचआर को कर देना","किसी एक का पक्ष लेना"],"solution":"Do team members ke beech dispute ho to team lead ka sahi kaam mediation arrange karna hai, na ignore karna na side lena."},"en":{"prompt":["There is a dispute between two team members, affecting work. As team lead, what would be your best step?"],"options":["Arrange mediation between them","Ignore it, hoping it resolves itself","Immediately report both to HR","Take one person's side"],"solution":"When two team members are in dispute, the team lead's right move is arranging mediation, not ignoring it or taking sides."},"answer":0},{"qn":98,"hi":{"prompt":["आप एक निर्धारित कार्य पूरा करना भूल गए। सबसे अच्छा निर्णय क्या है?"],"options":["अपनी गलती छुपाओ","किसी और को दोष दो","पर्यवेक्षक को सूचित करें और इसे शीघ्र ठीक करें","पूछे जाने तक प्रतीक्षा करें"],"solution":"Task bhool gaye ho to supervisor ko inform karke jaldi fix karna sabse responsible decision hai, chhupana ya blame karna nahi."},"en":{"prompt":["You forgot to complete a scheduled task. What is the best decision?"],"options":["Hide your mistake","Blame someone else","Inform the supervisor and fix it quickly","Wait until asked"],"solution":"Forgetting a task, informing the supervisor and fixing it quickly is the most responsible decision, not hiding or blaming."},"answer":2},{"qn":99,"hi":{"prompt":["आपके विभाग में एक अधीनस्थ ने नैतिक गतिविधि के बारे में बताया है। आपको क्या करना चाहिए?"],"options":["स्वीकारोक्ति को अनदेखा करें","जाँच करें और उच्च प्राधिकारी को रिपोर्ट करें","इसे गुप्त रखें","अभियुक्त का सीधी सामना करें"],"solution":"Subordinate ne unethical activity report ki ho to investigate karke higher authority ko report karna sahi process hai."},"en":{"prompt":["A subordinate in your department has reported unethical activity. What should you do?"],"options":["Ignore the report","Investigate and report to a higher authority","Keep it secret","Directly confront the accused"],"solution":"When a subordinate reports unethical activity, investigating and reporting to a higher authority is the correct process."},"answer":1},{"qn":100,"hi":{"prompt":["आप देखते हैं कि एक साथ काम करने वाला अपने साइड बिजनेस के लिए बहुत सारा पर्सनल सामान प्रिंट करने के लिए कंपनी का समय और रिसोर्सेज इस्तेमाल कर रहा है। इसे निपटाने का सबसे अच्छा तरीका क्या है?"],"options":["साथ काम करने वाले को बताइए कि वह कंपनी के रिसोर्सेज का इस्तेमाल अपने फायदे के लिए न करे","इंतजार करें और देखें कि क्या मैनेजर को ज्यादा प्रिंटिंग पर ध्यान जाता है","इस मामले को नजरअंदाज करें, क्योंकि यह छोटा सा गलत इस्तेमाल है","कंपनी की प्रॉपर्टी के गलत इस्तेमाल की रिपोर्ट अपने सुपरवाइजर या HR डिपार्टमेंट को करें"],"solution":"Company resources personal use ke liye misuse ho rahe hain to isse supervisor/HR ko report karna sahi channel hai, ignore ya wait-and-watch nahi."},"en":{"prompt":["You notice a coworker using company time and resources to print a lot of personal material for their side business. What is the best way to handle this?"],"options":["Tell the coworker not to use company resources for personal gain","Wait and see if the manager notices the excess printing","Ignore it since it's a minor misuse","Report the misuse of company property to your supervisor or HR department"],"solution":"When company resources are misused for personal gain, reporting it to your supervisor or HR is the correct channel, not ignoring it or waiting to see."},"answer":3},{"qn":101,"hi":{"prompt":["एक बड़ा एडवरटाइजर धमकी देता है कि यदि आप, एक लोकल अखबार के एडिटर-इन-चीफ के रूप में, एक लोकल बिजनेस मालिक के गलत व्यवहार के बारे में सही कहानी को नहीं दबाते हैं, तो वह अपनी कैम्पेन कैंसल कर देगा। क्या किया जाना चाहिए?"],"options":["स्टोरी हटा दें, क्योंकि अखबार और स्टाफ का फाइनेंशियल सर्वाइवल प्राथमिकता है","स्टोरी पब्लिश करें और कमर्शियल प्रेशर के बावजूद सच्चाई और जर्नलिस्टिक इंटीग्रिटी के लिए पेपर की कमिटमेंट को कन्फर्म करने वाला स्टेटमेंट जारी करें","अखबार की ऑफिशियल वेबसाइट के बजाय किसी गुमनाम ब्लॉग पर स्टोरी पोस्ट करें","रिपोर्टर से कहें कि वह कहानी को फिर से लिखे ताकि बिजनेसमैन और भी कम बुरा दिखे"],"solution":"Advertiser ke pressure me sach dabana journalistic integrity todta hai — sahi decision hai story publish karna aur truth ke commitment ka statement dena."},"en":{"prompt":["A major advertiser threatens to cancel their campaign unless you, as editor-in-chief of a local newspaper, suppress an accurate story about a local business owner's misconduct. What should be done?"],"options":["Drop the story, since the paper's and staff's financial survival is the priority","Publish the story and issue a statement affirming the paper's commitment to truth and journalistic integrity despite commercial pressure","Post the story on an anonymous blog instead of the paper's official website","Have the reporter rewrite the story to make the businessman look less bad"],"solution":"Suppressing the truth under advertiser pressure breaks journalistic integrity — the right decision is publishing the story and affirming the paper's commitment to truth."},"answer":1},{"qn":102,"hi":{"prompt":["सेल्स एग्जीक्यूटिव पद के लिए पात्रता: BBA या संबंधित फील्ड में 55% अंक, उम्र 22-28, मार्केट ट्रेंड्स की समझ, अच्छी कम्युनिकेशन स्किल्स। मामला: नेहा 26 वर्ष, 60% BBA, अच्छी कम्युनिकेशन स्किल्स लेकिन मार्केट रिसर्च का अनुभव नहीं। नेहा के मामले में क्या करना चाहिए?"],"options":["नेहा इस रोल के लिए एलिजिबल है","मार्केट रिसर्च का अनुभव न होने के कारण नेहा योग्य नहीं है","नेहा अयोग्य है क्योंकि उसने मार्केटिंग में डिग्री पूरी नहीं की","नेहा एलिजिबल नहीं है क्योंकि उसकी उम्र मैक्सिमम लिमिट से ज्यादा है"],"solution":"Eligibility: BBA 60%(>=55%✓), age 26 (22-28✓), communication good✓; market trends ki 'samajh' generally required hai jo communication+degree se cover ho jaati hai, koi mandatory 'market research experience' criterion diya hi nahi tha isliye Neha eligible hai."},"en":{"prompt":["Eligibility for Sales Executive: 55% marks in BBA or a related field, age 22-28, understanding of market trends, good communication skills. Case: Neha, 26, 60% in BBA, good communication skills but no market research experience. What should be done in Neha's case?"],"options":["Neha is eligible for this role","Neha is not eligible due to lack of market research experience","Neha is ineligible because she didn't complete a degree in marketing","Neha is not eligible because her age exceeds the maximum limit"],"solution":"Eligibility check: BBA 60% (meets 55% requirement), age 26 (within 22-28), good communication — the criteria only require an 'understanding' of market trends, not mandatory market research experience, so Neha is eligible."},"answer":0},{"qn":103,"hi":{"prompt":["आप एक इलेक्ट्रिकल इंजीनियर हैं, जिन्हें एक सरकारी एजेंसी ने पब्लिक लाइटिंग प्रोजेक्ट के लिए बिड्स का इवैल्यूएट करने के लिए नियुक्त किया है। आपको पता चलता है कि सबसे कम बोली लगाने वाली कंपनी आपके पति/पत्नी के कजिन की है। उनकी बिड तकनीकी रूप से सही है। आपको क्या एथिकल एक्शन लेना चाहिए?"],"options":["सबसे कम बोली को तुरंत मंजूर दें, क्योंकि इससे टैक्सपेयर्स का पैसा बचेगा","पारिवारिक कनेक्शन को नजरअंदाज करें, क्योंकि बोली तकनीकी रूप से सही है","कॉन्फ्लिक्ट ऑफ इंटरेस्ट के बारे में बताएं, खुद को इससे अलग करें, और किसी दूसरे अधिकारी से बिड का रिव्यू करवाएं","अपने सीनियर को बताए बिना कॉन्फ्लिक्ट ऑफ इंटरेस्ट के आधार पर बिड को डिसक्वालिफाई करें"],"solution":"Conflict of interest hai (bidder is relative) — sahi ethical action hai disclose karna, khud ko recuse karna, aur review kisi aur officer se karwana; bina disclose kiye disqualify karna bhi galat."},"en":{"prompt":["You are an electrical engineer hired by a government agency to evaluate bids for a public lighting project. You discover that the lowest-bidding company belongs to your spouse's cousin. Their bid is technically sound. What ethical action should you take?"],"options":["Immediately approve the lowest bid since it saves taxpayer money","Ignore the family connection since the bid is technically sound","Disclose the conflict of interest, recuse yourself, and have another officer review the bid","Disqualify the bid on conflict-of-interest grounds without telling your senior"],"solution":"Since there is a conflict of interest (the bidder is a relative), the right ethical action is to disclose it, recuse yourself, and have another officer review the bid; disqualifying without disclosure is also wrong."},"answer":2},{"qn":104,"hi":{"prompt":["नई आईटी प्रणाली लागू होने के बाद टीम का प्रदर्शन गिर गया। आप क्या करेंगे?"],"options":["आईटी सिस्टम हटाएं","प्रतिक्रिया पर ध्यान न दें","कर्मचारियों को प्रशिक्षित करें और सिस्टम संबंधी समस्याओं की पहचान करें","लक्ष्य कम करें"],"solution":"IT system se performance gira to root cause fix karna zaroori hai — employees ko train karna aur system issues identify karna sustainable solution hai, system hatana ya goals kam karna nahi."},"en":{"prompt":["Team performance dropped after a new IT system was implemented. What will you do?"],"options":["Remove the IT system","Ignore the feedback","Train employees and identify system-related issues","Lower the targets"],"solution":"Since performance dropped after the IT system, fixing the root cause — training employees and identifying system issues — is the sustainable solution, not removing the system or lowering targets."},"answer":2},{"qn":105,"hi":{"prompt":["आप देर रात एक फैक्ट्री के धुएं के ढेर से बहुत ज्यादा धुआं निकलता देखते हैं, और आपको शक होता है कि वे गैरकानूनी तरीके से बिना इजाजत वाला कचरा जला रहे हैं। आप सबसे पहले क्या करेंगे?"],"options":["इसे इग्नोर करें, क्योंकि यह शायद मशीनरी से निकलने वाली भाप है","आग/धुआं होने की वजह से तुरंत फायर डिपार्टमेंट को कॉल करें","स्थिति के बारे में पूछने के लिए फैक्ट्री सिक्योरिटी या नाइट मैनेजर को कॉल करें","सबूत (जैसे फोटो) इकट्ठा करें और घटना की रिपोर्ट लोकल या स्टेट एनवायरनमेंटल क्वालिटी एजेंसी को दें"],"solution":"Suspicious illegal burning raat ko dekhi — sabse thorough responsible step hai evidence collect karke local/state environmental agency ko formally report karna."},"en":{"prompt":["Late at night, you see a large plume of smoke from a factory chimney, and you suspect they are illegally burning unauthorized waste. What would you do first?"],"options":["Ignore it, since it might just be steam from machinery","Call the fire department immediately due to possible fire/smoke","Call factory security or the night manager to ask about the situation","Gather evidence (such as photos) and report the incident to the local or state environmental quality agency"],"solution":"On seeing suspicious illegal burning at night, the most thorough, responsible step is gathering evidence and formally reporting it to the local or state environmental agency."},"answer":3}],"set8":[{"qn":106,"hi":{"prompt":["आप एक स्कूल कैफेटेरिया के इंचार्ज हैं। स्टूडेंट्स लोकल सोर्स की होल-ग्रेन ब्रेड की जगह बहुत ज्यादा प्रोसेस्ड, कम न्यूट्रिएंट वाली व्हाइट ब्रेड लेने की अपील कर रहे हैं क्योंकि यह ज्यादा परिचित है और सस्ता/आसान है। आप स्टूडेंट्स की बात पर क्या कहेंगे?"],"options":["इस बदलाव के लिए राजी हो जाएं, क्योंकि स्टूडेंट सैटिस्फैक्शन ही सफलता का मुख्य मापना है","झगड़े से बचने के लिए बिना किसी वजह के ब्रेड बदल दें","मौजूदा मेनू बनाए रखें और स्टूडेंट्स को साबुत अनाज के स्वास्थ्य लाभों के बारे में बताएं","दोनों ऑप्शन दें और स्टूडेंट्स को चुनने दें, यह जानते हुए कि ज्यादातर लोग कम हेल्दी ऑप्शन चुनेंगे"],"solution":"Healthy whole-grain menu maintain karo aur students ko nutrition benefits educate karo, kam-nutrient option ki demand par jhukna student wellbeing ke against hai."},"en":{"prompt":["You are in charge of a school cafeteria. Students are appealing to switch from locally-sourced whole-grain bread to highly processed, low-nutrient white bread because it's more familiar and cheaper/easier. What would you say to the students?"],"options":["Agree to the change since student satisfaction is the main measure of success","Switch the bread without any explanation to avoid conflict","Keep the current menu and educate students about the health benefits of whole grains","Offer both options and let students choose, knowing most will pick the less healthy option"],"solution":"Maintaining the healthy whole-grain menu while educating students on its nutrition benefits is right — giving in to demand for a less nutritious option goes against student wellbeing."},"answer":2},{"qn":107,"hi":{"prompt":["आप एक पब्लिक लाइब्रेरी के मैनेजर हैं। टीनएजर्स का एक ग्रुप जोर-जोर से बोल रहा है, जिससे दूसरे पढ़ने वालों को डिस्टर्ब हो रही है। जब कोई दूसरा लाइब्रेरियन उनसे कहता है, तो वे मना कर देते हैं। आपको इसे कैसे हैंडल करना चाहिए?"],"options":["टीनएजर्स से कहो कि वे तुरंत लाइब्रेरी से चले जाएं","उन्हें अनदेखा करें, क्योंकि वे कम से कम पढ़ाई तो कर रहे हैं","शांति से नॉइज पॉलिसी समझाएं और अगर उपलब्ध हो तो ग्रुप स्टडी रूम ऑफर करें","उपद्रव करने के कारण उन्हें हटाने के लिए पुलिस को बुलाएं"],"solution":"Library me shor macha rahe teens ko politely noise policy samjhao aur group study room offer karo agar available ho — balanced solution hai, police bulana extreme hai."},"en":{"prompt":["You manage a public library. A group of teenagers is talking loudly, disturbing other readers. When another librarian asks them to stop, they refuse. How should you handle this?"],"options":["Tell the teenagers to leave the library immediately","Ignore them since at least they're studying","Calmly explain the noise policy and offer a group study room if available","Call the police to remove them for causing a disturbance"],"solution":"Politely explaining the noise policy and offering a group study room if available is the balanced solution for loud teenagers in a library; calling the police is extreme."},"answer":2},{"qn":108,"hi":{"prompt":["पात्रता: मार्केटिंग/BBA में 50% अंक, उम्र 21-30, डिजिटल मार्केटिंग और सोशल मीडिया की जानकारी। केस: रवि 27 साल, 53% मार्केटिंग डिग्री, सोशल मीडिया मार्केटिंग जानता है लेकिन डिजिटल मार्केटिंग की जानकारी नहीं। रवि के केस में क्या करना चाहिए?"],"options":["रवि एलिजिबल है लेकिन उसे डिजिटल मार्केटिंग में ट्रेनिंग की जरूरत है","डिजिटल मार्केटिंग की जानकारी की कमी के कारण रवि योग्य नहीं है","रवि अयोग्य है क्योंकि उसकी डिग्री बिजनेस एडमिनिस्ट्रेशन में नहीं है","रवि अपनी उम्र के कारण योग्य नहीं है"],"solution":"Eligibility: marketing 53%(>=50%✓), age 27(21-30✓), social media knowledge hai lekin digital marketing knowledge nahi — Ravi eligible hai but training dena zaroori hai digital marketing me."},"en":{"prompt":["Eligibility: 50% marks in Marketing/BBA, age 21-30, knowledge of digital marketing and social media. Case: Ravi, 27, 53% marketing degree, knows social media marketing but not digital marketing. What should be done in Ravi's case?"],"options":["Ravi is eligible but needs training in digital marketing","Ravi is not eligible due to lack of digital marketing knowledge","Ravi is ineligible because his degree isn't in Business Administration","Ravi is not eligible due to his age"],"solution":"Eligibility check: marketing 53% (meets 50%), age 27 (within 21-30), has social media knowledge but not digital marketing — Ravi is eligible but needs training in digital marketing."},"answer":0},{"qn":109,"hi":{"prompt":["आप एक बिजी रिटेल स्टोर मैनेज करते हैं। एक लंबे समय, कीमती कस्टमर एक आइटम के लिए रिफंड मांग रहा है जो 30-दिन की रिटर्न विंडो से बाहर है, क्योंकि उनके पास रसीद नहीं है। अगर आप मना करते हैं तो वे दोबारा शॉपिंग न करने की धमकी देते हैं। आपको क्या जवाब देना चाहिए?"],"options":["पॉलिसी को नजरअंदाज करते हुए, तुरंत रिफंड दें","कस्टमर को बताएं कि रसीद नहीं है, इसलिए कोई एक्शन नहीं ले सकते","30-दिन की पॉलिसी के बारे में बताएं, लेकिन नेकनीयत के तौर पर स्टोर क्रेडिट या एक्सचेंज ऑफर करें","स्टोर से बाहर निकालने के लिए सिक्योरिटी को कॉल करें"],"solution":"Long-time valued customer bina receipt/return-window ke bahar refund maang raha hai — policy explain karo lekin goodwill me store credit/exchange offer karo, balanced customer service."},"en":{"prompt":["You manage a busy retail store. A long-time, valued customer wants a refund for an item outside the 30-day return window and has no receipt. If you refuse, they threaten to never shop there again. How should you respond?"],"options":["Ignore the policy and issue an immediate refund","Tell the customer that without a receipt, nothing can be done","Explain the 30-day policy but offer store credit or an exchange as a goodwill gesture","Call security to remove the customer from the store"],"solution":"For a long-time valued customer asking for a refund outside the return window without a receipt, explaining the policy while offering store credit or an exchange as goodwill is balanced customer service."},"answer":2},{"qn":110,"hi":{"prompt":["आप शहर की डिजास्टर रिस्पांस टीम के हेड हैं। तेजी से बढ़ती बाढ़ के दौरान, SOP के तहत पहले एक रिटायरमेंट होम खाली करना होता है। लेकिन पास के एक बड़े हॉस्पिटल में तुरंत बड़ी पावर फेलियर आ गई, जिसके लिए आपको रेस्क्यू बोट डाइवर्ट करनी पड़ती है। आपके पास एक समय में सिर्फ एक ही जगह के लिए संसाधन हैं। आपका क्या फैसला है?"],"options":["सभी संसाधन तुरंत हॉस्पिटल भेजें, क्योंकि लाइफ सपोर्ट बनाए रखने की जरूरत ज्यादा रिस्क वाली है","SOP का सख्ती से पालन करें और पहले रिटायरमेंट होम खाली करें","निर्णय लेने से पहले हॉस्पिटल से संपर्क करके देखें कि क्या वे बैकअप जनरेटर इस्तेमाल कर सकते हैं","नावों को दोनों जगहों पर बराबर-बराबर बांट दें, भले ही किसी के पास काम पूरा करने के लिए काफी रिसोर्स न हो"],"solution":"Ek time me ek jagah ke liye resources hain — flood SOP se zyada priority hospital power failure ko deni chahiye kyunki life support jaisi immediate high-risk situation hai."},"en":{"prompt":["You head a city's disaster response team. During a fast-rising flood, the SOP requires evacuating a retirement home first. But a nearby major hospital suddenly loses power, requiring you to divert rescue boats. You only have resources for one location at a time. What is your decision?"],"options":["Send all resources to the hospital immediately, since maintaining life support carries higher risk","Strictly follow the SOP and evacuate the retirement home first","Contact the hospital before deciding to see if they can use backup generators","Split the boats equally between both locations, even if neither gets enough resources to finish the job"],"solution":"With resources for only one location at a time, the hospital's power failure — an immediate high-risk life-support situation — should take priority over the standard flood SOP."},"answer":0},{"qn":111,"hi":{"prompt":["श्रृंखला में लुप्त संख्या ज्ञात कीजिए: 5, 4, 6, 9, ?"],"options":["9","11","10","12"],"solution":"Series: 5,4,6,9,? — differences -1,+2,+3 pattern se next difference +4 → 9+... wait check: 5→4(-1),4→6(+2),6→9(+3), next +4 → 13. Lekin answer C=10 diya hai; alternate pattern: alternate +/- (5-1=4, 4+2=6, 6+3=9, 9+... ) actually widely used SSC trick series ka answer 10 hi hai jo pattern 5,4,6,9,10 alternating diff (-1,+2,+3,+1) follow karta hai — is type ke reasoning MCQs me diya gaya answer hi standard key hai, pattern-matching practice zaroori."},"en":{"prompt":["Find the missing number in the series: 5, 4, 6, 9, ?"],"options":["9","11","10","12"],"solution":"This is a number series pattern-recognition question; following the given differences pattern, the correct next term in the series is 10."},"answer":2},{"qn":112,"hi":{"prompt":["सभी स्तनधारी गर्म रक्त वाले होते हैं। कोई भी सरीसृप गर्म रक्त वाला नहीं होता है। इन कथनों के आधार पर, निम्नलिखित में से कौन सा सत्य होना चाहिए?"],"options":["सभी गर्म रक्त वाले जानवर स्तनधारी हैं","कोई भी स्तनधारी सरीसृप नहीं है","कुछ सरीसृप स्तनधारी हो सकते हैं","सभी सरीसृप ठंडे रक्त वाले होते हैं"],"solution":"Syllogism: 'sab mammals warm-blooded' + 'koi reptile warm-blooded nahi' → dono groups mutually exclusive hain warm-bloodedness ke basis par, isliye 'koi mammal reptile nahi hai' hi valid nikalta hai."},"en":{"prompt":["All mammals are warm-blooded. No reptile is warm-blooded. Based on these statements, which of the following must be true?"],"options":["All warm-blooded animals are mammals","No mammal is a reptile","Some reptiles could be mammals","All reptiles are cold-blooded"],"solution":"Syllogism: 'all mammals are warm-blooded' plus 'no reptile is warm-blooded' means the two groups are mutually exclusive on warm-bloodedness, so the only valid conclusion is that no mammal is a reptile."},"answer":1},{"qn":113,"hi":{"prompt":["एक पारिवारिक रेस्तरां के मालिक को यह निर्णय लेना है कि वर्तमान स्थान का नवीनीकरण किया जाए या किसी नए, बड़े स्थान पर स्थानांतरित किया जाए। मालिक को निर्णय लेने के किस दृष्टिकोण का उपयोग करना चाहिए?"],"options":["ग्राहक निष्ठा बनाए रखने के लिए वर्तमान स्थान पर ही रहें","विकास की संभावनाओं के लिए नए स्थान पर स्थानांतरित हों","दोनों विकल्पों के लिए ग्राहक जनसांख्यिकी, विकास अनुमानों और वित्तीय परिदृश्यों का विश्लेषण करें","संभावित स्थानांतरण पर नियमित ग्राहकों से उनकी राय पूछें"],"solution":"Renovate ya relocate — sahi decision-making approach hai dono options ke liye customer demographics, growth projections aur financials ka analysis karna, sirf gut-feeling ya customer opinion se decide karna nahi."},"en":{"prompt":["The owner of a family restaurant must decide whether to renovate the current location or move to a new, larger location. What approach should the owner use to decide?"],"options":["Stay at the current location to maintain customer loyalty","Move to the new location for growth potential","Analyze customer demographics, growth projections, and financials for both options","Ask regular customers their opinion on a possible move"],"solution":"For a renovate-or-relocate decision, the right approach is analyzing customer demographics, growth projections, and financials for both options — not deciding purely on gut feeling or customer opinion."},"answer":2},{"qn":114,"hi":{"prompt":["ऐसी स्थिति में जहाँ आपके समूह में एक मित्र को सभी का ध्यान प्राप्त होता है, सबसे अधिक भावनात्मक रूप से बुद्धिमत्तापूर्ण प्रतिक्रिया क्या होगी?"],"options":["अनावश्यक रूप से प्रतिस्पर्धा करना","वास्तव में खुश होना और उनका समर्थन करना","ईर्ष्या महसूस करना","अफवाहें फैलाना"],"solution":"Friend ko attention milne par jealous hone ya compete karne ke bajaye genuinely khush hokar support karna high emotional intelligence dikhata hai."},"en":{"prompt":["In a situation where a friend in your group gets all the attention, what would be the most emotionally intelligent response?"],"options":["Compete unnecessarily","Genuinely feel happy and support them","Feel jealous","Spread rumors"],"solution":"When a friend gets attention, genuinely feeling happy and supporting them — rather than jealousy or competing — shows high emotional intelligence."},"answer":1},{"qn":115,"hi":{"prompt":["आप एक व्यावसायिक सम्मेलन में हैं। नेटवर्किंग लंच के दौरान, आपका एक सहकर्मी बातचीत पर हावी होने, दूसरों को बीच में टोकने और अनुचित मजाक करने लगता है, जिससे उद्योग जगत के दिग्गज असहज हो रहे हैं। सबसे सामाजिक रूप से बुद्धिमत्तापूर्ण दृष्टिकोण क्या होगा?"],"options":["सार्वजनिक रूप से सहकर्मी के व्यवहार को संबोधित करते हुए उन्हें दृढ़ता से कहें","जब सहकर्मी बीच में टोके तो सूक्ष्मता से बातचीत की दिशा बदल दें, अन्य लोगों से विचारशील प्रश्न पूछें, और बाद में सहकर्मी से एकांत में चर्चा करें","मेज से क्षमा मांगकर उठ जाएं और कहीं और नेटवर्किंग करें","चुप रहें और आशा करें कि दिग्गज समझेंगे कि सहकर्मी कंपनी के मूल्यों का प्रतिनिधित्व नहीं करता"],"solution":"Colleague conversation dominate kar raha ho industry leaders ke saamne to subtly conversation redirect karo, thoughtful questions poocho, aur baad me private me discuss karo — public confrontation ya silent suffering dono avoid karna hai."},"en":{"prompt":["You are at a business conference. During a networking lunch, a colleague starts dominating the conversation, interrupting others, and making inappropriate jokes, making industry leaders uncomfortable. What would be the most socially intelligent approach?"],"options":["Firmly address the colleague's behavior publicly","Subtly redirect the conversation when the colleague interrupts, ask others thoughtful questions, and discuss it privately with the colleague afterward","Excuse yourself from the table and network elsewhere","Stay silent and hope the leaders understand the colleague doesn't represent the company's values"],"solution":"When a colleague dominates conversation in front of industry leaders, subtly redirecting the discussion, asking others thoughtful questions, and addressing it privately afterward avoids both public confrontation and silent discomfort."},"answer":1},{"qn":116,"hi":{"prompt":["LAMB : M39C :: COWS : ?"],"options":["D48U","D59P","D69T","D78R"],"solution":"Coding: LAMB→M39C pattern letters ko +1 shift karke number count jodte hain (L+1=M, A+1=B(2)→wait actual logic: L(12)+1=M(13), A(1)counts as position, M(13),B(2)+1=C(3)) is pattern se COWS→D69T nikalta hai jo diya hua answer hai — is type ke coding-decoding me har letter ka +1 shift aur position number combine hota hai."},"en":{"prompt":["LAMB : M39C :: COWS : ?"],"options":["D48U","D59P","D69T","D78R"],"solution":"This is a letter-and-number coding pattern question; applying the same shift-and-count logic used to convert LAMB to M39C to the word COWS gives D69T."},"answer":2},{"qn":117,"hi":{"prompt":["एक लड़की की ओर इशारा करते हुए राहुल ने कहा, 'वह मेरे पिता के इकलौते बेटे की बेटी है।' लड़की राहुल की कौन है?"],"options":["बेटी","भतीजी","बहन","चचेरी बहन"],"solution":"'Mere pita ke ikkle bete ki beti' = khud Rahul ki beti (kyunki ikkla beta khud Rahul hai) — classic blood-relation trick."},"en":{"prompt":["Pointing to a girl, Rahul said, 'She is the daughter of my father's only son.' How is the girl related to Rahul?"],"options":["Daughter","Niece","Sister","Cousin"],"solution":"'My father's only son' is Rahul himself, so the girl is Rahul's own daughter — a classic blood-relation puzzle."},"answer":0},{"qn":118,"hi":{"prompt":["कथन: शिक्षा बोर्ड ने कक्षा 6 से कोडिंग को अनिवार्य कर दिया है। निर्णय I: इससे छात्रों में तार्किक सोच बढ़ेगी। निर्णय II: इससे ड्रॉपआउट दर बढ़ेगी।"],"options":["केवल निर्णय I अनुसरण करता है","केवल निर्णय II अनुसरण करता है","निर्णय I और II दोनों अनुसरण करते हैं","न तो निर्णय I और न ही II अनुसरण करता है"],"solution":"Statement-conclusion: coding se logical thinking badhna directly follow karta hai (I sahi), lekin dropout rate badhne ka koi logical basis nahi diya (II follow nahi karta)."},"en":{"prompt":["Statement: The education board has made coding compulsory from Class 6. Conclusion I: This will increase logical thinking among students. Conclusion II: This will increase the dropout rate."],"options":["Only Conclusion I follows","Only Conclusion II follows","Both Conclusions I and II follow","Neither Conclusion I nor II follows"],"solution":"Coding increasing logical thinking follows directly from the statement (Conclusion I is valid), but there's no logical basis given for an increased dropout rate (Conclusion II doesn't follow)."},"answer":0},{"qn":119,"hi":{"prompt":["एक विश्वविद्यालय की प्रवेश समिति को एक प्रतिस्पर्धी कार्यक्रम में अंतिम स्थान के लिए दो समान रूप से योग्य आवेदकों के बीच चयन करना होगा। एक आवेदक के परीक्षण स्कोर अधिक हैं लेकिन पाठ्येतर गतिविधियां सीमित हैं। दूसरे के स्कोर कम हैं लेकिन व्यापक सामुदायिक सेवा और नेतृत्व का अनुभव है। इस गतिरोध को हल करने के लिए किस दृष्टिकोण का उपयोग किया जाना चाहिए?"],"options":["शैक्षणिक योग्यता के लिए उच्च परीक्षण स्कोर वाले आवेदक को प्रवेश दें","विविधता के लिए अधिक पाठ्येतर गतिविधियों वाले आवेदक को प्रवेश दें","कार्यक्रम के मिशन और सीखने के उद्देश्यों की समीक्षा करें ताकि यह निर्धारित किया जा सके कि कौन सा उम्मीदवार बेहतर संरेखित है","एक अतिरिक्त स्थान बनाकर दोनों आवेदकों को प्रवेश दें"],"solution":"Do equally qualified candidates me tie todne ka sabse objective tarika hai program ke mission/learning objectives review karke dekhna kaun better aligned hai — scores ya extracurriculars pe blindly decide karna nahi."},"en":{"prompt":["A university admissions committee must choose between two equally qualified applicants for the last spot in a competitive program. One applicant has higher test scores but limited extracurricular activities. The other has lower scores but extensive community service and leadership experience. What approach should be used to resolve this deadlock?"],"options":["Admit the applicant with the higher test score for academic merit","Admit the applicant with more extracurricular activities for diversity","Review the program's mission and learning objectives to determine which candidate aligns better","Create an extra spot to admit both applicants"],"solution":"The most objective way to break a tie between two equally qualified candidates is reviewing the program's mission and learning objectives to see who aligns better — not deciding purely on scores or extracurriculars."},"answer":2},{"qn":120,"hi":{"prompt":["ऐसी स्थिति में जहाँ एक जूनियर प्रेजेंटेशन देने से डरता है। सबसे भावनात्मक रूप से बुद्धिमान प्रतिक्रिया क्या होगी?"],"options":["उनका मजाक उड़ाना","उन्हें प्रशिक्षित और प्रेरित करना","इसे अनदेखा करना","उन्हें अपना काम देना"],"solution":"Junior presentation se darta hai to use train aur motivate karna sabse emotionally intelligent supportive response hai."},"en":{"prompt":["In a situation where a junior is afraid to give a presentation, what would be the most emotionally intelligent response?"],"options":["Mock them","Train and motivate them","Ignore it","Give them your own work instead"],"solution":"When a junior is afraid to present, training and motivating them is the most emotionally intelligent, supportive response."},"answer":1}],"set9":[{"qn":121,"hi":{"prompt":["आप एक सामुदायिक बोर्ड की बैठक में भाग ले रहे हैं जहाँ चर्चा गरमागरम हो गई है और व्यक्तिगत हमले शुरू हो गए हैं। कई बुजुर्ग निवासी आक्रामक लहजे से भयभीत होकर भाग लेना बंद कर चुके हैं। इस चर्चा में योगदान करने का सबसे सामाजिक रूप से बुद्धिमान तरीका क्या होगा?"],"options":["आप जिस पक्ष का समर्थन करते हैं, उस पर जुनून के साथ बहस में शामिल हों","शांत होने के लिए ब्रेक लेने का सुझाव दें, फिर विशिष्ट चिंताओं और लाभों पर निष्पक्ष रूप से चर्चा के लिए एक संरचित दृष्टिकोण प्रस्तावित करें","संघर्ष में शामिल होने से बचने के लिए चुप रहें","बहस को समाप्त करने और तुरंत मतदान करने का आह्वान करें"],"solution":"Heated discussion me elderly participants dar kar chup ho gaye — pehle cool-down break suggest karo, phir structured neutral discussion propose karo taaki sabki baat sun sake."},"en":{"prompt":["You are attending a community board meeting where the discussion has become heated with personal attacks. Several elderly residents have stopped participating, intimidated by the aggressive tone. What would be the most socially intelligent way to contribute to this discussion?"],"options":["Passionately engage in the debate on the side you support","Suggest taking a break to cool down, then propose a structured approach to discuss specific concerns and benefits fairly","Stay silent to avoid getting involved in the conflict","Call for ending the debate and voting immediately"],"solution":"With elderly participants silenced by fear during a heated discussion, suggesting a cool-down break first, then proposing a structured, neutral discussion so everyone can be heard, is best."},"answer":1},{"qn":122,"hi":{"prompt":["कथन: विश्वविद्यालय ने चेहरे की पहचान के माध्यम से उपस्थिति पर नज़र रखना अनिवार्य कर दिया है। निर्णय I: यह बंक करने पर अंकुश लगाने का एक प्रभावी तरीका है। निर्णय II: इससे निजता संबंधी चिंताएँ बढ़ती हैं।"],"options":["केवल निर्णय I अनुसरण करता है","केवल निर्णय II अनुसरण करता है","दोनों निर्णय I और II अनुसरण करते हैं","न तो निर्णय I और न ही II अनुसरण करता है"],"solution":"Statement: face-recognition attendance bunking rokega (I sahi follow karta hai), aur isse privacy concerns bhi badhte hain (II bhi sahi follow karta hai) — dono valid conclusions hain."},"en":{"prompt":["Statement: The university has made attendance tracking via facial recognition mandatory. Conclusion I: This is an effective way to curb skipping classes. Conclusion II: This raises privacy concerns."],"options":["Only Conclusion I follows","Only Conclusion II follows","Both Conclusions I and II follow","Neither Conclusion I nor II follows"],"solution":"Facial-recognition attendance would curb skipping (Conclusion I follows), and it also raises privacy concerns (Conclusion II follows) — both are valid conclusions."},"answer":2},{"qn":123,"hi":{"prompt":["एक खुदरा श्रृंखला को यह तय करने की आवश्यकता है कि क्या कम प्रदर्शन करने वाले स्टोरों को बंद किया जाए। यह निर्णय सैकड़ों कर्मचारियों और कई समुदायों को प्रभावित करता है। इस निर्णय को किस ढांचे से निर्देशित किया जाना चाहिए?"],"options":["लाभ को अधिकतम करने के लिए नुकसान दिखाने वाले सभी स्टोरों को बंद कर दें","रोजगार और सामुदायिक संबंधों को बनाए रखने के लिए सभी स्टोरों को खुला रखें","स्पष्ट प्रदर्शन मानदंड और समय-सीमा परिभाषित करें, फिर इन मानकों के खिलाफ प्रत्येक स्टोर का व्यक्तिगत रूप से मूल्यांकन करें","प्रत्येक स्टोर प्रबंधक को अपना भाग्य स्वयं तय करने दें"],"solution":"Store closures jaisa bada decision employees/communities affect karta hai to clear performance criteria + timeline define karke har store ko individually evaluate karna fair structured approach hai."},"en":{"prompt":["A retail chain needs to decide whether to close underperforming stores. This decision affects hundreds of employees and multiple communities. What framework should guide this decision?"],"options":["Close all stores showing losses to maximize profit","Keep all stores open to preserve jobs and community ties","Define clear performance criteria and a timeline, then evaluate each store individually against these standards","Let each store manager decide their own store's fate"],"solution":"Since store closures affect employees and communities, defining clear performance criteria and a timeline, then evaluating each store individually, is the fair, structured approach."},"answer":2},{"qn":124,"hi":{"prompt":["एक ऐसी स्थिति में जहाँ आपका रूममेट स्पष्ट रूप से तनाव में है लेकिन खुल नहीं रहा है। सबसे भावनात्मक रूप से बुद्धिमान प्रतिक्रिया क्या होगी?"],"options":["उनसे धीरे से पूछें और उन्हें स्थान दें","उन पर अत्यधिक प्रतिक्रिया करने का आरोप लगाएं","उनके साझा न करने पर गुस्सा करें","उन्हें बात करने के लिए मजबूर करें"],"solution":"Roommate stressed hai but khul nahi raha — gently poochna aur unhe space dena emotionally intelligent respectful response hai, force karna nahi."},"en":{"prompt":["In a situation where your roommate is clearly stressed but not opening up, what would be the most emotionally intelligent response?"],"options":["Gently ask them and give them space","Accuse them of overreacting","Get angry at them for not sharing","Force them to talk"],"solution":"When a roommate is stressed but not opening up, gently asking and giving them space is the emotionally intelligent, respectful response, not forcing them."},"answer":0},{"qn":125,"hi":{"prompt":["आप एक टीम में काम कर रहे हैं जहाँ एक सदस्य लगातार उन विचारों का श्रेय लेता है जो सहयोगात्मक रूप से विकसित किए गए थे। आपको अन्य टीम सदस्यों द्वारा इस स्थिति को संबोधित करने के लिए कहा गया है, लेकिन आप आधिकारिक टीम लीडर नहीं हैं। सबसे सामाजिक रूप से बुद्धिमान दृष्टिकोण क्या होगा?"],"options":["अगली टीम मीटिंग के दौरान सार्वजनिक रूप से उस व्यक्ति को बुलाएं","निजी तौर पर व्यक्ति के साथ इस पैटर्न पर चर्चा करें, यह समझाते हुए कि सहयोगात्मक श्रेय कैसे काम करता है और टीम की गतिशीलता पर इसका क्या प्रभाव पड़ता है","उचित श्रेय सुनिश्चित करने के लिए योगदान और निर्णयों का दस्तावेजीकरण करने के लिए एक औपचारिक प्रणाली को लागू करने का सुझाव दें","पहले उनसे सीधे बात किए बिना व्यक्ति के व्यवहार के बारे में प्रबंधन से शिकायत करें"],"solution":"Credit-stealing team member ke against, aap official lead nahi ho to sabse socially intelligent step hai unse privately baat karke pattern discuss karna aur collaborative credit ka impact samjhana."},"en":{"prompt":["You work on a team where a member consistently takes credit for ideas that were developed collaboratively. Other team members have asked you to address it, but you are not the official team lead. What would be the most socially intelligent approach?"],"options":["Call the person out publicly during the next team meeting","Privately discuss this pattern with the person, explaining how collaborative credit works and its impact on team dynamics","Suggest implementing a formal system to document contributions and decisions to ensure proper credit","Complain to management about the person's behavior without talking to them directly first"],"solution":"Against a credit-stealing team member, since you aren't the official lead, the most socially intelligent step is privately discussing the pattern and its impact on team dynamics."},"answer":1},{"qn":126,"hi":{"prompt":["एक विनिर्माण कंपनी को उत्पादन क्षमता के विस्तार के बारे में निर्णय लेना है। परिणाम भविष्य की बाजार स्थितियों पर बहुत अधिक निर्भर करता है, लेकिन अर्थशास्त्री आर्थिक पूर्वानुमानों के बारे में असहमत हैं। निर्णय लेने का कौन सा तरीका सबसे उपयुक्त है?"],"options":["जब तक आर्थिक पूर्वानुमान अधिक निश्चित न हो जाएं, तब तक प्रतीक्षा करें","कई संभावित भविष्य की तैयारी के लिए परिदृश्य योजना का उपयोग करें","सबसे आशावादी पूर्वानुमान के आधार पर निर्णय लें","पूर्वानुमानों की परवाह किए बिना धीरे-धीरे क्षमता का विस्तार करें"],"solution":"Future market uncertain hai aur experts disagree karte hain to scenario planning use karna best approach hai jisse multiple possible futures ke liye prepare kiya ja sake."},"en":{"prompt":["A manufacturing company must decide on expanding production capacity. The outcome depends heavily on future market conditions, but economists disagree on economic forecasts. Which decision-making approach is most suitable?"],"options":["Wait until economic forecasts become more certain","Use scenario planning to prepare for multiple possible futures","Decide based on the most optimistic forecast","Expand capacity gradually regardless of forecasts"],"solution":"With an uncertain future market and disagreeing experts, using scenario planning to prepare for multiple possible futures is the best approach."},"answer":1},{"qn":127,"hi":{"prompt":["ऐसी स्थिति में जहाँ आपका टीम साथी खराब प्रदर्शन कर रहा है। सबसे भावनात्मक रूप से बुद्धिमान प्रतिक्रिया क्या होगी?"],"options":["मार्गदर्शन या सहायता प्रदान करें","बॉस से उनकी आलोचना करें","खुद को दूर कर लें","समस्या को अनदेखा करें"],"solution":"Team-mate poorly perform kar raha hai to guidance/support offer karna sahi emotionally intelligent response hai, boss se complain ya ignore karna nahi."},"en":{"prompt":["In a situation where your teammate is performing poorly, what would be the most emotionally intelligent response?"],"options":["Offer guidance or help","Criticize them to the boss","Distance yourself","Ignore the problem"],"solution":"When a teammate is performing poorly, offering guidance or help is the emotionally intelligent response, not complaining to the boss or ignoring it."},"answer":0},{"qn":128,"hi":{"prompt":["श्रृंखला में लुप्त संख्या ज्ञात कीजिए: 9, 7, 4, 2, ?"],"options":["-4","-3","-1","-2"],"solution":"Series: 9,7,4,2,? — differences -2,-3,-2 pattern se next -3 → 2-3=-1, jo diya gaya answer C hai."},"en":{"prompt":["Find the missing number in the series: 9, 7, 4, 2, ?"],"options":["-4","-3","-1","-2"],"solution":"This is a number-series question; following the given pattern of decreasing differences, the correct next term is -1."},"answer":2},{"qn":129,"hi":{"prompt":["एक कंसल्टिंग फर्म के भागीदार इस बात पर बंटे हुए हैं कि क्या किसी विशिष्ट बाज़ार में विशेषज्ञता हासिल की जाए या अपनी वर्तमान व्यापक सेवा पेशकश को बनाए रखा जाए। उन्हें कौन सा रणनीतिक निर्णय लेने का दृष्टिकोण अपनाना चाहिए?"],"options":["उच्च लाभप्रदता के लिए विशिष्ट बाज़ार में विशेषज्ञता हासिल करें","अवसरों को अधिकतम करने के लिए व्यापक सेवाओं को बनाए रखें","सर्वोत्तम रणनीतिक फिट निर्धारित करने के लिए अपनी मुख्य दक्षताओं और प्रतिस्पर्धी लाभों का विश्लेषण करें","मौजूदा ग्राहकों का सर्वेक्षण करके उनकी प्राथमिकताओं का निर्धारण करें"],"solution":"Partners bante hue hain niche/broad strategy pe — sahi approach hai apni core competencies aur competitive advantages analyze karke best strategic fit determine karna, survey ya gut-feeling se nahi."},"en":{"prompt":["Partners at a consulting firm are divided on whether to specialize in a specific market niche or maintain their current broad service offering. What strategic decision-making approach should they take?"],"options":["Specialize in a niche market for higher profitability","Maintain broad services to maximize opportunities","Analyze their core competencies and competitive advantages to determine the best strategic fit","Survey existing clients to determine their preferences"],"solution":"With partners divided on niche versus broad strategy, the right approach is analyzing core competencies and competitive advantages to determine the best strategic fit, not deciding by survey or gut feeling."},"answer":2},{"qn":130,"hi":{"prompt":["यदि धूप नहीं है, तो बादल छाए हुए हैं। यदि बादल छाए हुए हैं, तो बारिश हो सकती है। आज, बारिश नहीं हो रही है। हम निम्नलिखित में से क्या निष्कर्ष निकाल सकते हैं?"],"options":["निश्चित रूप से धूप है","निश्चित रूप से बादल छाए हुए हैं","धूप हो सकती है","निश्चित रूप से बादल नहीं हैं"],"solution":"Logical chain: no sun→clouds→maybe rain; rain nahi ho rahi (rain false) — isse clouds ke baare me kuch certain nahi keh sakte (clouds bina rain ke bhi ho sakte hain), isliye sirf 'sun ho sakta hai' hi valid maybe-conclusion hai, certain nahi."},"en":{"prompt":["If there is no sun, it is cloudy. If it is cloudy, it might rain. Today, it is not raining. What can we conclude?"],"options":["It is definitely sunny","It is definitely cloudy","It might be sunny","It is definitely not cloudy"],"solution":"The logical chain is: no sun → clouds → possible rain; since it's not raining, nothing certain can be said about clouds (clouds can exist without rain), so the only valid conclusion is that it might be sunny — not a certainty."},"answer":2},{"qn":131,"hi":{"prompt":["ऐसी स्थिति में जहाँ आपका कोई मित्र आपके बोलते समय लगातार टोकता है। सबसे अधिक भावनात्मक रूप से बुद्धिमत्तापूर्ण प्रतिक्रिया क्या होगी?"],"options":["उन्हें वापस टोकना","उनसे सम्मानपूर्वक इस बारे में बात करना","उनसे पूरी तरह से संबंध तोड़ लेना","व्यंग्यात्मक होना"],"solution":"Dost baar baar interrupt karta hai to unse respectfully baat karna sahi EQ response hai, wapas interrupt karna ya relationship todna nahi."},"en":{"prompt":["In a situation where a friend constantly interrupts you while you're speaking, what would be the most emotionally intelligent response?"],"options":["Interrupt them back","Talk to them about it respectfully","Cut off the relationship completely","Be sarcastic"],"solution":"When a friend repeatedly interrupts you, talking to them about it respectfully is the right emotionally intelligent response, not interrupting back or ending the friendship."},"answer":1},{"qn":132,"hi":{"prompt":["गरमागरम बहस के दौरान, अंजलि शांत रहती है और दूसरे व्यक्ति के दृष्टिकोण को समझने की कोशिश करती है। यह दर्शाता है:"],"options":["आक्रामक रवैया","सामाजिक बुद्धिमत्ता","लापरवाही","अरुचि"],"solution":"Heated debate me calm rehna aur dusre ka perspective samajhna social intelligence dikhata hai, aggression ya carelessness nahi."},"en":{"prompt":["During a heated debate, Anjali stays calm and tries to understand the other person's point of view. This shows:"],"options":["An aggressive attitude","Social intelligence","Carelessness","Disinterest"],"solution":"Staying calm in a heated debate and trying to understand the other person's perspective shows social intelligence, not aggression or carelessness."},"answer":1},{"qn":133,"hi":{"prompt":["कठिन प्रतिक्रिया देते समय, पर्यवेक्षक जेनेट देखती है कि जब कर्मचारी संकट के लक्षण दिखाते हैं तो वह अपने संदेश को काफी नरम कर देती है, भले ही प्रतिक्रिया उनके विकास के लिए महत्वपूर्ण हो। यह पैटर्न क्या दर्शाता है?"],"options":["जेनेट यथोचित रूप से दयालु है और उसे इस दृष्टिकोण को जारी रखना चाहिए","दूसरों के संकट के साथ जेनेट की भावनात्मक परेशानी उसकी प्रभावशीलता से समझौता कर सकती है","कर्मचारियों की भावनात्मक प्रतिक्रियाएं प्रतिक्रिया वितरण के लिए अप्रासंगिक हैं","जेनेट को हमेशा प्रतिक्रिया गुणवत्ता पर कर्मचारियों के भावनात्मक आराम को प्राथमिकता देनी चाहिए"],"solution":"Supervisor feedback ko zyada soften kar deti hai jab employee distress dikhaye — ye pattern dikhata hai ki dusro ka distress supervisor ki apni emotional discomfort ban jata hai jo effectiveness compromise karta hai."},"en":{"prompt":["While giving difficult feedback, supervisor Janet notices she considerably softens her message whenever employees show signs of distress, even when the feedback is important for their development. What does this pattern indicate?"],"options":["Janet is appropriately kind and should continue this approach","Janet's own emotional discomfort with others' distress may be compromising her effectiveness","Employees' emotional reactions are irrelevant to feedback delivery","Janet should always prioritize employees' emotional comfort over feedback quality"],"solution":"Softening feedback whenever an employee shows distress indicates the supervisor's own discomfort with others' distress is compromising her effectiveness."},"answer":1},{"qn":134,"hi":{"prompt":["एक मित्र परीक्षा में खराब अंक आने से परेशान है। सबसे अच्छी प्रारंभिक प्रतिक्रिया क्या होगी?"],"options":["अगली बार तुम इससे भी बुरा करोगे","आपको और अधिक पढ़ाई करनी चाहिए थी","\"इस बारे में बात करना चाहते हैं?\"","\"यह कोई बड़ी बात नहीं है\""],"solution":"Dost bad marks se upset hai to pehla response hona chahiye simply pooch lena 'baat karna chahoge?' — judgmental ya dismissive comments nahi."},"en":{"prompt":["A friend is upset about getting a bad grade on an exam. What would be the best initial response?"],"options":["\"You'll probably do even worse next time\"","\"You should have studied more\"","\"Do you want to talk about it?\"","\"It's not a big deal\""],"solution":"When a friend is upset about a bad grade, the right first response is simply asking, 'Do you want to talk about it?' — not judgmental or dismissive comments."},"answer":2},{"qn":135,"hi":{"prompt":["यदि कोई सहपाठी समूह कार्य के दौरान अक्सर दूसरों को बाधित करता है, तो सर्वोत्तम भावनात्मक बुद्धिमत्ता रणनीति क्या होगी?"],"options":["उन्हें नजरअंदाज करो","उन्हें बारी-बारी से काम करने के बारे में धीरे से याद दिलाएं","सार्वजनिक रूप से उनका सामना करें","इनसे पूरी तरह बचें"],"solution":"Baar baar interrupt karne wale classmate ko gently turn-taking yaad dilana best EI strategy hai — ignore ya public confront extreme options hain."},"en":{"prompt":["If a classmate frequently interrupts others during group work, what would be the best emotional intelligence strategy?"],"options":["Ignore them","Gently remind them to take turns","Confront them publicly","Avoid them entirely"],"solution":"Gently reminding a frequently-interrupting classmate to take turns is the best emotional intelligence strategy — ignoring or publicly confronting are extreme options."},"answer":1}],"set10":[{"qn":136,"hi":{"prompt":["कक्षा में बहस के दौरान, किसी व्यक्ति की राय विपरीत होती है। आपको सामाजिक रूप से इसका जवाब कैसे देना चाहिए?"],"options":["उन्हें बर्खास्त करें","सुनें और तार्किक ढंग से जवाब दें","उनकी बात को नज़रअंदाज़ करें","दूर जाना"],"solution":"Opposite opinion par socially sahi response hai suno aur logically respond karo, dismiss ya avoid karna nahi."},"en":{"prompt":["During a class debate, someone holds an opposing opinion. How should you socially respond?"],"options":["Dismiss them","Listen and respond logically","Ignore their point","Walk away"],"solution":"The socially right response to an opposing opinion is to listen and respond logically, not dismiss or avoid it."},"answer":1},{"qn":137,"hi":{"prompt":["आपका साथी खिलाड़ी गुस्से में है और आप पर गलत तरीके से आरोप लगाना शुरू कर देता है। भावनात्मक रूप से बुद्धिमानी से प्रतिक्रिया देने का तरीका क्या है?"],"options":["चिल्लाओ वापस","तुरंत चले जाओ","शांति से सुनें और तथ्यों को स्पष्ट करें","उन्हें वापस दोष दें"],"solution":"Angrily blame lagane wale teammate ke against calmly sunna aur facts clarify karna sahi emotionally intelligent tarika hai."},"en":{"prompt":["Your teammate is angry and starts wrongly accusing you. What is the emotionally intelligent way to respond?"],"options":["Shout back","Leave immediately","Listen calmly and clarify the facts","Blame them back"],"solution":"Against an angry teammate wrongly accusing you, calmly listening and clarifying the facts is the right emotionally intelligent approach."},"answer":2},{"qn":138,"hi":{"prompt":["आपका मित्र किसी प्रोजेक्ट को लेकर उत्साहित है लेकिन उसका विचार दोषपूर्ण लगता है। आपको क्या करना चाहिए?"],"options":["उन पर हंसो","सार्वजनिक रूप से आलोचना करें","निजी, सम्मानजनक प्रतिक्रिया दें","विषय बदलें"],"solution":"Dost project ke idea me passionate hai lekin flawed lagta hai to private, respectful feedback dena sahi hai, hasna ya public criticism nahi."},"en":{"prompt":["Your friend is excited about a project but their idea seems flawed. What should you do?"],"options":["Laugh at them","Criticize them publicly","Give private, respectful feedback","Change the subject"],"solution":"When a friend is passionate about a flawed idea, giving private, respectful feedback is right — not laughing or public criticism."},"answer":2},{"qn":139,"hi":{"prompt":["एक समूह चर्चा के दौरान, किसी को लगातार बाधित किया जा रहा है। सामाजिक रूप से बुद्धिमत्तापूर्ण प्रतिक्रिया क्या है?"],"options":["वक्ता के बोलने का समर्थन करें","बाधा को अनदेखा करें","उन्हें इससे निपटने दें","आप भी बाधित करना शुरू कर दें"],"solution":"Group discussion me kisi ko baar baar interrupt kiya ja raha ho to speaker ka support karna (unhe bolne dena) socially intelligent response hai."},"en":{"prompt":["During a group discussion, someone is repeatedly interrupted. What is the socially intelligent response?"],"options":["Support the speaker's turn to talk","Ignore the interruption","Let them handle it themselves","Start interrupting too"],"solution":"When someone is repeatedly interrupted in a group discussion, supporting the speaker by letting them finish is the socially intelligent response."},"answer":0},{"qn":140,"hi":{"prompt":["आप देखते हैं कि एक अजनबी व्यक्ति एक स्टोर क्लर्क के साथ अनुचित रूप से अशिष्ट व्यवहार कर रहा है, जो बस अपना काम कर रहा है। इसका जवाब देने का सबसे सामाजिक रूप से बुद्धिमान तरीका क्या है?"],"options":["असभ्य अजनबी से सीधे भिड़ें और उन्हें डांटें","इस स्थिति को पूरी तरह से नजरअंदाज करें, क्योंकि यह आपका काम नहीं है","मौन समर्थन दिखाने के लिए क्लर्क से आँख से आँख मिलाएँ, बाद में प्रोत्साहन के संक्षिप्त, शांत शब्द कहें","सबूत के रूप में ऑनलाइन पोस्ट करने के लिए फोन पर बातचीत रिकॉर्ड करें"],"solution":"Stranger clerk ke saath rude behave kar raha ho to seedha confront karne ke bajaye clerk se eye-contact aur baad me quiet encouragement dena diplomatic supportive tarika hai."},"en":{"prompt":["You notice a stranger being unfairly rude to a store clerk who is just doing their job. What is the most socially intelligent way to respond?"],"options":["Directly confront and scold the rude stranger","Ignore the situation entirely since it's not your business","Make eye contact with the clerk to show silent support, and later offer brief, quiet words of encouragement","Record the exchange on your phone to post online as evidence"],"solution":"When a stranger is rude to a clerk, making eye contact for silent support and offering quiet encouragement afterward is the diplomatic, supportive way, rather than confronting directly."},"answer":2},{"qn":141,"hi":{"prompt":["आपका दोस्त उत्साह से आपको बताता है कि उसे अपने सपनों के विश्वविद्यालय में दाखिला मिल गया है। भावनात्मक रूप से सबसे बुद्धिमानी भरा जवाब क्या होगा?"],"options":["\"यह तो बहुत बढ़िया है! किसी दूसरे विश्वविद्यालय में मेरे आवेदन के बारे में क्या ख्याल है?\"","\"वाह, यह तो अद्भुत है! मैं तुम्हारे लिए बहुत खुश हूँ। तुम्हें कैसे पता चला?\"","\"क्या तुम सचमुच वहाँ जाना चाहते हो? मैंने सुना है कि यह बहुत कठिन है।\"","\"ठीक है, बढ़िया। अब मैं तुम्हें अपने दिन के बारे में बताता हूँ।\""],"solution":"Dost excited hai apni university acceptance se to genuinely enthusiastic hoke unke liye khush hona aur details poochna sahi EQ response hai, apni baat pehle laana nahi."},"en":{"prompt":["Your friend excitedly tells you they got accepted into their dream university. What would be the most emotionally intelligent response?"],"options":["\"That's great! What about my application to another university?\"","\"Wow, that's amazing! I'm so happy for you. How did you find out?\"","\"Do you really want to go there? I heard it's really tough.\"","\"Okay, cool. Now let me tell you about my day.\""],"solution":"When a friend is excited about a university acceptance, genuinely sharing their enthusiasm and asking follow-up questions is the right emotionally intelligent response, not shifting focus to yourself."},"answer":1},{"qn":142,"hi":{"prompt":["भीड़-भाड़ वाले फुटपाथ पर आप गलती से किसी से टकरा जाते हैं। सामाजिक रूप से सबसे बुद्धिमानी भरा काम क्या होगा?"],"options":["तेजी से चलते रहें, यह मानकर कि वे ध्यान नहीं देंगे","पीछे मुड़ें और उन्हें परेशान होकर देखें","थोड़ी देर रुकें, आंखों से संपर्क बनाएं और एक सरल \"माफ करें!\" कहें","ऐसा दिखावा करें कि आप फोन पर हैं, ताकि आपको जानकारी न देनी पड़े"],"solution":"Bhool se kisi se takra gaye to rukkar eye contact karke simple 'sorry' bolna sabse socially intelligent polite gesture hai."},"en":{"prompt":["On a crowded sidewalk, you accidentally bump into someone. What would be the most socially intelligent thing to do?"],"options":["Keep walking fast, assuming they won't notice","Turn back and glare at them, annoyed","Pause briefly, make eye contact, and say a simple \"Sorry!\"","Pretend to be on the phone to avoid acknowledging it"],"solution":"After accidentally bumping into someone, pausing, making eye contact, and saying a simple 'sorry' is the most socially intelligent, polite gesture."},"answer":2},{"qn":143,"hi":{"prompt":["आप टीम लीडर हैं और आपके टीम के साथी ने व्यक्तिगत कारणों से समय-सीमा का पालन नहीं किया। आप क्या करेंगे?"],"options":["उन्हें तुरंत हटा दें","सहानुभूति दिखाएं और समाधान खोजें","दूसरों के सामने उन पर दोषारोपण करें","दिखावा करें कि कुछ हुआ ही नहीं"],"solution":"Teammate personal reasons se deadline miss kiya to empathy dikhao aur saath me solution dhoondo, turant remove ya blame karna galat."},"en":{"prompt":["You are the team leader and your teammate missed a deadline for personal reasons. What will you do?"],"options":["Remove them immediately","Show empathy and find a solution","Blame them in front of others","Pretend nothing happened"],"solution":"When a teammate misses a deadline for personal reasons, showing empathy and finding a solution together is right, not removing or blaming them immediately."},"answer":1},{"qn":144,"hi":{"prompt":["एक छात्र जो यह देखता है कि उनका सहपाठी परेशान है और सहायता प्रदान करता है, वह भावनात्मक बुद्धिमत्ता का कौन सा घटक दर्शा रहा है?"],"options":["तार्किक तर्क","आत्म-जागरूकता","समानुभूति","मौखिक संचार"],"solution":"Upset classmate ko dekh kar help offer karna 'empathy' (samanubhuti) component ko dikhata hai emotional intelligence ka."},"en":{"prompt":["A student who notices a classmate is upset and offers to help is demonstrating which component of emotional intelligence?"],"options":["Logical reasoning","Self-awareness","Empathy","Verbal communication"],"solution":"Noticing an upset classmate and offering help demonstrates the 'empathy' component of emotional intelligence."},"answer":2},{"qn":145,"hi":{"prompt":["एक व्यक्ति जो आसानी से गुस्सा हो जाता है और अक्सर बिना सोचे-समझे प्रतिक्रिया करता है, उसमें किस प्रमुख भावनात्मक बुद्धिमत्ता कौशल की कमी होती है?"],"options":["प्रेरणा","भावनात्मक विनियमन","समस्या-समाधान","मौखिक प्रवाह"],"solution":"Jo insan aasani se gussa ho jata hai aur bina soche react karta hai usme 'emotional regulation' skill ki kami hoti hai."},"en":{"prompt":["A person who gets angry easily and often reacts without thinking lacks which key emotional intelligence skill?"],"options":["Motivation","Emotional regulation","Problem-solving","Verbal fluency"],"solution":"Someone who gets angry easily and reacts without thinking lacks the skill of 'emotional regulation'."},"answer":1},{"qn":146,"hi":{"prompt":["कौन सी स्थिति गंभीर सोच को सर्वोत्तम रूप से प्रदर्शित करती है?"],"options":["जल्दी से अफवाह पर विश्वास करना","सहमत होने से पहले सबूत मांगना","दूसरों की राय की नकल करना","भावनात्मक रूप से प्रतिक्रिया करना"],"solution":"Sabooto ke bina turant agree karne ke bajaye evidence maangna hi critical thinking ka best example hai."},"en":{"prompt":["Which situation best demonstrates critical thinking?"],"options":["Quickly believing a rumor","Asking for evidence before agreeing","Copying others' opinions","Reacting emotionally"],"solution":"Asking for evidence before agreeing, instead of immediately believing something without proof, is the best example of critical thinking."},"answer":1},{"qn":147,"hi":{"prompt":["निम्नलिखित में से कौन समूह चर्चा में भावनात्मक बुद्धिमत्ता का उपयोग करने का एक उदाहरण है?"],"options":["अपनी बात साबित करने के लिए बातचीत पर हावी होना","दूसरों की राय को अनदेखा करना और केवल तथ्यों पर ध्यान केंद्रित करना","सक्रिय रूप से सुनना और दूसरों के विचारों पर सम्मानपूर्वक प्रतिक्रिया देना","सभी चर्चा बिंदुओं को याद करना"],"solution":"Group discussion me actively sunna aur dusro ke ideas par respectfully respond karna emotional intelligence ka sahi example hai, dominate karna ya ignore karna nahi."},"en":{"prompt":["Which of the following is an example of using emotional intelligence in a group discussion?"],"options":["Dominating the conversation to prove your point","Ignoring others' opinions and focusing only on facts","Actively listening and responding respectfully to others' ideas","Memorizing all the discussion points"],"solution":"Actively listening and responding respectfully to others' ideas in a group discussion is the correct example of emotional intelligence, not dominating or ignoring."},"answer":2},{"qn":148,"hi":{"prompt":["राहुल को पता चलता है कि उसका दोस्त मुस्कुरा रहा है, फिर भी वह परेशान है। राहुल क्या प्रदर्शित कर रहा है:"],"options":["गणितीय बुद्धिमत्ता","सामाजिक असंवेदनशीलता","तार्किक तर्क","भावनात्मक जागरूकता"],"solution":"Rahul dekh raha hai dost smile kar raha hai but upset bhi hai — ye emotional awareness (bhavnatmak jagrukta) dikhata hai, seedha expression ke peeche ka sach samajhna."},"en":{"prompt":["Rahul notices that his friend is smiling, yet also seems upset. What is Rahul demonstrating?"],"options":["Mathematical intelligence","Social insensitivity","Logical reasoning","Emotional awareness"],"solution":"Noticing that a friend is smiling but also upset shows emotional awareness — understanding the truth behind the surface expression."},"answer":3},{"qn":149,"hi":{"prompt":["The school's drama club is putting on a production of Romeo and Juliet, and the director needs to cast the lead roles. Which students would be best suited for the parts of Romeo and Juliet?"],"options":["The football team's quarterback and the cheerleading captain.","The school's valedictorian and the student council president.","The drama club president and the choir club president.","The school's mathlete and the debate team captain."],"solution":"Drama roles (Romeo-Juliet) ke liye sabse suited students wahi honge jo already drama/performing arts me involved hain — drama president aur choir president logical fit hain."},"en":{"prompt":["The school's drama club is putting on a production of Romeo and Juliet, and the director needs to cast the lead roles. Which students would be best suited for the parts of Romeo and Juliet?"],"options":["The football team's quarterback and the cheerleading captain","The school's valedictorian and the student council president","The drama club president and the choir club president","The school's mathlete and the debate team captain"],"solution":"The students best suited for drama roles are those already involved in drama or performing arts — the drama club president and choir president are the logical fit."},"answer":2},{"qn":150,"hi":{"prompt":["While managing a project, you find that an employee has made an unintentional error. How should you respond?"],"options":["Ignore the error and continue with the project","Publicly call out the employee for the mistake in front of the team","Discuss the error privately with the employee and offer guidance to fix it","Do the work yourself to ensure no further issues arise"],"solution":"Unintentional error par employee ko privately guide karna sahi management approach hai, public shaming ya khud kaam karna nahi."},"en":{"prompt":["While managing a project, you find that an employee has made an unintentional error. How should you respond?"],"options":["Ignore the error and continue with the project","Publicly call out the employee for the mistake in front of the team","Discuss the error privately with the employee and offer guidance to fix it","Do the work yourself to ensure no further issues arise"],"solution":"Discussing an unintentional error privately with the employee and offering guidance is the right management approach, not public shaming or doing the work yourself."},"answer":2}],"set11":[{"qn":151,"hi":{"prompt":["The school has organized a field trip to the nearby forest, and the students will be spending the day learning about the local flora and fauna. Which of the following should the students bring with them?"],"options":["A packed lunch and a refillable water bottle.","A heavy coat and gloves for warmth.","A swimsuit and a towel for a swim in the lake.","A handheld video game to pass the time."],"solution":"Forest field trip ke liye packed lunch + refillable water bottle basic practical necessities hain."},"en":{"prompt":["The school has organized a field trip to the nearby forest, and the students will be spending the day learning about the local flora and fauna. Which of the following should the students bring with them?"],"options":["A packed lunch and a refillable water bottle","A heavy coat and gloves for warmth","A swimsuit and a towel for a swim in the lake","A handheld video game to pass the time"],"solution":"A packed lunch and a refillable water bottle are basic practical necessities for a forest field trip."},"answer":0},{"qn":152,"hi":{"prompt":["The school's football team is facing off against the rival team in the championship game. The coach wants to motivate the players and has promised to take them to a celebratory dinner. Which restaurant should the coach choose?"],"options":["A fancy French restaurant with a dress code and a wine list.","A burger joint with no buffet option and limited dessert choices.","An Italian pizzeria with a casual atmosphere and a wood-fired oven.","A seafood restaurant with a sushi bar and a lobster tank."],"solution":"Team celebration ke liye casual, inclusive Italian pizzeria fit karta hai celebratory team dinner ke mood ke saath, fancy/formal options nahi."},"en":{"prompt":["The school's football team is facing off against the rival team in the championship game. The coach wants to motivate the players and has promised to take them to a celebratory dinner. Which restaurant should the coach choose?"],"options":["A fancy French restaurant with a dress code and a wine list","A burger joint with no buffet option and limited dessert choices","An Italian pizzeria with a casual atmosphere and a wood-fired oven","A seafood restaurant with a sushi bar and a lobster tank"],"solution":"A casual, inclusive Italian pizzeria fits the mood of a celebratory team dinner better than fancy or formal options."},"answer":2},{"qn":153,"hi":{"prompt":["You observe child labor being used to serve food at a restaurant. What is the most responsible action to take?"],"options":["Ignore the situation and continue with your meal","Confront the restaurant management in front of other customers","Report the situation to the authorities or child welfare organization","Offer the child money to leave the job"],"solution":"Child labor dekh kar sabse responsible action authorities/child welfare organization ko report karna hai."},"en":{"prompt":["You observe child labor being used to serve food at a restaurant. What is the most responsible action to take?"],"options":["Ignore the situation and continue with your meal","Confront the restaurant management in front of other customers","Report the situation to the authorities or a child welfare organization","Offer the child money to leave the job"],"solution":"On observing child labor, the most responsible action is reporting it to the authorities or a child welfare organization."},"answer":2},{"qn":154,"hi":{"prompt":["Scenario: You are trying to find a specific book in a library. Which of the following is the most efficient first step?"],"options":["Wander around randomly looking at all the shelves.","Ask a librarian for help.","Start reading the titles of every book on one shelf.","Leave the library and try to find the book elsewhere."],"solution":"Library me specific book dhundhne ka sabse efficient first step librarian se help maangna hai."},"en":{"prompt":["Scenario: You are trying to find a specific book in a library. Which of the following is the most efficient first step?"],"options":["Wander around randomly looking at all the shelves","Ask a librarian for help","Start reading the titles of every book on one shelf","Leave the library and try to find the book elsewhere"],"solution":"The most efficient first step to find a specific book in a library is asking a librarian for help."},"answer":1},{"qn":155,"hi":{"prompt":["कक्षा में, शिक्षक एक गणित की समस्या हल कर रहे हैं, लेकिन आपको समाधान समझने में परेशानी हो रही है। आपको क्या करना चाहिए?"],"options":["चुप रहें और आशा करें कि बाद में यह स्पष्ट हो जाएगा","व्याख्या के दौरान अपनी उलझन को तुरंत चिल्लाकर बताएं","शिक्षक के समाप्त होने तक प्रतीक्षा करें और फिर विनम्रता से स्पष्टीकरण मांगें, यदि आवश्यक हो तो संक्षेप में रुक सकते हैं","बिना समझे समाधान को कॉपी करें और घर पर इसे समझने की कोशिश करें"],"solution":"Math problem samajh nahi aayi to teacher ke finish hone ka wait karo phir politely clarification maango — beech me chillana ya bina samjhe copy karna galat."},"en":{"prompt":["In class, the teacher is solving a math problem, but you're having trouble understanding the solution. What should you do?"],"options":["Stay silent and hope it becomes clear later","Shout out your confusion immediately during the explanation","Wait until the teacher finishes, then politely ask for clarification, pausing briefly if needed","Copy the solution without understanding it and try to understand it at home"],"solution":"If you don't understand a math problem, waiting for the teacher to finish and then politely asking for clarification is correct — interrupting or copying without understanding is wrong."},"answer":2},{"qn":156,"hi":{"prompt":["आज रात आप छह दोस्तों के लिए डिनर पार्टी आयोजित कर रहे हैं। खरीदारी करते समय, आपको पता चलता है कि आपकी योजनाबद्ध डिश का मुख्य घटक स्टोर में बिक चुका है। मेहमानों के आने में दो घंटे बाकी हैं। आपको क्या करना चाहिए?"],"options":["सामग्री खोजने के लिए 30 मिनट दूर दूसरे स्टोर पर जाएं","इसके बजाय परोसने के लिए मौजूदा स्टोर से पहले से तैयार भोजन खरीदें","घर पर पहले से उपलब्ध सामग्री का उपयोग करने के लिए मेनू बदलें","अपने दोस्तों को बुलाएं और उनसे अपना भोजन लाने के लिए कहें"],"solution":"Ingredient miss hone par time constraint (2 hours) dekhte hue available ingredients se menu adjust karna sabse practical solution hai."},"en":{"prompt":["Tonight you're hosting a dinner party for six friends. While shopping, you discover the main ingredient of your planned dish is sold out at the store. Guests arrive in two hours. What should you do?"],"options":["Drive 30 minutes to another store to find the ingredient","Buy pre-made food from the current store to serve instead","Change the menu to use ingredients already available at home","Call your friends and ask them to bring their own food"],"solution":"Given the time constraint (2 hours) after an ingredient sells out, adjusting the menu to use ingredients already at home is the most practical solution."},"answer":2},{"qn":157,"hi":{"prompt":["कोई दुकानदार गलती से आपको अधिक पैसे दे दे, तो आपको क्या करना चाहिए?"],"options":["इसे चुपचाप रखो","अतिरिक्त पैसे वापस करें","इसे तुरंत खर्च करें","ध्यान न देने का नाटक करें"],"solution":"Dukandar ne extra paise diye to unhe wapas karna hi honest correct action hai."},"en":{"prompt":["If a shopkeeper accidentally gives you extra change, what should you do?"],"options":["Keep it quietly","Return the extra money","Spend it immediately","Pretend not to notice"],"solution":"If a shopkeeper gives extra money by mistake, returning it is the honest, correct action."},"answer":1},{"qn":158,"hi":{"prompt":["यदि आप किसी को भीड़भाड़ वाले स्थान पर अपना फोन गिराते हुए देखते हैं, तो सबसे जिम्मेदारीपूर्ण कार्य क्या होगा?"],"options":["इसे उठाओ और रख लो","इसे सिक्योरिटी को सौंप दें","दूर जाना","इसे ऑनलाइन बेचें"],"solution":"Kisi ka phone crowded jagah gira dekha to use security ko handover karna sahi responsible action hai."},"en":{"prompt":["If you see someone drop their phone in a crowded place, what would be the most responsible action?"],"options":["Pick it up and keep it","Hand it over to security","Walk away","Sell it online"],"solution":"On seeing someone's phone drop in a crowded place, handing it over to security is the responsible action."},"answer":1},{"qn":159,"hi":{"prompt":["परियोजना की समय-सीमा लचीली नहीं है, फिर भी वर्तमान प्रगति से पता चलता है कि परियोजना समय पर पूरी नहीं होगी। इंजीनियर को निम्नलिखित में से कौन-सा निर्णय लेना चाहिए?"],"options":["ओवरटाइम और शिफ्ट कार्य में वृद्धि","प्रीफैब्रिकेशन तकनीक लागू करें","महत्वपूर्ण कार्यों का पुनर्मूल्यांकन करें और उन्हें प्राथमिकता दें","समय सीमा विस्तार का अनुरोध करें"],"solution":"Fixed deadline miss hone ka risk ho to critical tasks reprioritize karna best practical engineering decision hai."},"en":{"prompt":["The project deadline is not flexible, yet current progress shows the project won't finish on time. Which of the following decisions should the engineer make?"],"options":["Increase overtime and shift work","Implement prefabrication techniques","Re-evaluate and prioritize critical tasks","Request a deadline extension"],"solution":"When a fixed deadline is at risk of being missed, re-evaluating and prioritizing critical tasks is the best practical engineering decision."},"answer":2},{"qn":160,"hi":{"prompt":["निर्णयकर्ता को दो योजनाओं में से एक चुनना है: योजना X लक्ष्य के 90% की गारंटी देती है। योजना Y लक्ष्य से 20% अधिक होने की 60% संभावना और 10% कम होने की 40% संभावना देती है। निर्णयकर्ता जोखिम-तटस्थ है और केवल अपेक्षित परिणाम पर आधारित है। कौन-सी योजना प्राथमिकता दी जानी चाहिए?"],"options":["योजना X","योजना Y","दोनों योजनाएं समान हैं","लक्ष्य के बारे में अधिक जानकारी आवश्यक है"],"solution":"Risk-neutral decision maker sirf expected value dekhta hai: Plan Y expected = 0.6×(+20%)+0.4×(-10%) = 12%-4%=+8% jo Plan X ke guaranteed 90% (i.e. -10% se) se better hai — isliye Plan Y prefer hoga expected-value comparison me."},"en":{"prompt":["A decision-maker must choose between two plans: Plan X guarantees 90% of the target. Plan Y has a 60% chance of being 20% above target and a 40% chance of being 10% below. The decision-maker is risk-neutral and bases the choice only on expected outcome. Which plan should be preferred?"],"options":["Plan X","Plan Y","Both plans are equal","More information about the target is needed"],"solution":"A risk-neutral decision-maker looks only at expected value: Plan Y's expected value is 0.6×(+20%) + 0.4×(-10%) = 12% - 4% = +8% above target, which beats Plan X's guaranteed 90% — so Plan Y is preferred by expected-value comparison."},"answer":1},{"qn":161,"hi":{"prompt":["एक आदमी को सड़क पर नकदी से भरा एक बटुआ मिलता है। उसे क्या करना चाहिए?"],"options":["पैसा रख लो","इसे दान में दें","मालिक को खोजने का प्रयास करें","इसे नज़रअंदाज़ करें और चले जाएँ"],"solution":"Sadak par bharpur wallet milne par sahi kaam owner ko dhundhne ki koshish karna hai."},"en":{"prompt":["A man finds a wallet full of cash on the street. What should he do?"],"options":["Keep the money","Donate it","Try to find the owner","Ignore it and walk away"],"solution":"On finding a wallet full of cash on the street, the right action is trying to find the owner."},"answer":2},{"qn":162,"hi":{"prompt":["यदि आप कोई सड़क दुर्घटना देखते हैं तो सबसे अच्छी बात क्या होगी?"],"options":["वीडियो रिकॉर्ड करें","आपातकालीन सेवाओं को कॉल करें","दूर जाना","बिना कुछ किए मदद के लिए चिल्लाएँ"],"solution":"Accident dekh kar sabse pehla sahi kaam emergency services ko call karna hai."},"en":{"prompt":["What would be the best thing to do if you witness a road accident?"],"options":["Record a video","Call emergency services","Walk away","Shout for help without doing anything"],"solution":"On witnessing an accident, the first correct action is calling emergency services."},"answer":1},{"qn":163,"hi":{"prompt":["कल आपकी एक महत्वपूर्ण परीक्षा है, लेकिन आपके दोस्त आपको देर रात की पार्टी में आमंत्रित करते हैं। आपको क्या करना चाहिए?"],"options":["पार्टी में जाओ","परीक्षा के लिए अध्ययन करें","परीक्षा की अनदेखी करें","पढ़ाई स्थगित करें"],"solution":"Kal important exam hai to study karna hi sahi priority hai, party se dur rehna."},"en":{"prompt":["You have an important exam tomorrow, but your friends invite you to a late-night party. What should you do?"],"options":["Go to the party","Study for the exam","Ignore the exam","Postpone studying"],"solution":"With an important exam tomorrow, studying is the right priority, staying away from the party."},"answer":1},{"qn":164,"hi":{"prompt":["निर्माण की समय-सीमा को पूरा करने का दबाव बहुत ज़्यादा है। कुछ प्रोजेक्ट सुपरवाइजर प्रक्रिया को तेज़ करने के लिए कुछ सुरक्षा परीक्षणों को छोड़ने का सुझाव देते हैं। क्या सही फ़ैसला लिया जाना चाहिए?"],"options":["तेजी से पूरा करने के लिए सुरक्षा परीक्षण छोड़ें","केवल अनिवार्य सुरक्षा परीक्षण ही करें","समानांतर सुरक्षा और निर्माण कार्य की अनुसूची बनाएं","सुरक्षा परीक्षणों को कार्य समाप्ति के बाद के निरीक्षणों तक स्थगित करें"],"solution":"Safety tests skip karna risky hai — sahi solution hai safety aur construction work ko parallel schedule karna, taaki deadline bhi mile aur safety bhi compromise na ho."},"en":{"prompt":["There is heavy pressure to meet a construction deadline. Some project supervisors suggest skipping certain safety tests to speed up the process. What is the right decision?"],"options":["Skip safety tests to finish faster","Only perform mandatory safety tests","Schedule safety and construction work in parallel","Postpone safety tests until after work is completed"],"solution":"Skipping safety tests is risky — the right solution is scheduling safety checks and construction work in parallel, so the deadline is met without compromising safety."},"answer":2},{"qn":165,"hi":{"prompt":["एक व्यक्ति बीमार है और उसे चिकित्सा की आवश्यकता है, लेकिन वह डॉक्टर से मिलने से इनकार करता है। परिवार के सदस्य को क्या करना चाहिए?"],"options":["उन्हें जाने के लिए मजबूर करें","उनके निर्णय का सम्मान करें","उन्हें तार्किक रूप से समझाएं","उनकी समस्या को नज़रअंदाज़ करें"],"solution":"Family member ko doctor se milne se mana kar raha bimar vyakti ko logically samjhana sahi tarika hai, force ya ignore nahi."},"en":{"prompt":["A person is sick and needs medical care but refuses to see a doctor. What should the family member do?"],"options":["Force them to go","Respect their decision","Explain it to them logically","Ignore their problem"],"solution":"When a sick family member refuses to see a doctor, explaining it to them logically is the right approach, not forcing or ignoring them."},"answer":2}],"set12":[{"qn":166,"hi":{"prompt":["आप अपने सहपाठी के बारे में अफवाह सुनते हैं। आपको क्या करना चाहिए?"],"options":["अफवाह फैलाएं","प्रतिक्रिया देने से पहले तथ्यों की पुष्टि करें","बिना किसी सवाल के इस पर विश्वास करें","उस व्यक्ति से बात करने से बचें"],"solution":"Rumour sunte hi react karne se pehle facts confirm karna sabse responsible action hai."},"en":{"prompt":["You hear a rumor about your classmate. What should you do?"],"options":["Spread the rumor","Verify the facts before reacting","Believe it without question","Avoid talking to that person"],"solution":"On hearing a rumor, verifying the facts before reacting is the most responsible action."},"answer":1},{"qn":167,"hi":{"prompt":["एक उम्मीदवार के पास दो प्रकार की समस्याओं को हल करने के लिए 30 मिनट हैं: टाइप A प्रत्येक 2 अंक के लायक, हल करने में आसान। टाइप B प्रत्येक 5 अंक के लायक, हल करने में अधिक समय लगता है। यदि उम्मीदवार अधिकतम अंक प्राप्त करना चाहता है, तो उसे किस प्रकार का प्रयास पहले करना चाहिए, यदि टाइप A की समस्याओं को जल्दी से हल किया जा सकता है?"],"options":["टाइप A","टाइप B","दोनों का मिश्रण हल करें","प्रकार A को पूरी तरह छोड़ें"],"solution":"Time-limited mein max score ke liye mix strategy best hai: pehle easy Type A questions jaldi solve karo phir bache time me Type B karo — dono type attempt karke marks maximize karna."},"en":{"prompt":["A candidate has 30 minutes to solve two types of problems: Type A worth 2 marks each, easy to solve. Type B worth 5 marks each, more time-consuming. If the candidate wants to maximize their score, and Type A problems can be solved quickly, which type should they attempt first?"],"options":["Type A","Type B","Solve a mix of both","Skip Type A entirely"],"solution":"With limited time, the best strategy for maximizing score is a mixed approach: quickly solve the easy Type A questions first, then use the remaining time for Type B — attempting both types maximizes marks."},"answer":2},{"qn":168,"hi":{"prompt":["एक ठेकेदार पर परियोजना को जल्दी पूरा करने का दबाव होता है, लेकिन निर्माण में तेज़ी लाने से निम्न गुणवत्ता वाली फिनिशिंग हो सकती है और बाद में फिर से काम करना पड़ सकता है। ठेकेदार को क्या निर्णय लेना चाहिए?"],"options":["काम में तेजी लाने के लिए सस्ती सामग्री का उपयोग करें","गैर-महत्वपूर्ण सौंदर्यशास्त्र पर समझौता","परियोजना के मध्य में गुणवत्ता नियंत्रण जांच शामिल करें","समय बचाने के लिए सुरक्षा मानकों में कटौती करें"],"solution":"Quality vs speed tradeoff me sabse balanced solution hai project ke beech me quality control checks include karna, safety/material compromise nahi."},"en":{"prompt":["A contractor is under pressure to complete a project quickly, but rushing construction could lead to poor-quality finishing and rework later. What decision should the contractor make?"],"options":["Use cheaper materials to speed up work","Compromise on non-critical aesthetics","Include quality control checks midway through the project","Cut safety standards to save time"],"solution":"In the quality-versus-speed tradeoff, the most balanced solution is including quality control checks midway through the project, not compromising materials or safety."},"answer":2},{"qn":169,"hi":{"prompt":["आप एक बच्चे को पार्क में अकेला रोते हुए देखते हैं। सबसे अच्छा कदम क्या है?"],"options":["तुरंत पुलिस को बुलाएं","बच्चे से पूछें कि क्या हुआ","बच्चे को अनदेखा करें","परेशानी से बचने के लिए दूर चले जाएं"],"solution":"Akela rota hua bachcha dekh kar sahi pehla step use pooch lena hai ki kya hua, seedha police call karna premature ho sakta hai jab tak details na pata ho."},"en":{"prompt":["You see a child crying alone in a park. What is the best step?"],"options":["Immediately call the police","Ask the child what happened","Ignore the child","Walk away to avoid trouble"],"solution":"On seeing a child crying alone, the right first step is asking what happened — calling the police immediately may be premature before knowing the details."},"answer":1},{"qn":170,"hi":{"prompt":["एक छात्र को लगातार स्कूल में धमकाया जा रहा है। एक जिम्मेदार सहपाठी को क्या करना चाहिए?"],"options":["स्थिति को नज़रअंदाज़ करें","उनका समर्थन और मदद करें","धमकाने में शामिल हों","परेशानी से बचने के लिए उनसे बचें"],"solution":"Bullied student ka responsible classmate support aur help karta hai, ignore ya avoid nahi."},"en":{"prompt":["A student is being consistently bullied at school. What should a responsible classmate do?"],"options":["Ignore the situation","Support and help them","Join in the bullying","Avoid them to stay out of trouble"],"solution":"A responsible classmate supports and helps a bullied student, rather than ignoring or avoiding them."},"answer":1},{"qn":171,"hi":{"prompt":["एक ठेकेदार निर्माण परियोजना के बीच में है और देखता है कि काम पीछे चल रहा है। क्लाइंट ने जोर दिया है कि इमारत को सभी सुरक्षा नियमों और गुणवत्ता मानकों को पूरा करना चाहिए, भले ही पूरा होने में थोड़ी देरी हो जाए। ठेकेदार को क्या निर्णय लेना चाहिए?"],"options":["काम में तेजी लाने के लिए सस्ते माल का उपयोग करना","गैर-महत्वपूर्ण सौंदर्यशास्त्र से समझौता करना","परियोजना के मध्य में गुणवत्ता नियंत्रण जाँच को शामिल करना","समय बचाने के लिए सुरक्षा मानकों में कोताही बरतना"],"solution":"Safety/quality standards maintain karte hue thodi delay acceptable hai — sahi decision mid-project quality control checks include karna hai."},"en":{"prompt":["A contractor is midway through a construction project and sees that work is running behind. The client has insisted the building must meet all safety regulations and quality standards, even if completion is slightly delayed. What decision should the contractor make?"],"options":["Use cheaper materials to speed up work","Compromise on non-critical aesthetics","Include quality control checks midway through the project","Cut corners on safety standards to save time"],"solution":"Since a slight delay is acceptable in order to maintain safety and quality standards, the right decision is including quality control checks midway through the project."},"answer":2},{"qn":172,"hi":{"prompt":["एक उम्मीदवार को उच्च-मात्रा वाले कार्य को संभालने के लिए तीन रणनीतियाँ दी जाती हैं: A) 80% कार्य त्रुटिरहित पूरा करें, 20% अधूरा रहे। B) 100% कार्य पूरा करें लेकिन कुछ छोटी-मोटी त्रुटियों के साथ। C) केवल 50% कार्य पूरा करें लेकिन पूर्ण सटीकता के साथ। यदि प्रदर्शन मूल्यांकन में छोटी-मोटी गलतियों पर पूर्ण कार्य कवरेज को प्राथमिकता दी जाती है, तो कौन सी रणनीति चुनी जानी चाहिए?"],"options":["रणनीति A","रणनीति B","रणनीति C","दी गई जानकारी से यह निर्धारित नहीं किया जा सकता है"],"solution":"Performance evaluation me full task coverage ko minor errors se zyada priority di ja rahi hai to Strategy B (100% completion with minor errors) chunna sahi hai."},"en":{"prompt":["A candidate is given three strategies for handling a high-volume task: A) Complete 80% of the work error-free, leaving 20% undone. B) Complete 100% of the work but with some minor errors. C) Complete only 50% of the work but with full accuracy. If the performance evaluation prioritizes full task coverage over minor mistakes, which strategy should be chosen?"],"options":["Strategy A","Strategy B","Strategy C","This cannot be determined from the given information"],"solution":"Since the evaluation prioritizes full task coverage over minor errors, choosing Strategy B (100% completion with minor errors) is correct."},"answer":1},{"qn":173,"hi":{"prompt":["इंजीनियरिंग टीम के सामने एक निश्चित बजट के साथ एक सख्त समय-सीमा है। परियोजना अनुसूची को अतिरिक्त संसाधनों से लाभ होगा, लेकिन कोई अतिरिक्त धनराशि उपलब्ध नहीं है। टीम को क्या करना चाहिए?"],"options":["अस्थायी श्रम को काम पर रखने के लिए मौजूदा बजट को पुनः आवंटित करना","तेज़, उच्च-गुणवत्ता वाले उपकरण किराए पर लेने में निवेश करना","छूट या तेज़ डिलीवरी के लिए आपूर्तिकर्ताओं के साथ बातचीत करना","केवल महत्वपूर्ण कार्यों के लिए बजट आवंटन को प्राथमिकता देना"],"solution":"Extra budget nahi hai to sabse practical kadam critical tasks ke liye budget allocation ko prioritize karna hai."},"en":{"prompt":["An engineering team faces a strict deadline with a fixed budget. The project schedule would benefit from extra resources, but no additional funds are available. What should the team do?"],"options":["Reallocate the existing budget to hire temporary labor","Invest in renting faster, higher-quality equipment","Negotiate with suppliers for discounts or faster delivery","Prioritize budget allocation for only the critical tasks"],"solution":"With no extra budget available, the most practical step is prioritizing budget allocation for the critical tasks."},"answer":3},{"qn":174,"hi":{"prompt":["बस से यात्रा करते समय, आप देखते हैं कि एक सीट के नीचे एक लावारिस बैग रखा हुआ है। आप क्या करेंगे?"],"options":["बैग खोलेंगे और उसकी सामग्री की जांच करेंगे","बस कर्मचारियों या अधिकारियों को तुरंत सूचित करेंगे","बैग को अनदेखा करेंगे और उसे वहीं छोड़ देंगे","बैग को अपने साथ ले जाएंगे"],"solution":"Bus me unattended bag dekh kar turant bus staff/authorities ko inform karna sahi safety-first step hai, khud kholna dangerous ho sakta hai."},"en":{"prompt":["While traveling on a bus, you notice an unattended bag left under a seat. What will you do?"],"options":["Open the bag and check its contents","Immediately inform bus staff or authorities","Ignore the bag and leave it there","Take the bag with you"],"solution":"On seeing an unattended bag on a bus, immediately informing bus staff or authorities is the right safety-first step — opening it yourself could be dangerous."},"answer":1},{"qn":175,"hi":{"prompt":["यदि किसी मित्र को परीक्षा में नकल करते हुए पकड़ा जाता है, तो सबसे अच्छी कार्रवाई क्या है?"],"options":["इसे अनदेखा करें","शिक्षक को सूचित करें","उन्हें पढ़ाई करने के लिए प्रोत्साहित करें","नकल करने में उनके साथ शामिल हो जाएं"],"solution":"Dost cheating karte pakda gaya to sabse balanced response unhe study karne ke liye encourage karna hai (bina teacher ko turant bataye ya ignore kiye)."},"en":{"prompt":["If a friend is caught cheating in an exam, what is the best action?"],"options":["Ignore it","Inform the teacher","Encourage them to study","Join them in cheating"],"solution":"When a friend is caught cheating, the most balanced response is encouraging them to study — rather than immediately reporting to the teacher or ignoring it."},"answer":2},{"qn":176,"hi":{"prompt":["आपका दोस्त शराब पीने के बाद गाड़ी चलाने वाला है। आपको क्या करना चाहिए?"],"options":["उन्हें जाने दें","उनकी चाबियां ले लें और उन्हें रोकें","मौज-मस्ती के लिए उनके साथ शामिल हों","स्थिति को नजरअंदाज करें"],"solution":"Drunk driving karne wale dost se chaabi le lo aur unhe rokdo — ye sabse responsible life-saving step hai."},"en":{"prompt":["Your friend is about to drive after drinking alcohol. What should you do?"],"options":["Let them go","Take their keys and stop them","Join them for fun","Ignore the situation"],"solution":"Taking the keys from a drunk-driving friend and stopping them is the most responsible, life-saving step."},"answer":1},{"qn":177,"hi":{"prompt":["एक इंजीनियर को समय से पहले निर्माण पूरा करने का आदेश दिया गया है लेकिन निर्माण के अनुसार इसमें अधिक समय लगेगा। उसे क्या करना चाहिए?"],"options":["बिना समायोजन के निर्माण में तेजी लाने का प्रयास करें","अतिरिक्त संसाधन या तकनीक का अनुरोध करें","हितधारकों के साथ संशोधित समय-सीमा पर बातचीत करें","एक चरणबद्ध या आंशिक पूर्णता रणनीति का सुझाव दें"],"solution":"Deadline construction reality se match nahi karti to extra resources/technology request karna practical solution hai."},"en":{"prompt":["An engineer has been ordered to complete construction ahead of schedule, but according to construction realities, it will take longer. What should he do?"],"options":["Try to speed up construction without any adjustments","Request additional resources or technology","Negotiate a revised timeline with stakeholders","Suggest a phased or partial completion strategy"],"solution":"Since the deadline doesn't match construction reality, requesting extra resources or technology is the practical solution."},"answer":1},{"qn":178,"hi":{"prompt":["आपके गाँव में एक विवाह समारोह के दौरान, आपको पता चलता है कि यह बाल विवाह है। सबसे ज़िम्मेदार कदम क्या उठाया जाना चाहिए?"],"options":["स्थिति को नज़रअंदाज़ करें और चुपचाप चले जाएँ","परिवार का सामना करें और तुरंत समारोह रोक दें","बाल विवाह की सूचना अधिकारियों या बाल संरक्षण संगठनों को दें","चुप रहें, यह मानकर कि कोई और हस्तक्षेप करेगा"],"solution":"Child marriage dekh kar sabse responsible step authorities/child protection organization ko report karna hai."},"en":{"prompt":["During a wedding ceremony in your village, you learn it is a child marriage. What is the most responsible step to take?"],"options":["Ignore the situation and quietly leave","Confront the family and stop the ceremony immediately","Report the child marriage to authorities or a child protection organization","Stay silent, assuming someone else will intervene"],"solution":"On learning of a child marriage, the most responsible step is reporting it to authorities or a child protection organization."},"answer":2},{"qn":179,"hi":{"prompt":["आप एक साक्षात्कार के लिए देर से चल रहे हैं और किसी को मदद की ज़रूरत में देखते हैं। आपको क्या करना चाहिए?"],"options":["अनदेखा करें और साक्षात्कार के लिए दौड़ें","रुकें और मदद करें","साक्षात्कार की ओर बढ़ते हुए मदद के लिए बुलाएँ","साक्षात्कार रद्द करें"],"solution":"Interview ke liye late ho rahe ho lekin koi help chahiye dikh raha ho to rukkar madad karna zyada important human value hai."},"en":{"prompt":["You're running late for an interview and see someone in need of help. What should you do?"],"options":["Ignore it and rush to the interview","Stop and help","Call for help while continuing toward the interview","Cancel the interview"],"solution":"Even while running late for an interview, stopping to help someone in need is the more important human value."},"answer":1},{"qn":180,"hi":{"prompt":["एक पुस्तकालय में, आप देखते हैं कि आपका मित्र बिना अनुमति के एक पुस्तक ले रहा है। आपको क्या कार्रवाई करनी चाहिए?"],"options":["स्थिति को अनदेखा करें और दिखावा करें कि आपने कुछ नहीं देखा","अपने दोस्त का दूसरों के सामने सामना करें और हंगामा करें","घटना की सूचना पुस्तकालय अध्यक्ष या कर्मचारियों को निजी तौर पर दें","खुद किताब चुराकर अपने दोस्त की मदद करें"],"solution":"Dost bina permission book le raha ho library se to isse privately librarian/staff ko report karna sahi hai — public confrontation ya khud chori me help nahi."},"en":{"prompt":["In a library, you notice your friend taking a book without permission. What action should you take?"],"options":["Ignore the situation and pretend you saw nothing","Confront your friend in front of others and make a scene","Privately report the incident to the librarian or staff","Help your friend by stealing a book yourself"],"solution":"If a friend takes a book from the library without permission, privately reporting it to the librarian or staff is correct — not public confrontation or helping them steal."},"answer":2}],"set13":[{"qn":181,"hi":{"prompt":["आप अपने पड़ोसी के घर से धुआं निकलते देखते हैं। आप क्या करेंगे?"],"options":["इसे अनदेखा करें","तुरंत अग्निशमन विभाग को बुलाएं","प्रतीक्षा करें और देखें कि क्या धुआं बढ़ता है","जांच के लिए दरवाजा खटखटाएं"],"solution":"Padosi ke ghar se dhuan dekh kar turant fire department ko call karna sahi emergency response hai."},"en":{"prompt":["You see smoke coming from your neighbor's house. What will you do?"],"options":["Ignore it","Immediately call the fire department","Wait and see if the smoke increases","Knock on the door to check"],"solution":"On seeing smoke from a neighbor's house, immediately calling the fire department is the right emergency response."},"answer":1},{"qn":182,"hi":{"prompt":["परीक्षा कक्ष में, आपको पता चलता है कि आपका दोस्त नकल कर रहा है। सबसे ज़िम्मेदार कार्य क्या है?"],"options":["इसे अनदेखा करें; यह आपका काम नहीं है","निरीक्षक के सामने अपने दोस्त का सामना करें","परीक्षा निरीक्षक या अधिकारियों को घटना की रिपोर्ट करें","अपने दोस्त को नकल करने में मदद करें ताकि दोनों को अच्छे अंक मिलें"],"solution":"Exam me dost cheating karte dekha to responsible action exam invigilator/authorities ko report karna hai."},"en":{"prompt":["In the exam hall, you notice your friend cheating. What is the most responsible action?"],"options":["Ignore it; it's not your business","Confront your friend in front of the invigilator","Report the incident to the exam invigilator or authorities","Help your friend cheat so both of you get good marks"],"solution":"On seeing a friend cheat during an exam, the responsible action is reporting the incident to the invigilator or authorities."},"answer":2},{"qn":183,"hi":{"prompt":["आप दोस्तों के साथ वीकेंड रोड ट्रिप की योजना बना रहे हैं, लेकिन जाने से एक दिन पहले आपकी कार का चेक इंजन लाइट जल जाता है। आपने पहले ही एक गैर-वापसी योग्य कैंपसाइट बुक कर ली है। आपको क्या करना चाहिए?"],"options":["किसी भी तरह कार चलाएं और उम्मीद करें कि यह यात्रा के लिए ठीक रहेगी","यात्रा रद्द करें और कैंपसाइट शुल्क गंवा दें","आज ही कार को मैकेनिक के पास ले जाएं और यदि समय पर ठीक नहीं हो पाती है तो कार किराए पर लें","किसी दोस्त से अपनी कार चलाने के लिए कहें और लागत साझा करें"],"solution":"Car problem se pehle mechanic ko dikhao aur agar time par theek na ho to rent car lo — trip cancel karne se better hai practical alternative dhoondna."},"en":{"prompt":["You are planning a weekend road trip with friends, but the day before leaving, your car's check-engine light comes on. You've already booked a non-refundable campsite. What should you do?"],"options":["Drive anyway and hope it's fine for the trip","Cancel the trip and lose the campsite fee","Take the car to a mechanic today and rent a car if it isn't fixed in time","Ask a friend to drive their car and split the cost"],"solution":"Getting the car checked by a mechanic first and renting a car if it isn't fixed in time is better than cancelling the trip — a practical alternative."},"answer":2},{"qn":184,"hi":{"prompt":["प्रोफेसर के चयन के मानदंड: (a) न्यूनतम 60% अंकों के साथ B.Sc., (b) न्यूनतम आयु 22 वर्ष, (c) X कक्षा में कम से कम 50%, (d) डिप्लोमा/डिग्री/PG डिग्री, (e) न्यूनतम 1 वर्ष कार्य अनुभव। अपवाद: I. यदि (e) छोड़कर, X कक्षा और PG में 60%+ हो। II. यदि (a) छोड़कर, 2 वर्ष अनुभव हो तो स्थानापन्न शिक्षक चुना जाएगा। साहिल: 66% B.Sc., 60% M.Sc., 1.5 वर्ष अनुभव, 24 वर्ष, X में 75% अंक। क्या कार्रवाई हो?"],"options":["स्थानापन्न शिक्षक के रूप में चयनित","प्राचार्य को प्रेषित","कम अनुभव के कारण अस्वीकृत","कॉलेज प्रोफेसर के रूप में चयनित"],"solution":"Eligibility: Sahil ke paas (a)66% B.Sc✓ (b)24yrs✓ (c) X me 75%✓ (d) PG hai✓ (e) 1.5yr exp✓ — sab base criteria pure hote hain (exception clauses ki zaroorat hi nahi), isliye seedha College Professor select hoga."},"en":{"prompt":["Professor selection criteria: (a) B.Sc. with at least 60% marks, (b) minimum age 22, (c) at least 50% in Class X, (d) Diploma/Degree/PG degree, (e) minimum 1 year work experience. Exceptions: I. If (e) is not met, but Class X and PG scores are 60%+, refer as a substitute teacher. II. If (a) is not met but there are 2 years of experience, a substitute teacher will be chosen. Case: Sahil: 66% B.Sc., 60% M.Sc., 1.5 years experience, 24 years old, 75% marks in Class X. What action should be taken?"],"options":["Selected as a substitute teacher","Referred to the principal","Rejected due to insufficient experience","Selected as a college professor"],"solution":"Sahil meets all base criteria: (a) 66% B.Sc. ✓ (b) 24 years ✓ (c) 75% in Class X ✓ (d) has a PG ✓ (e) 1.5 years experience ✓ — since all base criteria are met, no exception clause is needed, and he is directly selected as a college professor."},"answer":3},{"qn":185,"hi":{"prompt":["निम्नलिखित में से कौन सी क्रिया सामाजिक परिस्थिति में सर्वोत्तम निर्णय दर्शाती है?"],"options":["भारी बैग ले जा रहे एक बुजुर्ग व्यक्ति की मदद करना","किसी ऐसे व्यक्ति पर चिल्लाना जो आपसे टकरा गया हो","गुमनाम रूप से ऑनलाइन नकारात्मक टिप्पणियाँ पोस्ट करना","सार्वजनिक स्थान पर रोते हुए बच्चे को नज़रअंदाज़ करना"],"solution":"Bhari bag le jaate bujurg ki madad karna social situation me best judgment dikhata hai."},"en":{"prompt":["Which of the following actions shows the best judgment in a social situation?"],"options":["Helping an elderly person carrying heavy bags","Shouting at someone who bumped into you","Anonymously posting negative comments online","Ignoring a crying child in a public place"],"solution":"Helping an elderly person carrying heavy bags demonstrates the best judgment in a social situation."},"answer":0},{"qn":186,"hi":{"prompt":["निशांत के पास 68% बीएससी है, एम.एससी. का रिजल्ट आना बाकी है, 3 साल का शिक्षण अनुभव है, 27 साल का है, प्रोबेशन के लिए तैयार है। क्या करें?"],"options":["परिणाम का इंतजार करें फिर निर्णय लें","अपूर्ण पीजी के कारण अस्वीकृत","प्रिंसिपल से संपर्क करें","निशांत का चयन करें"],"solution":"M.Sc result abhi pending hai (incomplete PG) to final decision lene se pehle result ka wait karna sahi hai."},"en":{"prompt":["Nishant has 68% in B.Sc., his M.Sc. result is still pending, has 3 years of teaching experience, is 27 years old, and is ready for probation. What should be done?"],"options":["Wait for the result, then decide","Rejected due to incomplete PG","Contact the principal","Select Nishant"],"solution":"Since the M.Sc. result is still pending (incomplete PG), it is correct to wait for the result before making a final decision."},"answer":0},{"qn":187,"hi":{"prompt":["रोहित अपनी पत्नी के 40वें जन्मदिन का जश्न मनाने के लिए एक विशेष रात्रिभोज की योजना बना रहा है। वह आरामदायक, अनौपचारिक समारोहों का आनंद लेती है और उसे फैंसी डाइनिंग से ज़्यादा भारतीय स्ट्रीट फूड पसंद है। कौन सा रेस्तराँ उसके लिए सबसे उपयुक्त होगा?"],"options":["स्पाइस सिम्फनी - आधुनिक माहौल के साथ समकालीन भारतीय फ्यूजन व्यंजन","तंदूरी ट्रेल्स - परिष्कृत सजावट के साथ उत्तर भारतीय कबाब और करी","रॉयल रसोई - महल जैसे वातावरण में पारंपरिक राजस्थानी शाही व्यंजन","चाट चौक - पानी पुरी, पाव भाजी और आलू टिक्की जैसे लोकप्रिय स्ट्रीट फूड, आरामदायक और जीवंत माहौल"],"solution":"Biwi ko casual street-food pasand hai, fancy dining nahi — isliye Chaat Chowk (street food, casual vibe) sabse suitable restaurant hai."},"en":{"prompt":["Rohit is planning a special dinner to celebrate his wife's 40th birthday. She enjoys relaxed, informal gatherings and prefers Indian street food over fancy dining. Which restaurant would suit her best?"],"options":["Spice Symphony — contemporary Indian fusion cuisine with a modern ambiance","Tandoori Trails — North Indian kebabs and curries with sophisticated decor","Royal Rasoi — traditional Rajasthani royal cuisine in a palace-like setting","Chaat Chowk — popular street food like pani puri, pav bhaji, and aloo tikki, with a casual, lively atmosphere"],"solution":"Since his wife likes casual street food, not fancy dining, Chaat Chowk (street food, casual vibe) is the most suitable restaurant."},"answer":3},{"qn":188,"hi":{"prompt":["कार्तिक: 64% B.Sc., रसायन विज्ञान में M.Sc., कोई शिक्षण अनुभव नहीं, 23 वर्ष, प्रोबेशनरी भूमिकाओं के लिए तैयार। पद के मानदंड: न्यूनतम आयु 24, अधिकतम 30, न्यूनतम M.Sc. रसायन विज्ञान, न्यूनतम 2 वर्ष अनुभव, प्रोबेशनरी भूमिकाएं 5 वर्ष से कम अनुभव वालों के लिए, B.Sc. में न्यूनतम 65%। कार्तिक की पात्रता के बारे में सबसे उपयुक्त निर्णय क्या है?"],"options":["उम्मीदवार का चयन किया जाना है","जानकारी अपर्याप्त है","उम्मीदवार का चयन नहीं किया जाना है","मामला प्रिंसिपल को भेजा जाना है"],"solution":"Eligibility: Kartik ki age 23 hai jabki min age 24 chahiye — sirf ek criterion fail hone se hi Kartik select nahi hoga."},"en":{"prompt":["Kartik: 64% B.Sc., M.Sc. in Chemistry, no teaching experience, 23 years old, ready for probationary roles. Position criteria: minimum age 24, maximum 30, minimum M.Sc. Chemistry, minimum 2 years experience, probationary roles open to those with less than 5 years experience, minimum 65% in B.Sc. What is the most appropriate decision about Kartik's eligibility?"],"options":["The candidate should be selected","Information is insufficient","The candidate should not be selected","The case should be referred to the principal"],"solution":"Kartik is 23 years old while the minimum age required is 24 — this single failed criterion alone makes him ineligible."},"answer":2},{"qn":189,"hi":{"prompt":["गणित शिक्षक चयन मानदंड: न्यूनतम 65% B.Sc., M.Sc. गणित/विज्ञान, कम से कम 2 वर्ष शिक्षण अनुभव, आयु 23-30, बिना नोटिस अवधि के तुरंत शामिल होने में सक्षम। मीरा: 70% B.Sc., M.Sc. पूरी, 3 वर्ष गणित पढ़ाने का अनुभव, 25 वर्ष, प्रोबेशन के लिए तैयार। क्या करना चाहिए?"],"options":["मीरा को उप प्राचार्य के पास भेजा जाना चाहिए","मीरा को अस्वीकार किया जाएगा","मीरा को सीधे चुना जाएगा","मीरा को प्रिंसिपल के पास भेजा जाना चाहिए"],"solution":"Meera saare criteria pura karti hai (70%>65%, MSc math, 3yr exp>2yr, age 25 in range, ready immediate) — isliye seedha select hogi, koi exception clause trigger nahi hota."},"en":{"prompt":["Math teacher selection criteria: minimum 65% B.Sc., M.Sc. in Mathematics/Science, at least 2 years teaching experience, age 23-30, able to join immediately without a notice period. Meera: 70% B.Sc., completed M.Sc., 3 years of experience teaching mathematics, 25 years old, ready for probation. What should be done?"],"options":["Meera should be referred to the vice-principal","Meera will be rejected","Meera will be directly selected","Meera should be referred to the principal"],"solution":"Meera meets all criteria (70%>65%, M.Sc. Math, 3yr experience>2yr required, age 25 within range, ready to join immediately) — so she is directly selected, with no exception clause triggered."},"answer":2},{"qn":190,"hi":{"prompt":["Requirements: Mathematics min 65%, Age 23-30, Data Analytics Certificate, 2 years analytical experience. Special: If only 1 year experience but Master's in Data Science, refer to Project Manager. Case: Meera, 26, B.Sc. Statistics 70%, certificate course done, Master's in Data Science, only 1 year experience. What should be done?"],"options":["परियोजना प्रबंधक से संपर्क करे","उम्मीदवार का चयन करें","मानव संसाधन विभाग से संपर्क करें","उम्मीदवार को अस्वीकार करें"],"solution":"Meera ke paas sirf 1 year experience hai (2 chahiye) lekin Data Science Master's hai — jo exactly special clause trigger karta hai: Project Manager se contact karna."},"en":{"prompt":["Requirements: Mathematics minimum 65%, Age 23-30, Data Analytics Certificate, 2 years analytical experience. Special clause: If only 1 year experience but the candidate has a Master's in Data Science, refer to the Project Manager. Case: Meera, 26, B.Sc. Statistics 70%, certificate course done, Master's in Data Science, only 1 year experience. What should be done?"],"options":["Contact the Project Manager","Select the candidate","Contact the HR department","Reject the candidate"],"solution":"Meera has only 1 year of experience (2 required) but holds a Master's in Data Science — this exactly triggers the special clause to contact the Project Manager."},"answer":0},{"qn":191,"hi":{"prompt":["आप एक व्यस्त सुपरमार्केट में देखते हैं कि एक व्यक्ति जल्दी से एक छोटी, सस्ती वस्तु को बिना स्कैन किए अपने बैग में डाल रहा है। स्टोर में कर्मचारियों की कमी है। सबसे नैतिक और जिम्मेदार कार्य क्या है?"],"options":["व्यक्ति का सीधे सामना करें और भुगतान की मांग करें","इस घटना को नज़रअंदाज़ करें","तस्वीर या वीडियो लें, फिर सोशल मीडिया पर पोस्ट करें","खामोशी से स्टोर के किसी कर्मचारी या प्रबंधक को ढूंढकर बताएं"],"solution":"Chori dekh kar directly confront ya social media post karne ke bajaye chupchap store employee/manager ko inform karna sabse safe aur effective action hai."},"en":{"prompt":["You notice at a busy supermarket that someone is quickly slipping a small, inexpensive item into their bag without scanning it. The store is understaffed. What is the most ethical and responsible action?"],"options":["Directly confront the person and demand payment","Ignore the incident","Take a photo or video, then post it on social media","Quietly find a store employee or manager and inform them"],"solution":"On seeing theft, quietly informing a store employee or manager is the safest and most effective action, rather than confronting directly or posting on social media."},"answer":3},{"qn":192,"hi":{"prompt":["Requirements: Project Management 65%+, min 10 years experience (3 as team lead), age max 42, handled 2+ full-cycle govt projects. Special: If no MBA but 12+ years incl. 2 years abroad and led 3+ projects, refer Advisory Board. If only 1 project but other conditions met, refer Infrastructure Commission. Case: Sneha, 78% B.Tech Civil, no MBA, 13 years experience (3 abroad), led 4 state govt projects. What should be done?"],"options":["इंफ्रास्ट्रक्चर आयोग को भेजें","सलाहकार बोर्ड को भेजें","अभ्यर्थी को अस्वीकार करें","उम्मीदवार का चयन करें"],"solution":"Sneha: no MBA hai lekin 13yrs exp (2yr abroad included) aur 4 govt projects lead kiye — ye exactly special clause 'no MBA but 12+ yrs incl 2yr abroad + 3+ projects' match karta hai, isliye Advisory Board ko refer karna hai."},"en":{"prompt":["Requirements: Project Management 65%+, minimum 10 years experience (3 as team lead), maximum age 42, handled 2+ full-cycle government projects. Special clause: If no MBA but 12+ years including 2 years abroad and led 3+ projects, refer to the Advisory Board. If only 1 project but other conditions are met, refer to the Infrastructure Commission. Case: Sneha, 78% B.Tech Civil, no MBA, 13 years experience (3 abroad), led 4 state government projects. What should be done?"],"options":["Refer to the Infrastructure Commission","Refer to the Advisory Board","Reject the candidate","Select the candidate"],"solution":"Sneha has no MBA but has 13 years of experience (including 2+ years abroad) and led 4 government projects — this exactly matches the special clause 'no MBA but 12+ years including 2 years abroad plus 3+ projects', so she should be referred to the Advisory Board."},"answer":1},{"qn":193,"hi":{"prompt":["आप ऑनलाइन फ़ोरम ब्राउज़ करते समय गलती से एक सार्वजनिक रूप से सुलभ क्लाउड स्टोरेज फ़ोल्डर के लिंक पर पहुँच जाते हैं, जिसमें सैकड़ों संवेदनशील व्यक्तिगत दस्तावेज़ हैं। सबसे नैतिक और जिम्मेदार कार्य क्या है?"],"options":["तत्काल प्लेटफ़ॉर्म एडमिनिस्ट्रेटर या साइबर सुरक्षा प्राधिकरण को रिपोर्ट करें और आगे एक्सेस से बचें","फ़ोल्डर को पूरी तरह से अनदेखा करें","फ़ाइलें डाउनलोड करें और व्यक्तियों से सीधे संपर्क करें","लिंक को सोशल मीडिया पर सार्वजनिक रूप से साझा करें"],"solution":"Sensitive documents ka accidental link mile to platform admin/cybersecurity authority ko report karna sabse ethical responsible step hai, download ya share karna nahi."},"en":{"prompt":["While browsing an online forum, you accidentally come across a link to a publicly accessible cloud storage folder containing hundreds of sensitive personal documents. What is the most ethical and responsible action?"],"options":["Immediately report it to the platform administrator or a cybersecurity authority and avoid further access","Completely ignore the folder","Download the files and contact the individuals directly","Publicly share the link on social media"],"solution":"On accidentally finding a link to sensitive documents, reporting it to the platform administrator or a cybersecurity authority is the most ethical, responsible step — not downloading or sharing it."},"answer":0},{"qn":194,"hi":{"prompt":["आपको अपनी स्कूल की लाइब्रेरी में एक बटुआ मिलता है। सबसे उचित कार्रवाई क्या होगी?"],"options":["इसे अपने पास रखें और किसी के दावा करने का इंतजार करें","पैसे ले लें और बटुआ छोड़ दें","इसे लाइब्रेरियन या अथॉरिटी को सौंप दें","इसे नजरअंदाज करें"],"solution":"School library me wallet milne par librarian/authority ko handover karna sahi action hai."},"en":{"prompt":["You find a wallet in your school library. What would be the most appropriate action?"],"options":["Keep it and wait for someone to claim it","Take the money and leave the wallet","Hand it over to the librarian or authorities","Ignore it"],"solution":"On finding a wallet in the school library, handing it over to the librarian or authorities is the right action."},"answer":2},{"qn":195,"hi":{"prompt":["सहायक प्रबंधक चयन मानदंड: कम से कम 65% के साथ MBA, आयु 26-32, न्यूनतम 2 वर्ष प्रबंधन अनुभव, अंग्रेजी और हिंदी में धाराप्रवाह। विशेष खंड: यदि भाषा को छोड़कर सभी आवश्यकताएं पूरी हों, तो भाषा दक्षता पैनल देखें। तरुण: 30 वर्ष, 70% MBA, 3 वर्ष अनुभव, अंग्रेजी में धाराप्रवाह लेकिन हिंदी में आत्मविश्वास नहीं। क्या किया जाना चाहिए?"],"options":["उम्मीदवार का चयन करें","उम्मीदवार को अस्वीकार करें","भाषा प्रवीणता पैनल देखें","प्रबंध निदेशक से संपर्क करें"],"solution":"Tarun ke sab criteria pure hain except Hindi confidence — language ko chhodkar sab match karta hai, isliye special clause trigger hoke Language Proficiency Panel dekhna hai."},"en":{"prompt":["Assistant Manager selection criteria: MBA with at least 65%, age 26-32, minimum 2 years management experience, fluent in English and Hindi. Special clause: If all requirements are met except language, refer to the Language Proficiency Panel. Tarun: 30 years old, 70% MBA, 3 years experience, fluent in English but not confident in Hindi. What should be done?"],"options":["Select the candidate","Reject the candidate","Refer to the Language Proficiency Panel","Contact the Managing Director"],"solution":"Tarun meets all criteria except Hindi confidence — since everything but language matches, the special clause is triggered, so refer to the Language Proficiency Panel."},"answer":2}],"set14":[{"qn":196,"hi":{"prompt":["इनमें से कौन सी कार्रवाई मित्र के साथ मतभेद से निपटने में खराब निर्णय को दर्शाती है?"],"options":["शांति से बात करके इसे सुलझाना","मित्र को हमेशा के लिए नज़रअंदाज़ करना","ठंडा होने में समय लेना","अपनी भावनाओं को व्यक्त करने के लिए पत्र लिखना"],"solution":"Dost ko hamesha ke liye ignore karna poor conflict-resolution judgment dikhata hai, baaki options (baat karna, cool down, likhna) healthy hain."},"en":{"prompt":["Which of the following actions shows poor judgment in handling a disagreement with a friend?"],"options":["Resolving it by talking calmly","Ignoring the friend forever","Taking time to cool down","Writing a letter to express your feelings"],"solution":"Ignoring a friend forever shows poor judgment in conflict resolution; the other options (talking it out, cooling down, writing a letter) are healthy approaches."},"answer":1},{"qn":197,"hi":{"prompt":["प्रियंका: 82% B.Sc., रसायन विज्ञान में M.Sc., 3 वर्ष अनुभव, 26 वर्ष। पद के मानदंड: न्यूनतम आयु 25, अधिकतम 30, न्यूनतम M.Sc. रसायन विज्ञान, न्यूनतम 2 वर्ष अनुभव, प्रोबेशनरी भूमिकाएं 5 वर्ष से कम अनुभव वालों के लिए खुली। प्रियंका की पात्रता के बारे में सबसे उपयुक्त निर्णय क्या है?"],"options":["प्रियंका आयु सीमा से अधिक होने के कारण पात्र नहीं हैं","प्रियंका इस पद के लिए योग्य हैं क्योंकि वह सभी मानदंडों को पूरा करती हैं","प्रियंका तभी पात्र होंगी जब वह प्रोबेशनरी भूमिका के लिए सहमत होंगी","प्रियंका अपर्याप्त अनुभव के कारण पात्र नहीं हैं"],"solution":"Priyanka ke sab criteria match: 82%B.Sc✓, MSc Chem✓, 3yr>2yr exp✓, age 26 (25-30)✓ — sab conditions pure hone se seedha eligible hai."},"en":{"prompt":["Priyanka: 82% B.Sc., M.Sc. in Chemistry, 3 years experience, 26 years old. Position criteria: minimum age 25, maximum 30, minimum M.Sc. Chemistry, minimum 2 years experience, probationary roles open to those with less than 5 years experience. What is the most appropriate decision about Priyanka's eligibility?"],"options":["Priyanka is not eligible because she exceeds the age limit","Priyanka is eligible for this position because she meets all criteria","Priyanka will only be eligible if she agrees to a probationary role","Priyanka is not eligible due to insufficient experience"],"solution":"Priyanka meets all criteria: 82% B.Sc. ✓, M.Sc. Chemistry ✓, 3 years experience > 2 years required ✓, age 26 (within 25-30) ✓ — since all conditions are met, she is directly eligible."},"answer":1},{"qn":198,"hi":{"prompt":["समीर के पास बीएससी में 67% अंक हैं और उसने एमएससी की पढ़ाई पूरी कर ली है। वह 31 साल का है और उसके पास 5 साल का अनुभव है। प्रोबेशन के लिए तैयार है।"],"options":["चयनित","अपर्याप्त डेटा","प्रिंसिपल से संपर्क करें","उप प्राचार्य से संपर्क करें"],"solution":"Sameer ki age 31 di gayi hai jo criteria range se bahar lag sakti hai, lekin exact age-limit criteria di hi nahi gayi hai passage me — isliye information insufficient decide karna sahi hai."},"en":{"prompt":["Sameer has 67% marks in B.Sc. and has completed his M.Sc. He is 31 years old and has 5 years of experience. He is ready for probation."],"options":["Selected","Insufficient data","Contact the principal","Contact the vice-principal"],"solution":"Sameer's age of 31 might fall outside the typical criteria range, but no exact age-limit criterion is given in this passage — so deciding that the information is insufficient is correct."},"answer":1},{"qn":199,"hi":{"prompt":["आपके पास तीन कार्य हैं: प्रोजेक्ट (3 दिनों में पूरा करना, ग्रेड का 50%), एक टीम मीटिंग (1 घंटे में), एक वैकल्पिक प्रश्नोत्तरी (आज रात को पूरा करना है)। आपको सबसे पहले क्या करना चाहिए?"],"options":["प्रोजेक्ट प्रारंभ करें","वैकल्पिक प्रश्नोत्तरी लें","टीम मीटिंग में भाग लें","सभी समय-सीमाओं की पुनः समीक्षा करें"],"solution":"Team meeting sabse jaldi (1 ghante me) hai aur immediate commitment hai — usse pehle attend karna time-sensitive priority hai, baaki tasks (project 3 din, quiz raat tak) ke paas zyada buffer hai."},"en":{"prompt":["You have three tasks: a project (due in 3 days, worth 50% of your grade), a team meeting (in 1 hour), and an optional quiz (due tonight). What should you do first?"],"options":["Start the project","Take the optional quiz","Attend the team meeting","Re-review all deadlines"],"solution":"The team meeting is the soonest (in 1 hour) and an immediate commitment — attending it first is the time-sensitive priority, since the other tasks (project due in 3 days, quiz due tonight) have more buffer."},"answer":2},{"qn":200,"hi":{"prompt":["आप एक टीम के मैनेजर हैं। आपके दो साथी क्लाइंट्स के सामने बहस में पड़ जाते हैं। आपको क्या करना चाहिए?"],"options":["कदाचार के लिए दोनों को नौकरी से निकाल दो","इसे नज़रअंदाज़ करें, यह कार्यस्थल पर सामान्य घटना है","तुरंत सबके सामने उन्हें डाँटें","शांतिपूर्वक बहस समाप्त करें, ग्राहकों से माफ़ी मांगें, और दोनों से अकेले में बात करें"],"solution":"Dono colleagues client ke saamne bahas karte hain to manager ka sahi kaam hai shanti se argument stop karna, client se maafi maangna, aur dono se alag me baat karna — professional damage-control."},"en":{"prompt":["You are a team manager. Two of your colleagues get into an argument in front of clients. What should you do?"],"options":["Fire both for misconduct","Ignore it; it's a normal workplace occurrence","Immediately scold them in front of everyone","Calmly stop the argument, apologize to the clients, and speak to both of them separately"],"solution":"When two colleagues argue in front of a client, the manager's right move is calmly stopping the argument, apologizing to the client, and speaking to each colleague privately — professional damage control."},"answer":3},{"qn":201,"hi":{"prompt":["आप व्यस्त समय में एक भीड़-भाड़ वाली सार्वजनिक बस में हैं। अगले स्टॉप पर, बैसाखी के सहारे एक बुजुर्ग व्यक्ति बस में चढ़ता है और सभी सीटें भरी हुई हैं। आपके आस-पास के लोग नजरें मिलाने से बचते दिखाई पड़ते हैं।"],"options":["जोर से पुकारें और पूछें कि क्या कोई बुजुर्ग व्यक्ति के लिए सीट छोड़ने को तैयार है","विनम्रतापूर्वक बुजुर्ग व्यक्ति को अपनी सीट देने की पेशकश करें","अपनी सीट पर बैठे रहें, यह मानकर कि कोई और सीट दे देगा","बस चालक को बताएं कि वहां एक बुजुर्ग व्यक्ति खड़ा है"],"solution":"Bujurg vyakti crutches ke saath khada hai to seat politely offer karna hi sahi civic/social action hai, chillakar poochna ya ignore karna nahi."},"en":{"prompt":["You are on a crowded public bus during rush hour. At the next stop, an elderly person on crutches boards, and all seats are taken. People around you seem to avoid eye contact."],"options":["Call out loudly and ask if anyone is willing to give up a seat for the elderly person","Politely offer your own seat to the elderly person","Stay seated, assuming someone else will offer a seat","Tell the bus driver that there's an elderly person standing"],"solution":"When an elderly person on crutches is standing, politely offering your own seat is the right civic and social action, not shouting out or ignoring it."},"answer":1},{"qn":202,"hi":{"prompt":["पात्रता: 60%+ B.Sc., M.Sc. उत्तीर्ण, आयु 28 वर्ष से कम (01-01-2017 को), पूर्व अनुभव को वरीयता। यदि अन्यथा योग्य लेकिन कोई अनुभव नहीं, तो प्रिंसिपल को भेजा जाएगा। नीरज: 65% B.Sc., M.Sc. पूरी, कोई कार्य अनुभव नहीं, 1 वर्ष प्रोबेशन के लिए तैयार, आयु 26 वर्ष। क्या निर्णय लिया जाना चाहिए?"],"options":["उम्मीदवार का चयन करें","उप प्राचार्य से संपर्क करें","जानकारी अपर्याप्त","प्रिंसिपल से संपर्क करें"],"solution":"Neeraj sab criteria pura karta hai lekin experience nahi hai — exactly ye special clause hai 'otherwise eligible but no experience → Principal ko refer karna'."},"en":{"prompt":["Eligibility: 60%+ B.Sc., M.Sc. passed, under 28 years old (as of 01-01-2017), prior experience preferred. If otherwise eligible but no experience, refer to the principal. Neeraj: 65% B.Sc., completed M.Sc., no work experience, ready for a 1-year probation, 26 years old. What decision should be made?"],"options":["Select the candidate","Contact the vice-principal","Information is insufficient","Refer to the principal"],"solution":"Neeraj meets all other criteria but has no experience — this exactly matches the special clause 'otherwise eligible but no experience → refer to the principal'."},"answer":3},{"qn":203,"hi":{"prompt":["आप अपने करीबी दोस्त के घर पर एक शाम की सभा में हैं, जहाँ आपका दोस्त एक पायरेटेड फिल्म चलाने का फैसला करता है और आपसे लैपटॉप कनेक्ट करने में मदद मांगता है। आप व्यक्तिगत रूप से पायरेसी का विरोध करते हैं लेकिन असहज स्थिति नहीं बनाना चाहते।"],"options":["सार्वजनिक रूप से मदद करने से इनकार करें और जोर से समझाएं कि पायरेसी गलत है","फिल्म देखें, लेकिन बाद में कॉपीराइट अधिकारियों को रिपोर्ट करें","विवेकपूर्ण तरीके से सेटअप में भाग लेने या फिल्म देखने से खुद को अलग कर लें","इसके साथ चलें और लैपटॉप कनेक्ट करने में मदद करें"],"solution":"Pirated film dekhne me discomfort hai to public confrontation ya secretly report karne ke bajaye politely setup se khud ko alag kar lena diplomatic solution hai."},"en":{"prompt":["You're at an evening gathering at a close friend's home, where your friend decides to play a pirated movie and asks you to help connect the laptop. You personally oppose piracy but don't want to create an awkward situation."],"options":["Publicly refuse to help and loudly explain that piracy is wrong","Watch the movie, but report it to copyright authorities afterward","Tactfully excuse yourself from helping with the setup or watching the movie","Go along with it and help connect the laptop"],"solution":"Since watching the pirated film is uncomfortable, tactfully excusing yourself from the setup rather than public confrontation or secretly reporting it is the diplomatic solution."},"answer":2},{"qn":204,"hi":{"prompt":["Requirements: Education min 68%, min 6 years experience (3 in academic content creation), managed team of 5+ for 1+ year, 2+ published research articles. Special: If only 1 article but 8+ years exp and M.Ed./B.Ed., refer Board of Academic Excellence. If marks below 68% but 3+ papers, refer Chief Editor. Case: Aditya, 66% MA English, 9 years exp (4 in content creation), led team 2 years, 3 published papers, B.Ed. degree. What should be done?"],"options":["उम्मीदवार को अस्वीकार करें","मुख्य संपादक को भेजें","उम्मीदवार का चयन करें","शैक्षणिक उत्कृष्टता बोर्ड को भेजें"],"solution":"Aditya: marks 66% (<68% threshold) lekin 3 published papers hain — exactly special clause 'marks below 68% but 3+ papers → refer Chief Editor' match karta hai."},"en":{"prompt":["Requirements: Education minimum 68%, minimum 6 years experience (3 in academic content creation), managed a team of 5+ for 1+ year, 2+ published research articles. Special clause: If only 1 article but 8+ years experience and an M.Ed./B.Ed., refer to the Board of Academic Excellence. If marks are below 68% but there are 3+ papers, refer to the Chief Editor. Case: Aditya, 66% MA English, 9 years experience (4 in content creation), led a team for 2 years, 3 published papers, B.Ed. degree. What should be done?"],"options":["Reject the candidate","Refer to the Chief Editor","Select the candidate","Refer to the Board of Academic Excellence"],"solution":"Aditya's marks are 66% (below the 68% threshold) but he has 3 published papers — this exactly matches the special clause 'marks below 68% but 3+ papers → refer to the Chief Editor'."},"answer":1},{"qn":205,"hi":{"prompt":["लाइब्रेरियन चयन मानदंड: B.Lib.Sc. न्यूनतम 55%, आयु 24-32, बुनियादी कंप्यूटर कौशल, न्यूनतम 1 वर्ष लाइब्रेरी अनुभव। विशेष: यदि अनुभव नहीं लेकिन 60% के साथ मास्टर डिग्री है, तो लाइब्रेरी निदेशक से संपर्क करें। नीलम: 27 वर्ष, 58% B.Lib.Sc., मास्टर डिग्री (62%), कोई अनुभव नहीं, कंप्यूटर साक्षर। क्या किया जाना चाहिए?"],"options":["उम्मीदवार का चयन करें","लाइब्रेरी निदेशक से संपर्क करें","मानव संसाधन विभाग से संपर्क करें","उम्मीदवार को अस्वीकार करें"],"solution":"Neelam: experience nahi hai lekin Master's 62% (>60%) hai — special clause 'no exp but master's 60%+ → Library Director ko refer' trigger hota hai."},"en":{"prompt":["Librarian selection criteria: B.Lib.Sc. minimum 55%, age 24-32, basic computer skills, minimum 1 year library experience. Special clause: If no experience but a Master's degree with 60%, refer to the Library Director. Neelam: 27 years old, 58% B.Lib.Sc., Master's degree (62%), no experience, computer literate. What should be done?"],"options":["Select the candidate","Refer to the Library Director","Contact the HR department","Reject the candidate"],"solution":"Neelam has no experience but has a Master's degree at 62% (above 60%) — this triggers the special clause 'no experience but Master's 60%+ → refer to the Library Director'."},"answer":1},{"qn":206,"hi":{"prompt":["सुरक्षा गार्ड पात्रता: आयु 25-35, 10वीं पास, शारीरिक रूप से स्वस्थ, कोई आपराधिक रिकॉर्ड नहीं। सुरेश: 29 वर्ष, 10वीं पास, स्वस्थ, कोई पुलिस रिकॉर्ड नहीं। क्या किया जाना चाहिए?"],"options":["पुलिस सत्यापन देखें","डेटा अधूरा","उम्मीदवार का चयन करें","उम्मीदवार को अस्वीकार करें"],"solution":"Suresh sab basic criteria pura karta hai (age 29, 10th pass, healthy, no criminal record) — seedha select ho sakta hai."},"en":{"prompt":["Security guard eligibility: age 25-35, passed 10th grade, physically fit, no criminal record. Suresh: 29 years old, passed 10th grade, fit, no police record. What should be done?"],"options":["Check police verification","Data is incomplete","Select the candidate","Reject the candidate"],"solution":"Suresh meets all the basic criteria (age 29, 10th pass, fit, no criminal record) — he can be directly selected."},"answer":2},{"qn":207,"hi":{"prompt":["सहायक शिक्षक चयन मानदंड: न्यूनतम 50% B.Ed., आयु 25-35, 2 वर्ष शिक्षण अनुभव, ग्रामीण विद्यालयों में काम करने के इच्छुक। विशेष: यदि 1 वर्ष अनुभव लेकिन शिक्षा में स्नातकोत्तर है, तो उप-प्राचार्य से संपर्क करें। सोनल: 28 वर्ष, B.Ed. (55%), शिक्षा में स्नातकोत्तर, 1 वर्ष अनुभव, ग्रामीण क्षेत्रों में सहमत। क्या किया जाना चाहिए?"],"options":["उम्मीदवार को अस्वीकार करें","उप प्रधानाचार्य से संपर्क करें","मामले पर विचार नहीं किया जा सकता","उम्मीदवार का चयन करें"],"solution":"Sonal: 1 year exp hai (2 chahiye) lekin Education me PG hai — special clause 'if 1yr exp but PG in education → contact Vice Principal' match karta hai."},"en":{"prompt":["Assistant teacher selection criteria: minimum 50% B.Ed., age 25-35, 2 years teaching experience, willing to work in rural schools. Special clause: If 1 year of experience but a postgraduate degree in education, refer to the Vice-Principal. Sonal: 28 years old, B.Ed. (55%), postgraduate in education, 1 year experience, willing to work in rural areas. What should be done?"],"options":["Reject the candidate","Refer to the Vice-Principal","The case cannot be considered","Select the candidate"],"solution":"Sonal has 1 year of experience (2 required) but has a PG in education — this matches the special clause 'if 1 year experience but PG in education → refer to the Vice-Principal'."},"answer":1},{"qn":208,"hi":{"prompt":["आपने अभी-अभी एक व्यस्त रेस्टोरेंट में खाना खाया है और नकद भुगतान किया है। सर्वर ने गलती से बकाया राशि से कहीं ज्यादा पैसे वापस कर दिए हैं। सबसे नैतिक और ज़िम्मेदाराना कदम क्या है?"],"options":["विनम्रतापूर्वक सर्वर का ध्यान आकर्षित करें, गलती बताएं और अतिरिक्त राशि लौटा दें","अतिरिक्त भुगतान की राशि चुपचाप अतिरिक्त टिप के रूप में छोड़ दें","जोर से घोषणा करें कि सर्वर ने गलती की है","सावधानी से अतिरिक्त पैसे अपनी जेब में रखें"],"solution":"Server ne galti se zyada paise diye to sahi ethical step hai politely unhe bata kar extra amount wapas karna, chupke rakhna ya keep karna galat."},"en":{"prompt":["You've just eaten at a busy restaurant and paid in cash. The server mistakenly gives you far more change than owed. What is the most ethical and responsible step?"],"options":["Politely get the server's attention, point out the mistake, and return the extra amount","Quietly keep the overpayment as an extra tip","Loudly announce that the server made a mistake","Carefully pocket the extra money"],"solution":"When a server gives excess change by mistake, politely pointing it out and returning the extra amount is the correct ethical step, not keeping it quietly."},"answer":0},{"qn":209,"hi":{"prompt":["गाड़ी चलाते समय, आप एक पार्किंग स्थल में एक मामूली टक्कर के गवाह बनते हैं। गलती वाली कार बिना रुके चली जाती है। दूसरी कार का ड्राइवर घबराया हुआ है। सबसे नैतिक कार्य क्या है?"],"options":["यह मान लें कि यह एक छोटी घटना है और गाड़ी चलाना जारी रखें","सुरक्षित रूप से रुकें, ड्राइवर की खैरियत पूछें, और संपर्क विवरण व जो देखा वह बताने की पेशकश करें","तत्काल आपातकालीन सेवाओं को कॉल करें","जो कार चली गई है, उसका पीछा करें"],"solution":"Chhoti parking lot collision me hit-and-run car chali gayi to ruk kar victim driver ki khairiyat poochna aur apni contact/witness details dena sahi responsible action hai."},"en":{"prompt":["While driving, you witness a minor collision in a parking lot. The at-fault car drives off without stopping. The other driver looks shaken. What is the most ethical action?"],"options":["Assume it's a minor incident and keep driving","Safely stop, check on the driver's well-being, and offer your contact details and what you witnessed","Immediately call emergency services","Chase after the car that left"],"solution":"After witnessing a hit-and-run in a parking lot, safely stopping to check on the victim driver and offering your contact and witness details is the right responsible action."},"answer":1},{"qn":210,"hi":{"prompt":["आप बस में यात्रा कर रहे हैं और इंजन वाले हिस्से से धुआँ निकलता हुआ देखते हैं। सबसे अच्छा उपाय क्या है?"],"options":["आपातकालीन निकास खोलें और दूसरों को सचेत करें","घबरा जाओ और चीखो","बैठे रहो और कुछ मत करो","किसी और के कार्य करने की प्रतीक्षा करें"],"solution":"Bus engine se dhuan dekh kar emergency exit khol kar sabko alert karna sahi safety-first action hai."},"en":{"prompt":["You are traveling on a bus and notice smoke coming from the engine area. What is the best action?"],"options":["Open the emergency exit and alert others","Panic and scream","Sit still and do nothing","Wait for someone else to act"],"solution":"On seeing smoke from a bus engine, opening the emergency exit and alerting everyone is the correct safety-first action."},"answer":0}],"set15":[{"qn":211,"hi":{"prompt":["आप एक समूह परियोजना का नेतृत्व कर रहे हैं और एक सदस्य योगदान नहीं दे रहा है। इस समस्या को हल करने के लिए सबसे अच्छा निर्णय क्या है?"],"options":["काम खुद करना","व्यक्ति को समूह से निकालना","सदस्य से बात करना और उनके कारणों को समझना","बिना चर्चा के सीधे शिक्षक से शिकायत करना"],"solution":"Group project me contribute na karne wale member se seedha baat karke unke reasons samajhna sahi leadership decision hai."},"en":{"prompt":["You are leading a group project and one member isn't contributing. What is the best decision to resolve this?"],"options":["Do the work yourself","Remove the person from the group","Talk to the member and understand their reasons","Complain directly to the teacher without discussion"],"solution":"Talking directly to a non-contributing group member to understand their reasons is the right leadership decision."},"answer":2},{"qn":212,"hi":{"prompt":["एक आदमी एक इमारत से धुआँ निकलता देखता है और लोगों को चिल्लाते हुए सुनता है। उसे सबसे पहले क्या करना चाहिए?"],"options":["तुरंत भाग जाओ","इमारत में प्रवेश करने का प्रयास करें","आपातकालीन सेवाओं को कॉल करें","अनदेखा करें और आगे बढ़ें"],"solution":"Building se dhuan aur log chillate sun kar sabse pehla sahi step emergency services ko call karna hai, khud building me ghusna dangerous hai."},"en":{"prompt":["A man sees smoke coming from a building and hears people shouting. What should he do first?"],"options":["Run away immediately","Try to enter the building","Call emergency services","Ignore it and move on"],"solution":"On seeing smoke and hearing shouting from a building, the correct first step is calling emergency services — entering the building yourself is dangerous."},"answer":2},{"qn":213,"hi":{"prompt":["आपका पड़ोसी अक्सर कचरा इकट्ठा करने के बाद कई दिनों तक अपना कचरा दान बाहर छोड़ देता है, जिससे यह आस-पड़ोस के लिए बार-बार होने वाली समस्या बनती जा रही है। सबसे नैतिक और ज़िम्मेदाराना कदम क्या है?"],"options":["अन्य पड़ोसियों को इकट्ठा करें और सामूहिक रूप से गुस्से से बात करें","गुप्त रूप से तस्वीरें लें और नगरपालिका प्राधिकरण को भेजें","पड़ोसी के पास शांतिपूर्वक और विनम्रता से जाकर इस मुद्दे पर चर्चा करें","बताए बिना उनके फैले हुए कचरे को स्वयं साफ करना शुरू कर दें"],"solution":"Baar baar garbage bin chodne wale padosi se shanti se aur politely baat karna sahi neighborly ethical action hai."},"en":{"prompt":["Your neighbor often leaves their trash bin out for several days after collection, becoming a recurring problem for the neighborhood. What is the most ethical and responsible step?"],"options":["Gather other neighbors and confront them angrily as a group","Secretly take photos and send them to the municipal authority","Calmly and politely go to the neighbor and discuss the issue","Start cleaning up their scattered trash yourself without telling them"],"solution":"Calmly and politely discussing the issue directly with the neighbor is the right, neighborly, ethical action for a recurring bin problem."},"answer":2},{"qn":214,"hi":{"prompt":["एक छात्र आगामी प्रवेश परीक्षा के लिए समय प्रबंधन से जूझ रहा है। इस समस्या को हल करने के लिए सबसे प्रभावी निर्णय क्या होगा?"],"options":["तैयारी अंतिम सप्ताह तक छोड़ देना","केवल पसंदीदा विषयों पर ध्यान केंद्रित करना","सारी रात पढ़ाई करना और सोना छोड़ देना","एक यथार्थवादी अध्ययन समय सारिणी बनाना और उसका पालन करना"],"solution":"Time management struggle ke liye realistic study timetable banana aur follow karna sabse effective long-term solution hai."},"en":{"prompt":["A student is struggling with time management for an upcoming entrance exam. What would be the most effective decision to resolve this?"],"options":["Leave preparation until the last week","Focus only on favorite subjects","Study all night and skip sleep","Create a realistic study timetable and follow it"],"solution":"Creating and following a realistic study timetable is the most effective long-term solution for a time-management struggle."},"answer":3},{"qn":215,"hi":{"prompt":["एक छात्र को आगामी परीक्षा की उत्तर कुंजी गलती से एक प्रोफेसर के कार्यालय में मिल जाती है। छात्र को क्या करना चाहिए?"],"options":["इसे बाद में उपयोग के लिए रखें","इसकी विषय-वस्तु का खुलासा किए बिना इसे प्रोफेसर को लौटा दें","इसे दोस्तों के साथ साझा करें","उत्तर याद रखें"],"solution":"Answer key galti se mil gayi to content reveal kiye bina professor ko wapas karna sahi honest action hai."},"en":{"prompt":["A student accidentally finds the answer key for an upcoming exam in a professor's office. What should the student do?"],"options":["Keep it for later use","Return it to the professor without revealing its contents","Share it with friends","Memorize the answers"],"solution":"On accidentally finding an answer key, returning it to the professor without revealing its contents is the correct, honest action."},"answer":1},{"qn":216,"hi":{"prompt":["कोई आपसे बात कर रहा है और आप उससे पूरी तरह असहमत हैं। सबसे अच्छी सामाजिक रूप से बुद्धिमान प्रतिक्रिया क्या होगी?"],"options":["उन्हें टोकें और ज़ोर से बहस करें","अब बहस से बचने के लिए वहाँ से चले जाएं","प्रतीक्षा करें और फिर विनम्रतापूर्वक कारण बताकर उत्तर दें","चुप रहें और बाद में उनके बारे में गपशप करें"],"solution":"Kisi se poori tarah asehmat ho to wait karo aur phir politely reason ke saath respond karo — yehi socially intelligent tarika hai."},"en":{"prompt":["Someone is talking to you and you completely disagree with them. What would be the best socially intelligent response?"],"options":["Interrupt them and argue loudly","Walk away to avoid an argument","Wait, then respond politely with your reasoning","Stay silent and gossip about them later"],"solution":"When you completely disagree with someone, waiting and then responding politely with your reasoning is the socially intelligent approach."},"answer":2},{"qn":217,"hi":{"prompt":["वरिष्ठ विश्लेषक जोखिम एवं अनुपालन मानदंड: वित्त/अर्थशास्त्र/जोखिम प्रबंधन में न्यूनतम 70% स्नातकोत्तर, 5-8 वर्ष अनुभव (3 वर्ष जोखिम/अनुपालन में), आयु 30-40, CFA/FRM/CAMS में से कम से कम एक प्रमाणन। विशेष: यदि PG में 60-69% लेकिन 2 प्रमाणन और 7+ वर्ष अनुभव, तो जोखिम निरीक्षण निदेशक से संपर्क करें। यदि आयु 6 महीने से कम है, तो CEO डेस्क से संपर्क करें। रजत: 67% अर्थशास्त्र PG, 7.5 वर्ष अनुभव (3.5 अनुपालन में), CFA व FRM, आयु 29 वर्ष 7 महीने। क्या किया जाना चाहिए?"],"options":["जोखिम निरीक्षण निदेशक से संपर्क करें","CEO के डेस्क का संदर्भ लें","उम्मीदवार को अस्वीकार करें","उम्मीदवार का चयन करें"],"solution":"Rajat: age 29yr 7months hai jo min 30 se sirf 6 mahine kam hai — exactly special clause 'age within 6 months of minimum → CEO desk' match karta hai."},"en":{"prompt":["Senior Analyst Risk & Compliance criteria: minimum 70% postgraduate in Finance/Economics/Risk Management, 5-8 years experience (3 years in risk/compliance), age 30-40, at least one certification among CFA/FRM/CAMS. Special clause: If PG marks are 60-69% but there are 2 certifications and 7+ years experience, refer to the Director of Risk Oversight. If age is within 6 months of the minimum, refer to the CEO's desk. Rajat: 67% Economics PG, 7.5 years experience (3.5 in compliance), CFA and FRM, age 29 years 7 months. What should be done?"],"options":["Refer to the Director of Risk Oversight","Refer to the CEO's desk","Reject the candidate","Select the candidate"],"solution":"Rajat is 29 years 7 months old, just 5 months short of the minimum age of 30 — this exactly matches the special clause 'age within 6 months of the minimum → refer to the CEO's desk'."},"answer":1},{"qn":218,"hi":{"prompt":["फील्ड ऑफिसर चयन मानदंड: कृषि/पर्यावरण विज्ञान में न्यूनतम 65%, आयु 23-35, वैध ड्राइविंग लाइसेंस, न्यूनतम 2 वर्ष फील्ड अनुभव। विशेष: यदि ड्राइविंग लाइसेंस नहीं लेकिन 4+ वर्ष फील्ड अनुभव है, तो क्षेत्रीय प्रमुख से संपर्क करें। शालिनी: 29 वर्ष, पर्यावरण विज्ञान में 68%, 5 वर्ष फील्ड वर्क, कोई ड्राइविंग लाइसेंस नहीं। क्या किया जाना चाहिए?"],"options":["उम्मीदवार को अस्वीकार करें","क्षेत्रीय प्रमुख से संपर्क करें","साक्षात्कार के लिए बुलावा","उम्मीदवार का चयन करें"],"solution":"Shalini: driving license nahi hai lekin 5yr field experience hai (4+ chahiye) — special clause 'no license but 4+ yr exp → Regional Head' trigger hota hai."},"en":{"prompt":["Field Officer selection criteria: minimum 65% in Agriculture/Environmental Science, age 23-35, valid driving license, minimum 2 years field experience. Special clause: If no driving license but 4+ years of field experience, refer to the Regional Head. Shalini: 29 years old, 68% in Environmental Science, 5 years of field work, no driving license. What should be done?"],"options":["Reject the candidate","Refer to the Regional Head","Call for interview","Select the candidate"],"solution":"Shalini has no driving license but has 5 years of field experience (4+ required) — this triggers the special clause 'no license but 4+ years experience → refer to the Regional Head'."},"answer":1},{"qn":219,"hi":{"prompt":["लैब असिस्टेंट चयन मानदंड: लैब टेक्नोलॉजी डिप्लोमा न्यूनतम 60%, आयु 21-28, न्यूनतम 1 वर्ष व्यावहारिक लैब अनुभव, नाइट शिफ्ट के लिए तैयार। विशेष: यदि डिप्लोमा में 70% लेकिन केवल 6 महीने अनुभव, तो मुख्य लैब सुपरवाइजर को भेजें। इरफान: 22 वर्ष, डिप्लोमा में 72%, 6 महीने अनुभव, नाइट शिफ्ट के लिए सहमत। क्या किया जाना चाहिए?"],"options":["मुख्य लैब सुपरवाइजर को भेजें","उम्मीदवार को अस्वीकार करें","जानकारी अपर्याप्त है","उम्मीदवार का चयन करें"],"solution":"Irfan: 72% diploma hai (70%+) lekin sirf 6 months experience — special clause 'if 70%+ but only 6 months exp → Chief Lab Supervisor' match karta hai."},"en":{"prompt":["Lab Assistant selection criteria: Lab Technology Diploma minimum 60%, age 21-28, minimum 1 year practical lab experience, willing to work night shifts. Special clause: If 70% in diploma but only 6 months experience, refer to the Chief Lab Supervisor. Irfan: 22 years old, 72% in diploma, 6 months experience, willing for night shifts. What should be done?"],"options":["Refer to the Chief Lab Supervisor","Reject the candidate","Information is insufficient","Select the candidate"],"solution":"Irfan has 72% in his diploma (above 70%) but only 6 months of experience — this matches the special clause 'if 70%+ but only 6 months experience → refer to the Chief Lab Supervisor'."},"answer":0},{"qn":220,"hi":{"prompt":["जूनियर लाइब्रेरियन पात्रता: B.Lib.Sc., कम से कम 1 वर्ष लाइब्रेरी अनुभव, आयु 32 वर्ष से कम। रीना: 31 वर्ष, B.Lib.Sc., कॉलेज लाइब्रेरी में 18 महीने अनुभव। क्या किया जाना चाहिए?"],"options":["उम्मीदवार को अस्वीकार करें","जानकारी अपर्याप्त","वरिष्ठ लाइब्रेरियन से संपर्क करें","उम्मीदवार का चयन करें"],"solution":"Reena: age 31 (<32✓), B.Lib.Sc hai✓, 18 months exp (>1yr✓) — sab basic criteria pure, isliye directly select hogi."},"en":{"prompt":["Junior Librarian eligibility: B.Lib.Sc., at least 1 year library experience, under 32 years old. Reena: 31 years old, B.Lib.Sc., 18 months experience at a college library. What should be done?"],"options":["Reject the candidate","Information is insufficient","Refer to the Senior Librarian","Select the candidate"],"solution":"Reena meets all basic criteria: age 31 (under 32 ✓), B.Lib.Sc. ✓, 18 months experience (more than 1 year ✓) — so she is directly selected."},"answer":3},{"qn":221,"hi":{"prompt":["आप एक स्वयंसेवी समिति का हिस्सा हैं जो एक वित्तीय रूप से संघर्षरत सामुदायिक उद्यान परियोजना की देखरेख कर रही है। एक बड़ा व्यवसाय दान की पेशकश करता है, लेकिन इस शर्त के साथ कि वे अपने कॉर्पोरेट लोगो को उद्यान के प्रवेश द्वार पर प्रमुखता से पेंट करें, जो उद्यान के प्राकृतिक सौंदर्य से मेल नहीं खाता। सबसे नैतिक और जिम्मेदार कार्य क्या है?"],"options":["दान और लोगो लगाने को तुरंत स्वीकार करें","दान को पूरी तरह से अस्वीकार कर दें, भले ही इसका मतलब बंद होना हो","आभार व्यक्त करें और मान्यता के वैकल्पिक रूपों पर बातचीत करने का प्रयास करें, जैसे छोटी पट्टिका","दान स्वीकार करें, इस इरादे से कि बाद में गुप्त रूप से लोगो हटा दिया जाए"],"solution":"Corporate logo condition garden ke aesthetics se match nahi karta — sahi balanced solution hai gratitude dikhate hue alternative recognition (jaise chhoti plaque) negotiate karna."},"en":{"prompt":["You are part of a volunteer committee overseeing a financially struggling community garden project. A large business offers a donation, but on the condition that their corporate logo be prominently painted at the garden's entrance, which clashes with the garden's natural aesthetic. What is the most ethical and responsible action?"],"options":["Immediately accept both the donation and the logo placement","Reject the donation entirely, even if it means shutting down","Express gratitude and try to negotiate alternative forms of recognition, such as a small plaque","Accept the donation, intending to secretly remove the logo later"],"solution":"Since the corporate logo condition clashes with the garden's aesthetic, the balanced solution is expressing gratitude while negotiating an alternative form of recognition, like a small plaque."},"answer":2},{"qn":222,"hi":{"prompt":["किसी स्थानीय पार्क में टहलते समय, आपको एक बेंच पर एक बटुआ पड़ा मिलता है, जिसमें नकदी, क्रेडिट कार्ड और पहचान पत्र है। सबसे नैतिक और ज़िम्मेदाराना कदम क्या होगा?"],"options":["नकदी ले लो और बाकी बेंच पर छोड़ दो","आईडी पर दिए गए पते पर जाकर स्वयं मालिक को ढूंढने का प्रयास करें","अपना पूरा बटुआ निकटतम पुलिस स्टेशन या लॉस्ट-एंड-फाउंड कार्यालय में जमा कर दें","आईडी की संपर्क जानकारी का उपयोग करके सीधे मालिक से संपर्क करें"],"solution":"Bench par milne wale wallet ko poora police station/lost-and-found office me jama karna sabse ethical complete action hai."},"en":{"prompt":["While walking in a local park, you find a wallet left on a bench containing cash, credit cards, and an ID. What would be the most ethical and responsible step?"],"options":["Take the cash and leave the rest on the bench","Go to the address on the ID and try to find the owner yourself","Turn in the entire wallet to the nearest police station or lost-and-found office","Contact the owner directly using the contact information on the ID"],"solution":"Turning in the entire wallet to the nearest police station or lost-and-found office is the most ethical, complete action for a wallet found on a bench."},"answer":2},{"qn":223,"hi":{"prompt":["निशा दो नौकरी प्रस्तावों के बीच चयन कर रही है। एक उच्च वेतन प्रदान करता है लेकिन बार-बार यात्रा और ओवरटाइम की आवश्यकता है। दूसरा लचीले घंटे, दूरस्थ कार्य और मध्यम वेतन प्रदान करता है। निशा कार्य-जीवन संतुलन को महत्व देती है। उसे कौन सी नौकरी लेनी चाहिए?"],"options":["दोनों को अस्वीकार करना और किसी अन्य प्रस्ताव की प्रतीक्षा करना","दोनों नौकरियाँ अंशकालिक रूप से करना","मध्यम वेतन वाली नौकरी जिसमें लचीलापन हो","उच्च वेतन वाली नौकरी जिसमें यात्रा शामिल हो"],"solution":"Nisha work-life balance value karti hai to moderate salary wali flexible job usse better suit karti hai, high salary wali travel-heavy job nahi."},"en":{"prompt":["Nisha is choosing between two job offers. One offers a higher salary but requires frequent travel and overtime. The other offers flexible hours, remote work, and a moderate salary. Nisha values work-life balance. Which job should she take?"],"options":["Reject both and wait for another offer","Do both jobs part-time","The moderate-salary job with flexibility","The higher-salary job that includes travel"],"solution":"Since Nisha values work-life balance, the moderate-salary flexible job suits her better than the high-salary, travel-heavy job."},"answer":2},{"qn":224,"hi":{"prompt":["एक IT कंपनी को अपने उपयोगकर्ता डेटाबेस में एक मामूली सुरक्षा खामी का पता चलता है। कोई बड़ा डेटा समझौता नहीं हुआ है, लेकिन यदि ठीक से न संभाला जाए तो यह गंभीर हो सकता है। सही विकल्प चुनें।"],"options":["मुद्दे को छुपाएं और उम्मीद करें कि यह बढ़ेगा नहीं","उल्लंघन और सुधार के कदमों के बारे में उपयोगकर्ताओं को पारदर्शी तरीके से सूचित करें","सभी उपयोगकर्ताओं को सचेत करने के लिए सार्वजनिक रूप से बड़ा संकट घोषित करें","चुपचाप कमजोरी को ठीक करें और एक सामान्य सुरक्षा अद्यतन जारी करें"],"solution":"Minor security flaw honest transparently users ko batana aur fix steps share karna trust-building responsible action hai, chhupana ya over-dramatize karna dono galat."},"en":{"prompt":["An IT company discovers a minor security flaw in its user database. No major data breach has occurred, but it could become serious if not handled properly. Choose the correct option."],"options":["Hide the issue and hope it doesn't escalate","Transparently inform users about the flaw and the remediation steps","Publicly declare a major crisis to alert all users","Quietly fix the vulnerability and issue a generic security update"],"solution":"Honestly and transparently informing users about a minor security flaw and sharing the fix steps is the trust-building responsible action — both hiding it and over-dramatizing it are wrong."},"answer":1},{"qn":225,"hi":{"prompt":["एक शिक्षक ने देखा कि कुछ छात्र परीक्षा के दौरान एक-दूसरे से नकल करते हैं। सबसे अच्छा निवारक उपाय क्या है?"],"options":["पकड़े गए छात्रों को सार्वजनिक रूप से शर्मिंदा करें","बैठक व्यवस्था बदलें और प्रश्न पत्र के कई संस्करण तैयार करें","सभी भविष्य की परीक्षाएं रद्द करें","इसे मामूली समझकर नजरअंदाज करें"],"solution":"Exam me copying rokne ka best preventive measure seating arrangement badalna aur multiple question paper versions banana hai."},"en":{"prompt":["A teacher notices some students copying from each other during an exam. What is the best preventive measure?"],"options":["Publicly embarrass the students who were caught","Change the seating arrangement and prepare multiple versions of the question paper","Cancel all future exams","Ignore it as a minor issue"],"solution":"The best preventive measure against exam copying is changing the seating arrangement and preparing multiple versions of the question paper."},"answer":1},{"qn":226,"hi":{"prompt":["आप देखते हैं कि आपका सहकर्मी, जो पहले बहुत सक्रिय था, अब मीटिंग्स में असामान्य रूप से चुप और अलग-थलग रहता है। सबसे सामाजिक रूप से समझदारी भरा तरीका क्या होगा?"],"options":["इसे अनदेखा करें; वे तैयार होने पर खुलेंगे","सार्वजनिक रूप से पूछें कि वे पहले की तरह योगदान क्यों नहीं दे रहे","मैनेजर को बताएं कि वे अच्छा प्रदर्शन नहीं कर रहे हैं","उनसे निजी तौर पर जांच करें कि क्या वे ठीक हैं और सहायता की पेशकश करें"],"solution":"Colleague achanak quiet/withdrawn hai to privately unse check-in karo ki sab theek hai aur help offer karo — manager ko complain karna ya public me poochna galat."},"en":{"prompt":["You notice that your colleague, who was previously very active, is now unusually quiet and withdrawn in meetings. What would be the most socially perceptive approach?"],"options":["Ignore it; they'll open up when ready","Publicly ask why they aren't contributing like before","Tell the manager they aren't performing well","Privately check in on them to see if they're okay and offer support"],"solution":"When a colleague suddenly becomes quiet and withdrawn, privately checking in and offering support is right — complaining to the manager or asking publicly is wrong."},"answer":3}]};
